export const pack2 = [
{ id:301, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Um servidor público que utiliza papel e impressora do CRECI para imprimir materiais de estudo pessoais para outros concursos está:", imagem:null, alternativas:["A) Agindo com eficiência, pois está aproveitando o tempo livre para estudar.","B) Praticando um ato ético de autoaperfeiçoamento profissional.","C) Violando o princípio da moralidade ao utilizar recursos públicos para fins privados.","D) Isento de qualquer crítica, desde que não atrapalhe suas tarefas diárias.","E) Agindo dentro da legalidade, pois não há lei que proíba especificamente o uso de papel."], resposta_correta:2, explicacao:"Justificativa: Recursos públicos são destinados exclusivamente ao interesse público. Uso privado é imoral e ilegal. Dica do Especialista: Bens da repartição para uso pessoal = Improbidade + Infração Ética.", status:0, historico:0 },
{ id:302, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"O princípio que estabelece que o interesse da coletividade deve prevalecer sobre o interesse de indivíduos isolados é o da:", imagem:null, alternativas:["A) Indisponibilidade do interesse público.","B) Supremacia do interesse público sobre o privado.","C) Legalidade estrita.","D) Publicidade administrativa.","E) Presunção de legitimidade."], resposta_correta:1, explicacao:"Justificativa: É o princípio basilar do Direito Administrativo que justifica as prerrogativas estatais. Dica do Especialista: A 'Supremacia' é a base dos poderes; a 'Indisponibilidade' é a base dos deveres.", status:0, historico:0 },
{ id:303, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Administração Pública e Ética", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Analise: 'A função pública deve ser tida como exercício de cidadania e, consequentemente, como encargo de alta responsabilidade'. Essa visão implica que:", imagem:null, alternativas:["A) O servidor pode cobrar taxas extras por fora para garantir a rapidez do serviço.","B) O descaso com o patrimônio público é uma falta meramente administrativa, sem teor ético.","C) A dignidade da pessoa humana deve ser respeitada em todos os atendimentos do conselho.","D) O servidor é um cidadão comum e não precisa prestar contas de seus atos à sociedade.","E) O cargo público é uma propriedade do servidor, que dele pode dispor como desejar."], resposta_correta:2, explicacao:"Justificativa: A ética pública está ancorada no respeito ao cidadão e na responsabilidade social. Dica do Especialista: A Quadrix sempre coloca alternativas que tentam 'diminuir' a responsabilidade do servidor; descarte-as imediatamente.", status:0, historico:0 },
{ id:304, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"De acordo com as recentes alterações na Lei nº 8.429/1992, assinale a alternativa que descreve corretamente o elemento subjetivo necessário para a configuração do ato de improbidade administrativa:", imagem:null, alternativas:["A) Admite-se a modalidade culposa apenas nos atos que geram prejuízo ao erário.","B) O dolo deve ser genérico, bastando a vontade livre de realizar a conduta descrita no tipo.","C) Exige-se o dolo específico, caracterizado pela vontade livre e consciente de alcançar o resultado ilícito.","D) A culpa grave equipara-se ao dolo para fins de perda da função pública e suspensão de direitos.","E) O mero exercício da função ou desempenho de competência pública, sem prova de má-fé, presume o dolo."], resposta_correta:2, explicacao:"Justificativa: Com a Lei 14.230/21, a improbidade culposa foi extinta e exige-se dolo específico (vontade de alcançar o resultado ilícito).", status:0, historico:0 },
{ id:305, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Um assistente administrativo do CRECI-BA, visando beneficiar um amigo, facilita a aquisição de um bem por preço inferior ao de mercado. Essa conduta, segundo a Lei nº 8.429/1992, tipifica-se como:", imagem:null, alternativas:["A) Ato que atenta contra os princípios da administração pública, exclusivamente.","B) Ato de improbidade que importa enriquecimento ilícito do próprio servidor.","C) Ato de improbidade administrativa que causa prejuízo ao erário.","D) Mera irregularidade administrativa, não passível de punição por improbidade se não houver propina.","E) Ato de improbidade por omissão, visto que ele deixou de fiscalizar o valor correto."], resposta_correta:2, explicacao:"Justificativa: Facilitar a aquisição por preço inferior causa dano patrimonial efetivo (Art. 10).", status:0, historico:0 },
{ id:306, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Sobre as sanções previstas para atos que atentam contra os princípios da administração pública, assinale a alternativa correta em conformidade com a redação atual da lei:", imagem:null, alternativas:["A) É cabível a suspensão de direitos políticos por até 12 anos.","B) É cabível a perda da função pública, independentemente do tempo de serviço.","C) É cabível o pagamento de multa civil de até 24 vezes o valor da remuneração percebida pelo agente.","D) O ressarcimento ao erário é dispensável, visto que não houve prejuízo financeiro direto.","E) A sanção de proibição de contratar com o Poder Público deve ser sempre de 10 anos."], resposta_correta:2, explicacao:"Justificativa: Para atos contra princípios (Art. 11), a multa é de até 24 vezes a remuneração. Não há mais suspensão de direitos políticos nem perda da função para o Art. 11.", status:0, historico:0 },
{ id:307, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Considere que um ex-dirigente do conselho tenha deixado o cargo há 9 anos. O Ministério Público decide ajuizar ação de improbidade hoje por atos cometidos no último dia de mandato. Sobre a prescrição, é correto afirmar:", imagem:null, alternativas:["A) A ação é imprescritível, pois trata-se de defesa do patrimônio público.","B) A ação prescreveu, pois o prazo prescricional unificado é de 8 anos a contar da ocorrência do fato.","C) O prazo prescricional é de 5 anos, seguindo a regra geral dos servidores federais.","D) A prescrição ocorre em 10 anos para casos de enriquecimento ilícito.","E) Não corre prescrição enquanto o agente não for formalmente notificado pelo Tribunal de Contas."], resposta_correta:1, explicacao:"Justificativa: A Lei 14.230 unificou o prazo em 8 anos contados da ocorrência do fato ou da cessação da permanência.", status:0, historico:0 },
{ id:308, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"A aplicação das sanções da Lei de Improbidade Administrativa independe:", imagem:null, alternativas:["A) Da ocorrência de dolo por parte do agente público.","B) Da efetiva ocorrência de dano ao patrimônio público, salvo quanto à pena de ressarcimento.","C) Da aprovação ou rejeição das contas pelo Tribunal de Contas competentes.","D) Da existência de cargo, emprego ou função pública na data da condenação.","E) Da demonstração de que o ato visava o benefício de terceiros."], resposta_correta:2, explicacao:"Justificativa: O Art. 21, II, diz que a aplicação independe da aprovação ou rejeição das contas.", status:0, historico:0 },
{ id:309, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Assinale a alternativa que apresenta uma conduta que NÃO MAIS constitui ato de improbidade que atenta contra os princípios da administração pública (Art. 11):", imagem:null, alternativas:["A) Revelar fato ou circunstância de que tem ciência em razão das atribuições e que deva permanecer em segredo.","B) Negar publicidade aos atos oficiais, salvo os casos de sigilo previstos em lei.","C) Frustrar a licitude de processo licitatório ou de processo seletivo para simplificado.","D) Deixar de prestar contas quando esteja obrigado a fazê-lo, desde que para ocultar irregularidades.","E) Praticar ato visando fim proibido em lei ou regulamento ou diverso daquele previsto na regra de competência."], resposta_correta:4, explicacao:"Justificativa: O inciso I do Art. 11 foi revogado. Atualmente, as condutas do Art. 11 são taxativas.", status:0, historico:0 },
{ id:310, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Em relação à responsabilidade de terceiros na Lei de Improbidade, assinale a opção correta:", imagem:null, alternativas:["A) O terceiro que não é agente público não pode ser processado com base na Lei nº 8.429/1992.","B) O terceiro responde apenas se houver dano material ao erário, excluindo-se enriquecimento ilícito.","C) As disposições da lei são aplicáveis ao terceiro que, mesmo não sendo agente público, induza ou concorra dolosamente para o ato.","D) A punição do terceiro independe da punição do agente público que praticou o ato principal.","E) O terceiro pessoa jurídica não pode ser responsabilizado, apenas seus sócios majoritários."], resposta_correta:2, explicacao:"Justificativa: Art. 3º: Terceiro responde se induzir ou concorrer dolosamente.", status:0, historico:0 },
{ id:311, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Sobre a sucessão hereditária na Lei de Improbidade, se o agente público falecer durante o processo:", imagem:null, alternativas:["A) O processo é extinto imediatamente, visto que as penas de improbidade são personalíssimas.","B) O sucessor responde por todas as penas, inclusive suspensão de direitos políticos.","C) O sucessor está sujeito às cominações de perda de bens e ressarcimento até o limite da herança.","D) A multa civil é perdoada, mas o ressarcimento deve ser pago integralmente pelos herdeiros.","E) A responsabilidade do sucessor limita-se aos casos de enriquecimento ilícito, excluindo prejuízo ao erário."], resposta_correta:2, explicacao:"Justificativa: Art. 8º: O sucessor está sujeito à obrigação de reparar o dano e à perda de bens até o limite do valor da herança.", status:0, historico:0 },
{ id:312, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Analise: 'O Ministério Público poderá celebrar acordo de não persecução cível'. Sobre esse instrumento, é correto afirmar:", imagem:null, alternativas:["A) É proibido em casos que envolvam enriquecimento ilícito acima de 100 salários mínimos.","B) Exige, entre outros requisitos, o integral ressarcimento do dano ao erário.","C) Pode ser celebrado apenas após o trânsito em julgado da sentença condenatória.","D) Dispensa a confissão do investigado para garantir a celeridade do processo.","E) É uma decisão unilateral do Juiz, não dependendo de proposta do Ministério Público."], resposta_correta:1, explicacao:"Justificativa: Art. 17-B: O ANPC exige o ressarcimento integral e a oitiva do ente lesado.", status:0, historico:0 },
{ id:313, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Dentre as penas abaixo, qual pode ser aplicada a um agente que praticou ato de improbidade que importa em enriquecimento ilícito, mas NÃO pode ser aplicada para atos contra princípios?", imagem:null, alternativas:["A) Multa civil.","B) Ressarcimento integral do dano.","C) Suspensão de direitos políticos.","D) Perda da função pública.","E) Proibição de contratar com o poder público."], resposta_correta:2, explicacao:"Justificativa: Atos contra princípios (Art. 11) não possuem mais as penas de suspensão de direitos políticos e perda da função pública.", status:0, historico:0 },
{ id:314, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Uma empresa de tecnologia que se beneficia dolosamente de um edital viciado no CRECI-BA pode ser processada por improbidade administrativa. Contudo, se a conduta também for tipificada na Lei Anticorrupção (Lei nº 12.846/2013):", imagem:null, alternativas:["A) A empresa deve responder apenas pela Lei de Improbidade por ser lei especial.","B) A empresa responderá obrigatoriamente em ambos os processos de forma independente.","C) A pessoa jurídica não sofrerá as sanções da Lei de Improbidade se o ato já for punido pela Lei Anticorrupção.","D) O processo de improbidade absorve todas as multas da Lei Anticorrupção.","E) A Lei Anticorrupção é inconstitucional para autarquias profissionais como o CRECI."], resposta_correta:2, explicacao:"Justificativa: Art. 3º, § 2º: Se o ato for punido pela Lei 12.846, a PJ não sofre sanções da LIA.", status:0, historico:0 },
{ id:315, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Assinale a alternativa que indica o prazo máximo de suspensão de direitos políticos para o ato de improbidade que causa prejuízo ao erário:", imagem:null, alternativas:["A) Até 8 anos.","B) Até 10 anos.","C) Até 12 anos.","D) Até 14 anos.","E) A lei não prevê mais suspensão para prejuízo ao erário."], resposta_correta:2, explicacao:"Justificativa: Prejuízo ao erário (Art. 10): suspensão de até 12 anos. Enriquecimento ilícito (Art. 9): até 14 anos.", status:0, historico:0 },
{ id:316, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Considere: I. 'Divergência interpretativa da lei baseada em jurisprudência não pacificada'. II. 'Vontade de omitir informação para esconder erro técnico'. Qual(is) item(ns) configura(m) improbidade?", imagem:null, alternativas:["A) Apenas I.","B) Apenas II.","C) I e II.","D) Nenhum dos dois, pois erro técnico é culpa.","E) Ambos, pois a administração pública exige perfeição."], resposta_correta:1, explicacao:"Justificativa: Art. 1º, § 8º: Divergência interpretativa não é improbidade. A II indica má-fé (dolo), logo é improbidade.", status:0, historico:0 },
{ id:317, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Sobre a indisponibilidade de bens em ações de improbidade, é INCORRETO afirmar:", imagem:null, alternativas:["A) Pode recair sobre bens adquiridos antes do ato ilícito.","B) Exige a demonstração de perigo de dano ou risco ao resultado útil do processo.","C) Pode atingir valores em conta corrente até o limite de 40 salários mínimos, sem exceções.","D) Deve recair prioritariamente sobre veículos e imóveis.","E) Não pode ser decretada se o dano ao erário for meramente estimado, sem liquidez."], resposta_correta:2, explicacao:"Justificativa: Art. 16, § 10: Valores até 40 salários mínimos em poupança ou outras aplicações são impenhoráveis.", status:0, historico:0 },
{ id:318, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"A ação para a aplicação das sanções de que trata a Lei nº 8.429/1992 será proposta pelo:", imagem:null, alternativas:["A) Ministério Público ou pela Pessoa Jurídica interessada.","B) Exclusivamente pelo Ministério Público.","C) Qualquer cidadão no gozo de seus direitos políticos.","D) Conselho Federal (COFECI) em caso de autarquias regionais.","E) Juiz de Direito da Comarca onde ocorreu o fato."], resposta_correta:1, explicacao:"Justificativa: Art. 17: A legitimidade ativa passou a ser EXCLUSIVA do Ministério Público.", status:0, historico:0 },
{ id:319, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Qual conduta abaixo constitui enriquecimento ilícito (Art. 9) e gera a pena de perda dos bens acrescidos ao patrimônio?", imagem:null, alternativas:["A) Doar bens da autarquia para entidade privada sem licitação.","B) Adquirir bens de valor desproporcional à evolução do patrimônio sem justificativa.","C) Retardar ou deixar de praticar ato de ofício indevidamente.","D) Frustrar a licitude de concurso público para favorecer parente.","E) Ordenar despesa não autorizada em lei ou regulamento."], resposta_correta:1, explicacao:"Justificativa: A desproporcionalidade patrimonial injustificada (Art. 9, VII) é presunção de enriquecimento ilícito.", status:0, historico:0 },
{ id:320, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Se o réu em ação de improbidade for condenado a ressarcir o erário, mas também for condenado em processo administrativo disciplinar (PAD) a devolver o mesmo valor:", imagem:null, alternativas:["A) Ele deverá pagar as duas vezes como medida pedagógica.","B) O valor pago no PAD deve ser abatido do montante da condenação judicial.","C) A condenação judicial anula automaticamente a decisão administrativa.","D) O ressarcimento judicial tem prioridade sobre o ressarcimento administrativo.","E) A lei proíbe que se cobre ressarcimento em duas instâncias diferentes."], resposta_correta:1, explicacao:"Justificativa: Art. 21, § 4º: Ressarcimento em uma instância deve ser compensado na outra para evitar enriquecimento do Estado.", status:0, historico:0 },
{ id:321, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Sobre a perda da função pública como sanção de improbidade, assinale a correta:", imagem:null, alternativas:["A) Atinge apenas o cargo que o agente ocupava no momento do ato.","B) Atinge, em regra, todos os vínculos que o agente possua com o poder público na data da decisão.","C) Só pode ser decretada pelo Juiz se houver reincidência específica em 5 anos.","D) É automática após o recebimento da petição inicial pelo magistrado.","E) Aplica-se apenas a cargos eletivos e de confiança, não a servidores de carreira."], resposta_correta:1, explicacao:"Justificativa: Art. 12, § 1º: A perda da função atinge o vínculo atual, mas o juiz pode estender a outros vínculos em casos graves.", status:0, historico:0 },
{ id:322, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Um estagiário do CRECI-BA, que não recebe remuneração, utiliza um veículo oficial para fins particulares com o consentimento doloso de seu supervisor. Neste caso:", imagem:null, alternativas:["A) O estagiário não responde por improbidade, pois não é agente público remunerado.","B) Apenas o supervisor responde, pois o estagiário não possui vínculo estatutário.","C) Ambos podem responder por improbidade, pois o conceito de agente público abrange quem atua sem remuneração e transitoriamente.","D) O ato é considerado mera falta disciplinar por envolver estagiário.","E) A lei de improbidade não se aplica a autarquias de fiscalização profissional."], resposta_correta:2, explicacao:"Justificativa: Art. 2º: O conceito de agente público é o mais amplo possível (com ou sem remuneração).", status:0, historico:0 },
{ id:323, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Improbidade Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"A multa civil pode ser aumentada até o dobro, se o juiz considerar que, em virtude da situação econômica do réu, o valor inicial é:", imagem:null, alternativas:["A) Incompatível com o dano causado.","B) Insuficiente para a finalidade de punição e dissuasão.","C) Inferior ao valor da remuneração do agente no ano do fato.","D) Contrário ao princípio da dignidade da pessoa humana.","E) Maior que o lucro obtido pelo agente com o ato ilícito."], resposta_correta:1, explicacao:"Justificativa: Art. 12, § 2º: Se o réu for muito rico e a multa padrão for 'irrisória', o juiz pode dobrar o valor.", status:0, historico:0 },
{ id:324, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Nos termos da Lei nº 9.784/1999, que regula o processo administrativo federal, é direito do administrado perante a Administração Pública:", imagem:null, alternativas:["A) Ser tratado com urbanidade, apenas se for servidor de outro órgão.","B) Fazer-se assistir, obrigatoriamente, por advogado em todas as fases do processo.","C) Ter ciência da tramitação dos processos em que tenha a condição de interessado e obter cópias de documentos.","D) Prestar depoimento apenas se houver ordem judicial prévia.","E) Escolher o servidor que irá analisar seu processo por afinidade técnica."], resposta_correta:2, explicacao:"Justificativa: Art. 3º, II: Direito à informação e cópias. Advogado é opcional no PA.", status:0, historico:0 },
{ id:325, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Dentre os princípios expressamente previstos no caput do Art. 2º da Lei nº 9.784/1999, NÃO se inclui o da:", imagem:null, alternativas:["A) Motivação.","B) Razoabilidade.","C) Segurança Jurídica.","D) Ampla Defesa.","E) Supremacia do Poder Hierárquico."], resposta_correta:4, explicacao:"Justificativa: Hierarquia é critério de organização, não princípio do caput da Lei 9784.", status:0, historico:0 },
{ id:326, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Sobre a competência no processo administrativo, assinale a alternativa correta:", imagem:null, alternativas:["A) A competência é irrenunciável e se exerce pelos órgãos administrativos a que foi atribuída como própria.","B) Um órgão administrativo não pode delegar parte de sua competência a outros órgãos se não houver subordinação hierárquica.","C) O ato de delegação e sua revogação não precisam ser publicados no meio oficial.","D) A avocação de competência é a regra, ocorrendo sempre que o superior desejar.","E) É delegável a decisão de recursos administrativos para garantir celeridade."], resposta_correta:0, explicacao:"Justificativa: Art. 11: Competência é irrenunciável. Delegação pode ocorrer mesmo sem hierarquia (Art. 12).", status:0, historico:0 },
{ id:327, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Um servidor do CRECI-BA é designado para julgar um processo onde o interessado é seu primo de 2º grau. Segundo a Lei nº 9.784/1999, esse servidor:", imagem:null, alternativas:["A) Está impedido de atuar, pois há relação de parentesco.","B) É apenas suspeito, podendo atuar se declarar sua imparcialidade.","C) Pode atuar normalmente, visto que o impedimento é apenas para parentes de 1º grau.","D) Deve solicitar autorização ao Ministério Público para prosseguir.","E) Está impedido apenas se o primo for credor ou devedor do servidor."], resposta_correta:0, explicacao:"Justificativa: Art. 18, II: Impedimento por parentesco até o 3º grau.", status:0, historico:0 },
{ id:328, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"A Administração Pública Federal tem o dever de emitir decisão explícita em processos administrativos. Concluída a instrução, o prazo para decidir é de:", imagem:null, alternativas:["A) 15 dias, improrrogáveis.","B) 30 dias, podendo ser prorrogado por igual período mediante motivação.","C) 60 dias, se o processo envolver matéria técnica complexa.","D) 5 dias, sob pena de nulidade do ato por omissão.","E) Não há prazo legal, devendo observar-se o tempo razoável."], resposta_correta:1, explicacao:"Justificativa: Art. 49: Prazo de 30 dias, prorrogável por mais 30.", status:0, historico:0 },
{ id:329, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"No processo administrativo, os atos do órgão instrucional que não tenham por objeto a decisão de mérito deverão ser praticados no prazo de:", imagem:null, alternativas:["A) 2 dias.","B) 5 dias.","C) 10 dias.","D) 15 dias.","E) 30 dias."], resposta_correta:1, explicacao:"Justificativa: Art. 24: Prazo de 5 dias para atos gerais, salvo disposição em contrário.", status:0, historico:0 },
{ id:330, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Considera-se 'interessado' no processo administrativo, para fins de direito a recurso:", imagem:null, alternativas:["A) Exclusivamente a pessoa física que iniciou o processo.","B) Aqueles que, sem terem iniciado o processo, têm direitos ou interesses que possam ser afetados pela decisão.","C) Apenas o Ministério Público e a Defensoria Pública.","D) Servidores do órgão que tenham amizade com o requerente.","E) Qualquer cidadão, independentemente de sofrer impacto com a decisão."], resposta_correta:1, explicacao:"Justificativa: Art. 9º, II: Interessados são os que têm direitos afetados.", status:0, historico:0 },
{ id:331, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Sobre a motivação dos atos administrativos na Lei nº 9.784/1999, assinale a INCORRETA:", imagem:null, alternativas:["A) Devem ser motivados os atos que neguem, limitem ou afetem direitos ou interesses.","B) A motivação deve ser clara e congruente, podendo consistir em declaração de concordância com fundamentos de pareceres anteriores.","C) A motivação é facultativa em atos que decidam recursos administrativos.","D) Devem ser motivados os atos que dispensem ou declarem a inexigibilidade de processo licitatório.","E) A motivação deve indicar os fundamentos de fato e de direito."], resposta_correta:2, explicacao:"Justificativa: Art. 50, VII: A decisão de recursos administrativos DEVE ser motivada.", status:0, historico:0 },
{ id:332, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Os prazos no processo administrativo federal começam a correr a partir da data da cientificação oficial e são contados:", imagem:null, alternativas:["A) Em dias úteis, excluindo o dia do começo e incluindo o do vencimento.","B) Em dias corridos, incluindo o dia do começo e excluindo o do vencimento.","C) Em dias corridos, excluindo o dia do começo e incluindo o do vencimento.","D) Em horas úteis, a partir do protocolo.","E) Conforme o critério do servidor responsável pela intimação."], resposta_correta:2, explicacao:"Justificativa: Art. 66: Dias corridos, exclui o início e inclui o fim.", status:0, historico:0 },
{ id:333, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Das decisões administrativas cabe recurso, em face de razões de legalidade e de mérito. O prazo para interposição de recurso administrativo é de:", imagem:null, alternativas:["A) 5 dias úteis.","B) 10 dias corridos.","C) 15 dias corridos.","D) 30 dias úteis.","E) 60 dias corridos."], resposta_correta:1, explicacao:"Justificativa: Art. 59: Prazo de 10 dias para recorrer.", status:0, historico:0 },
{ id:334, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Em um processo no CRECI-BA, a autoridade nota que houve um vício de legalidade insanável. Ela deve:", imagem:null, alternativas:["A) Revogar o ato por razões de interesse público.","B) Anular o ato, de ofício ou mediante provocação.","C) Convalidar o ato, pois o tempo cura a ilegalidade.","D) Suspender o processo até que o interessado conserte o vício.","E) Encaminhar o caso para a Polícia Federal imediatamente."], resposta_correta:1, explicacao:"Justificativa: Art. 53: A Administração DEVE anular atos ilegais.", status:0, historico:0 },
{ id:335, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Salvo disposição legal específica, o recurso administrativo tramitará, no máximo, por:", imagem:null, alternativas:["A) Duas instâncias administrativas.","B) Três instâncias administrativas.","C) Quatro instâncias administrativas.","D) Instâncias ilimitadas até o esgotamento da matéria.","E) Uma única instância, sendo a decisão soberana."], resposta_correta:1, explicacao:"Justificativa: Art. 57: Máximo de 3 instâncias.", status:0, historico:0 },
{ id:336, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Sobre a desistência e renúncia no processo administrativo, assinale a correta:", imagem:null, alternativas:["A) O interessado pode desistir do pedido, mas isso impede que ele entre com novo pedido no futuro.","B) A desistência do interessado obriga a Administração a extinguir o processo imediatamente.","C) A Administração pode prosseguir com o processo se considerar que o interesse público assim o exige, mesmo com desistência.","D) Desistência e renúncia são atos que exigem concordância do Ministério Público.","E) Só é permitida a desistência se o processo não tiver ultrapassado a fase de instrução."], resposta_correta:2, explicacao:"Justificativa: Art. 51, § 2º: A Administração pode seguir se houver interesse público.", status:0, historico:0 },
{ id:337, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"A intimação do interessado para ciência de decisão ou efetivação de diligência deve observar a antecedência mínima de:", imagem:null, alternativas:["A) 24 horas.","B) 48 horas.","C) 3 dias úteis.","D) 5 dias corridos.","E) 15 dias corridos."], resposta_correta:2, explicacao:"Justificativa: Art. 26, § 2º: Antecedência mínima de 3 dias úteis.", status:0, historico:0 },
{ id:338, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Quando o vício de um ato administrativo for sanável e não acarretar lesão ao interesse público nem prejuízo a terceiros, a autoridade poderá:", imagem:null, alternativas:["A) Anulá-lo preventivamente.","B) Revogá-lo por conveniência.","C) Convalidá-lo.","D) Ignorá-lo sob o manto da discricionariedade.","E) Extingui-lo por caducidade."], resposta_correta:2, explicacao:"Justificativa: Art. 55: Convalidação de vícios sanáveis.", status:0, historico:0 },
{ id:339, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Inexistindo disposição específica, os atos do órgão instrucional deverão ser praticados no prazo de cinco dias. Caso não seja cumprido pelo servidor:", imagem:null, alternativas:["A) O ato é nulo de pleno direito.","B) O processo é arquivado por inércia.","C) O superior deve ser informado para fins de apuração de responsabilidade.","D) O prazo é dobrado automaticamente sem necessidade de aviso.","E) O interessado ganha o direito de decidir a matéria em seu favor."], resposta_correta:2, explicacao:"Justificativa: Art. 24, § 1º: O descumprimento de prazo deve ser reportado ao superior.", status:0, historico:0 },
{ id:340, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Assinale a alternativa que indica uma hipótese em que o processo administrativo NÃO pode ser iniciado:", imagem:null, alternativas:["A) Por iniciativa de associações em defesa de direitos coletivos.","B) Por provocação de interessado pessoa jurídica.","C) De ofício pela autoridade que detém a competência.","D) Anonimamente, em qualquer circunstância, sem indicação de fatos.","E) Por menores de 18 anos que possuam capacidade civil nos termos da lei."], resposta_correta:3, explicacao:"Justificativa: O PA exige identificação do interessado (Art. 6º).", status:0, historico:0 },
{ id:341, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Um processo administrativo federal pode ser extinto quando o objeto da decisão se tornar impossível, inútil ou prejudicado por fato superveniente. Esse encerramento deve ser:", imagem:null, alternativas:["A) Mantido em sigilo para evitar recursos.","B) Decidido por sorteio entre os conselheiros.","C) Motivadoramente declarado pela autoridade.","D) Comunicado apenas ao Ministério Público.","E) Realizado sem necessidade de intimação do interessado."], resposta_correta:2, explicacao:"Justificativa: Art. 52: Extinção por perda de objeto exige motivação.", status:0, historico:0 },
{ id:342, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Sobre a fase de instrução no processo administrativo, é correto afirmar que:", imagem:null, alternativas:["A) Cabe ao interessado a prova dos fatos que tenha alegado, mas a Administração pode produzir provas de ofício.","B) É vedada a realização de audiências públicas para não expor a intimidade do administrado.","C) O interessado não tem direito de formular quesitos em perícias técnicas.","D) Elementos de prova obtidos por meios ilícitos são aceitos se ajudarem na busca pela verdade real.","E) A Administração não pode recusar provas propostas pelos interessados em nenhuma hipótese."], resposta_correta:0, explicacao:"Justificativa: Art. 28 e 29: Ônus da prova é do interessado, mas há o impulso oficial.", status:0, historico:0 },
{ id:343, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Processo Administrativo", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"O direito da Administração de anular os atos administrativos de que decorram efeitos favoráveis para os destinatários decai em:", imagem:null, alternativas:["A) 2 anos.","B) 5 anos, salvo comprovada má-fé.","C) 8 anos, seguindo o prazo de improbidade.","D) 10 anos, para atos que envolvam gastos financeiros.","E) Nunca, pois a nulidade é absoluta."], resposta_correta:1, explicacao:"Justificativa: Art. 54: Prazo decadencial de 5 anos (salvo má-fé).", status:0, historico:0 },
{ id:344, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Transparência e Controle", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"No que se refere à transparência ativa prevista na Lei nº 12.527/2011, é dever dos órgãos e entidades públicas a divulgação em seus sítios oficiais de informações de interesse coletivo, EXCETO:", imagem:null, alternativas:["A) Estrutura organizacional e competências do órgão.","B) Registros de quaisquer repasses ou transferências de recursos financeiros.","C) Informações detalhadas sobre a vida privada de seus dirigentes.","D) Procedimentos para a realização de licitações e seus respectivos editais.","E) Respostas a perguntas mais frequentes da sociedade."], resposta_correta:2, explicacao:"Justificativa: A LAI protege a vida privada, honra e imagem (Art. 31). A transparência ativa foca em dados institucionais e financeiros do órgão.", status:0, historico:0 },
{ id:345, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"De acordo com a Lei nº 13.709/2018 (LGPD), o dado pessoal sobre origem racial ou étnica, convicção religiosa, opinião política, filiação a sindicato ou a organização de caráter religioso, filosófico ou político é classificado como:", imagem:null, alternativas:["A) Dado pessoal anonimizado.","B) Dado pessoal sensível.","C) Dado público de livre acesso.","D) Dado institucional irrestrito.","E) Dado pessoal de natureza administrativa."], resposta_correta:1, explicacao:"Justificativa: Art. 5º, II: Define dados sensíveis como aqueles que podem gerar discriminação (origem, religião, política, etc.).", status:0, historico:0 },
{ id:346, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Transparência e Controle", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Ao receber um pedido de acesso à informação, caso a informação não esteja disponível de imediato, o órgão deverá responder no prazo de até:", imagem:null, alternativas:["A) 10 dias, improrrogáveis.","B) 15 dias, podendo ser prorrogado por mais 5 dias.","C) 20 dias, podendo ser prorrogado por mais 10 dias, mediante justificativa.","D) 30 dias, independentemente de justificativa.","E) 5 dias úteis, contados do recebimento."], resposta_correta:2, explicacao:"Justificativa: Art. 11, § 1º: Prazo de 20 dias, prorrogável por mais 10 dias com justificativa expressa.", status:0, historico:0 },
{ id:347, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Um Conselho Regional de Corretores de Imóveis (CRECI) contrata uma empresa de software para realizar o processamento dos dados de seus inscritos. Sob a ótica da LGPD, o CRECI e a empresa de software são, respectivamente:", imagem:null, alternativas:["A) Operador e Controlador.","B) Titular e Encarregado.","C) Controlador e Operador.","D) Agente de Tratamento e Autoridade Nacional.","E) Usuário e Processador."], resposta_correta:2, explicacao:"Justificativa: Art. 5º, VI e VII: O Controlador (CRECI) toma as decisões; o Operador (empresa) realiza o tratamento em nome do controlador.", status:0, historico:0 },
{ id:348, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Transparência e Controle", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"As informações que possam colocar em risco a segurança do Presidente e Vice-Presidente da República e respectivos cônjuges e filhos serão classificadas como reservadas e ficarão sob sigilo até o término do mandato, EXCETO:", imagem:null, alternativas:["A) Se envolverem gastos com cartão corporativo.","B) Se o Presidente decidir pela publicidade imediata.","C) Se o mandato for interrompido por renúncia.","D) Se houver decisão do Poder Judiciário em sentido contrário.","E) A lei não prevê exceções, o sigilo é absoluto por 100 anos."], resposta_correta:1, explicacao:"Justificativa: Art. 24, § 2º: O sigilo dura até o término do mandato ou período presidencial, mas não há essa exceção de 'gasto' ou 'renúncia' na letra da lei.", status:0, historico:0 },
{ id:349, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"O princípio da LGPD que garante aos titulares a consulta facilitada e gratuita sobre a forma e a duração do tratamento, bem como sobre a integralidade de seus dados pessoais, é o da:", imagem:null, alternativas:["A) Prevenção.","B) Transparência.","C) Livre acesso.","D) Necessidade.","E) Não discriminação."], resposta_correta:2, explicacao:"Justificativa: Art. 6º, IV: O livre acesso garante ao titular saber como seus dados são tratados de forma gratuita.", status:0, historico:0 },
{ id:350, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Transparência e Controle", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"No processo de classificação de informação em grau de sigilo, a autoridade que possui competência para classificar uma informação como ULTRASSECRETA no âmbito federal é:", imagem:null, alternativas:["A) Qualquer servidor ocupante de cargo DAS-4 ou superior.","B) Comandantes da Marinha, Exército e Aeronáutica.","C) O Encarregado de Dados do órgão.","D) O Presidente do Conselho Regional interessado.","E) Apenas o Presidente da República."], resposta_correta:1, explicacao:"Justificativa: Art. 27, I: Chefes de missões diplomáticas e comandantes militares podem classificar como ultrassecreta.", status:0, historico:0 },
{ id:351, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"A pessoa indicada pelo controlador e operador para atuar como canal de comunicação entre o controlador, os titulares dos dados e a Autoridade Nacional de Proteção de Dados (ANPD) é o:", imagem:null, alternativas:["A) Auditor Independente.","B) Ouvidor-Geral.","C) Encarregado.","D) Gestor de Segurança da Informação.","E) Secretário de Transparência."], resposta_correta:2, explicacao:"Justificativa: Art. 5º, VIII: O Encarregado (DPO) é a ponte entre as partes envolvidas no tratamento.", status:0, historico:0 },
{ id:352, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Transparência e Controle", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"A Lei de Acesso à Informação estabelece que o serviço de busca e fornecimento da informação é gratuito, ressalvada a cobrança de:", imagem:null, alternativas:["A) Taxas de protocolo administrativo.","B) Honorários de pesquisa por hora trabalhada pelo servidor.","C) Valor correspondente ao custo dos serviços e materiais utilizados na reprodução de documentos.","D) Tarifas de conveniência para atendimento presencial.","E) Multas por pedidos considerados repetitivos."], resposta_correta:2, explicacao:"Justificativa: Art. 12: O acesso é gratuito, mas o material de reprodução (xerox, pendrive) pode ser cobrado.", status:0, historico:0 },
{ id:353, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Sobre o consentimento para tratamento de dados pessoais na LGPD, assinale a alternativa correta:", imagem:null, alternativas:["A) O consentimento deve ser sempre por escrito, sob pena de nulidade.","B) Pode ser revogado a qualquer momento mediante manifestação expressa do titular, por procedimento gratuito e facilitado.","C) O consentimento obtido para uma finalidade genérica é válido para todos os tratamentos futuros do órgão.","D) É proibido o tratamento de dados de crianças e adolescentes, mesmo com consentimento.","E) Uma vez dado o consentimento, o titular não pode mais solicitar a exclusão dos dados."], resposta_correta:1, explicacao:"Justificativa: Art. 8º, § 5º: O consentimento é revogável e a revogação deve ser fácil e gratuita.", status:0, historico:0 },
{ id:354, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Transparência e Controle", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Caso o acesso à informação seja negado, o requerente poderá interpor recurso contra a decisão no prazo de 10 dias a contar da sua ciência. Esse recurso deverá ser dirigido à:", imagem:null, alternativas:["A) Autoridade máxima do próprio órgão.","B) Autoridade hierarquicamente superior à que exarou a decisão negativa.","C) Controladoria-Geral da União, obrigatoriamente em primeira instância.","D) Justiça Federal, mediante petição assinada por advogado.","E) Comissão Mista de Reavaliação de Informações."], resposta_correta:1, explicacao:"Justificativa: Art. 15: O recurso administrativo sobe para a autoridade superior à que negou o pedido.", status:0, historico:0 },
{ id:355, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"A LGPD NÃO se aplica ao tratamento de dados pessoais realizado:", imagem:null, alternativas:["A) Por pessoa jurídica de direito público para fins de segurança pública.","B) Para fins exclusivamente jornalísticos e artísticos.","C) Por conselhos profissionais para fiscalização de seus inscritos.","D) Através de meios digitais por empresas de e-commerce nacionais.","E) Por profissionais liberais que mantêm cadastro de clientes."], resposta_correta:1, explicacao:"Justificativa: Art. 4º, II, 'a': A LGPD não se aplica para fins exclusivamente jornalísticos e artísticos.", status:0, historico:0 },
{ id:356, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Transparência e Controle", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Informações pessoais relativas à intimidade, vida privada, honra e imagem terão seu acesso restrito, independentemente de classificação de sigilo, pelo prazo máximo de:", imagem:null, alternativas:["A) 10 anos a contar da data de sua produção.","B) 30 anos a contar da data de sua produção.","C) 50 anos a contar da data de sua produção.","D) 100 anos a contar da data de sua produção.","E) Período indeterminado, enquanto o titular estiver vivo."], resposta_correta:3, explicacao:"Justificativa: Art. 31, § 1º, I: O prazo de proteção de dados pessoais na LAI é de 100 anos.", status:0, historico:0 },
{ id:357, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"A utilização de meios técnicos razoáveis e disponíveis no momento do tratamento, por meio dos quais um dado perde a possibilidade de associação, direta ou indireta, a um indivíduo, é chamada de:", imagem:null, alternativas:["A) Criptografia simétrica.","B) Pseudoanonimização.","C) Anonimização.","D) Eliminação de dados.","E) Blindagem digital."], resposta_correta:2, explicacao:"Justificativa: Art. 5º, XI: Definição de anonimização (perda de associação com o indivíduo).", status:0, historico:0 },
{ id:358, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Transparência e Controle", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Um cidadão solicita ao CRECI-BA uma listagem contendo o nome e o número de registro de todos os corretores ativos na região. Segundo a LAI, tal pedido:", imagem:null, alternativas:["A) Deve ser negado por violar a privacidade dos corretores.","B) Deve ser atendido, pois se trata de informação de interesse público e registro profissional.","C) Só pode ser atendido se houver autorização expressa de cada corretor.","D) Deve ser atendido mediante pagamento de uma taxa de serviço extraordinário.","E) Deve ser negado se o solicitante não apresentar o motivo da consulta."], resposta_correta:1, explicacao:"Justificativa: Registros profissionais e nomes de inscritos em autarquias são dados públicos por natureza da atividade.", status:0, historico:0 },
{ id:359, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"O tratamento de dados pessoais pode ser realizado sem o consentimento do titular em diversas hipóteses legais. NÃO constitui uma dessas hipóteses:", imagem:null, alternativas:["A) Para o cumprimento de obrigação legal ou regulatória pelo controlador.","B) Para a execução de políticas públicas previstas em leis e regulamentos.","C) Para a realização de pesquisas por órgão de pesquisa, garantida a anonimização sempre que possível.","D) Para fins de marketing direto e prospecção de clientes por empresas privadas.","E) Para a proteção da vida ou da incolumidade física do titular ou de terceiro."], resposta_correta:3, explicacao:"Justificativa: Marketing não é base legal automática; exige legítimo interesse ou consentimento, dependendo do caso.", status:0, historico:0 },
{ id:360, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Transparência e Controle", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Submetem-se aos ditames da Lei nº 12.527/2011 (LAI) as entidades privadas sem fins lucrativos que recebam, para realização de ações de interesse público, recursos públicos diretamente do orçamento ou mediante:", imagem:null, alternativas:["A) Empréstimos bancários com juros de mercado.","B) Contratos de gestão, termos de parceria ou convênios.","C) Doações de pessoas físicas anônimas.","D) Aluguéis de imóveis de terceiros.","E) Venda de produtos em bazares beneficentes."], resposta_correta:1, explicacao:"Justificativa: Art. 2º: Entidades privadas que recebem recursos via convênios/parcerias devem prestar contas via LAI.", status:0, historico:0 },
{ id:361, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Conforme a LGPD, o tratamento de dados pessoais cujo acesso é público deve considerar a finalidade, a boa-fé e o interesse público que justificaram sua disponibilização. Nesse contexto:", imagem:null, alternativas:["A) Dados públicos podem ser utilizados para qualquer finalidade sem restrições.","B) É dispensada a observância dos princípios da LGPD por serem dados já expostos.","C) O controlador que obteve o dado público é dispensado de obter novo consentimento para finalidades idênticas.","D) O dado público torna-se propriedade de quem o coletou.","E) A lei proíbe o cruzamento de dados públicos com dados privados."], resposta_correta:2, explicacao:"Justificativa: Art. 7º, § 4º: Dispensa novo consentimento se a finalidade original for mantida.", status:0, historico:0 },
{ id:362, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Transparência e Controle", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"São consideradas informações que podem ser classificadas como sigilosas aquelas cuja divulgação possa, entre outros:", imagem:null, alternativas:["A) Revelar falhas de gestão de governantes eleitos.","B) Prejudicar ou causar risco a planos ou operações estratégicos das Forças Armadas.","C) Gerar críticas negativas na imprensa sobre o desempenho de uma autarquia.","D) Expor salários de servidores ocupantes de cargos efetivos.","E) Divulgar agendas de reuniões de conselheiros de órgãos profissionais."], resposta_correta:1, explicacao:"Justificativa: Art. 23, IV: Segurança nacional e planos militares são passíveis de classificação.", status:0, historico:0 },
{ id:363, categoria:"Conhecimentos Complementares", materia:"Legislação", assunto:"Proteção de Dados", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"A documentação do controlador que contém a descrição dos processos de tratamento de dados pessoais que podem gerar riscos às liberdades civis e aos direitos fundamentais é o:", imagem:null, alternativas:["A) Plano Diretor de TI.","B) Relatório de Impacto à Proteção de Dados Pessoais (RIPD).","C) Manual de Conduta Ética Digital.","D) Termo de Uso e Política de Privacidade.","E) Inventário de Ativos de Rede."], resposta_correta:1, explicacao:"Justificativa: Art. 5º, XVII: O RIPD descreve os processos e riscos do tratamento de dados.", status:0, historico:0 },
{ id:364, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No âmbito do CRECI-BA, a função administrativa de Planejamento é responsável por estabelecer os objetivos da autarquia. Sobre essa função, assinale a alternativa que descreve uma característica do planejamento estratégico:", imagem:null, alternativas:["A) Possui foco no curto prazo e em tarefas específicas de fiscalização.","B) É elaborado pelos chefes de seção para o horizonte de um ano.","C) Envolve a organização como um todo e é voltado para o longo prazo.","D) Define metodicamente como cada processo administrativo será arquivado.","E) Restringe-se exclusivamente à alocação de recursos financeiros mensais."], resposta_correta:2, explicacao:"Justificativa: O planejamento estratégico é sistêmico, de longo prazo e abrange toda a organização. A Quadrix costuma trocar as características entre os níveis estratégico, tático (médio prazo) e operacional (curto prazo/tarefas).", status:0, historico:0 },
{ id:365, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A função administrativa que consiste em agrupar as atividades necessárias para atingir os objetivos e atribuir cada grupo a um executivo com autoridade para supervisionar as pessoas é a:", imagem:null, alternativas:["A) Planejamento.","B) Organização.","C) Direção.","D) Controle.","E) Execução."], resposta_correta:1, explicacao:"Justificativa: Organização refere-se à estruturação, alocação de recursos e divisão de trabalho. A pegadinha aqui é confundir 'supervisionar' com a função Direção, mas o foco do enunciado está no 'agrupamento de atividades' e 'atribuição de autoridade', que são pilares da Organização.", status:0, historico:0 },
{ id:366, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No que tange à função Direção, a teoria de motivação que divide os fatores em 'Higiênicos' (que evitam a insatisfação) e 'Motivacionais' (que geram satisfação) é a teoria de:", imagem:null, alternativas:["A) Maslow (Hierarquia das Necessidades).","B) Douglas McGregor (Teoria X e Y).","C) Frederick Herzberg (Teoria dos Dois Fatores).","D) David McClelland (Teoria das Necessidades Adquiridas).","E) Victor Vroom (Teoria da Expectância)."], resposta_correta:2, explicacao:"Justificativa: Herzberg diferencia fatores extrínsecos (higiênicos) de intrínsecos (motivacionais). A banca adora dizer que os fatores higiênicos, se presentes, garantem a motivação, o que é falso; eles apenas evitam a insatisfação.", status:0, historico:0 },
{ id:367, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Considere que o Diretor do CRECI estabeleça um padrão de desempenho para o setor de atendimento e, ao final do mês, compare o resultado alcançado com esse padrão. Esse processo refere-se à função de:", imagem:null, alternativas:["A) Organização, pois ordena o fluxo de trabalho.","B) Planejamento, pois define o padrão futuro.","C) Controle, que visa monitorar e corrigir desvios.","D) Direção, pois lidera a equipe rumo à meta.","E) Avaliação Punitiva, focada exclusivamente no erro."], resposta_correta:2, explicacao:"Justificativa: O controle possui as fases de: estabelecimento de padrões, observação do desempenho, comparação e ação corretiva. A Quadrix tenta induzir o erro ao sugerir que a definição do padrão é planejamento, mas no contexto de 'comparação' e 'correção', trata-se de Controle.", status:0, historico:0 },
{ id:368, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Gestão de Materiais e Almoxarifado", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Na gestão de estoques do conselho, a classificação ABC é uma ferramenta que diferencia os itens por sua importância e valor. É correto afirmar que os itens da Classe A:", imagem:null, alternativas:["A) Representam a maior quantidade de itens em estoque (cerca de 80%).","B) São itens de baixo valor monetário e alta importância operacional.","C) Representam a menor quantidade de itens, mas o maior valor financeiro acumulado.","D) Devem ser controlados de forma simplificada por serem abundantes.","E) São descartáveis e não exigem inventários periódicos."], resposta_correta:2, explicacao:"Justificativa: Classe A: Poucos itens (cerca de 20%) com alto valor (80%). Classe C: Muitos itens com baixo valor. A banca inverte as porcentagens e a importância para confundir o candidato.", status:0, historico:0 },
{ id:369, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Sobre o processo de recrutamento e seleção, assinale a alternativa que apresenta uma vantagem do recrutamento interno para o CRECI-BA:", imagem:null, alternativas:["A) Traz 'sangue novo' e ideias externas para a autarquia.","B) É mais econômico e motiva os atuais colaboradores com chances de promoção.","C) Garante a renovação total da cultura organizacional do órgão.","D) Exige testes de seleção mais rigorosos que o recrutamento externo.","E) Elimina a necessidade de treinamento de integração do servidor."], resposta_correta:1, explicacao:"Justificativa: O recrutamento interno aproveita o capital humano atual, é mais rápido, barato e funciona como fator motivacional. O erro comum é dizer que ele é sempre melhor que o externo, o que depende da necessidade de inovação.", status:0, historico:0 },
{ id:370, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A gestão financeira de uma autarquia exige o controle do 'Capital de Giro'. Este conceito refere-se a:", imagem:null, alternativas:["A) Recursos destinados exclusivamente para investimentos em novas sedes.","B) Diferença entre os ativos circulantes e os passivos circulantes, garantindo a operação.","C) Valor total arrecadado com anuidades durante um exercício de dez anos.","D) Empréstimos bancários de longo prazo para quitação de dívidas trabalhistas.","E) Patrimônio líquido total, incluindo imóveis e frotas de veículos."], resposta_correta:1, explicacao:"Justificativa: Capital de giro (ou Ativo Circulante) é o recurso necessário para as operações do dia a dia. A banca costuma confundir com patrimônio fixo ou receitas de longo prazo.", status:0, historico:0 },
{ id:371, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise os itens abaixo sobre as funções administrativas:\nI. A descentralização distribui a autoridade para os níveis inferiores.\nII. A liderança autocrática foca na participação total do subordinado.\nIII. O controle preventivo ocorre durante a execução da atividade.\nAssinale a alternativa que apresenta a sequência correta de verdadeiro (V) ou falso (F):", imagem:null, alternativas:["A) V, V, V","B) V, F, F","C) F, V, F","D) V, F, V","E) F, F, V"], resposta_correta:1, explicacao:"Justificativa: I-V; II-F (Autocrática é centralizadora; a democrática é participativa); III-F (Preventivo é antes; o que ocorre durante é o simultâneo/concorrente). A Quadrix adora essas inversões técnicas sutis.", status:0, historico:0 },
{ id:372, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Uma estrutura organizacional funcional caracteriza-se por:", imagem:null, alternativas:["A) Unidade de comando absoluta, onde cada subordinado reporta a apenas um chefe.","B) Especialização das funções, onde cada setor responde por sua área de conhecimento.","C) Ser indicada apenas para organizações muito pequenas e instáveis.","D) Facilitar a visão global da organização em detrimento da técnica.","E) Isolar completamente os departamentos, impedindo qualquer comunicação entre eles."], resposta_correta:1, explicacao:"Justificativa: Na estrutura funcional, a autoridade é baseada na especialização. A pegadinha é dizer que ela mantém a 'unidade de comando' (que é característica da estrutura Linear).", status:0, historico:0 },
{ id:373, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Gestão de Materiais e Almoxarifado", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O Inventário Rotativo diferencia-se do Inventário Periódico por:", imagem:null, alternativas:["A) Ser realizado obrigatoriamente apenas uma vez ao ano para fechamento de balanço.","B) Consistir na contagem contínua de grupos de itens ao longo do tempo.","C) Exigir a paralisação total das atividades de fiscalização para ser executado.","D) Ser menos preciso por não conferir todos os itens da autarquia de uma vez.","E) Aplicar-se exclusivamente a itens de baixo valor (Classe C)."], resposta_correta:1, explicacao:"Justificativa: Rotativo = contínuo e sem parar a operação. Periódico = anual e geralmente exige parada. A banca inverte as definições para confundir o candidato sobre a eficiência de cada método.", status:0, historico:0 },
{ id:374, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No processo de Treinamento e Desenvolvimento (T&D), o treinamento é considerado uma ação de:", imagem:null, alternativas:["A) Longo prazo, focada na carreira futura do servidor.","B) Curto prazo, focada no desempenho do cargo atual.","C) Natureza exclusivamente teórica, sem aplicação prática no CRECI.","D) Caráter punitivo para servidores com baixo rendimento funcional.","E) Responsabilidade única do servidor, sem interferência da administração."], resposta_correta:1, explicacao:"Justificativa: Treinamento = Curto prazo/Cargo atual. Desenvolvimento = Longo prazo/Carreira. Inversão clássica da Quadrix em temas de RH.", status:0, historico:0 },
{ id:375, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Considere as seguintes assertivas sobre o Ciclo PDCA:\nI. 'P' (Plan) refere-se à execução rigorosa do que foi decidido.\nII. 'D' (Do) envolve o treinamento e a execução do processo.\nIII. 'C' (Check) foca na verificação dos resultados e monitoramento.\nIV. 'A' (Act) consiste na ação corretiva para padronizar o sucesso ou aprender com o erro.\nEstão corretas apenas:", imagem:null, alternativas:["A) I e II.","B) III e IV.","C) II, III e IV.","D) I, III e IV.","E) Todas as assertivas."], resposta_correta:2, explicacao:"Justificativa: A I está errada porque o 'Plan' é o planejamento, não a execução (que é o Do). A banca costuma descrever o 'Do' como se fosse 'Design' (planejar) para induzir ao erro.", status:0, historico:0 },
{ id:376, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Gestão de Materiais e Almoxarifado", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O 'Ponto de Pedido' na gestão de estoques é o momento em que:", imagem:null, alternativas:["A) O estoque atinge o nível zero e a autarquia para de operar.","B) Deve-se emitir uma nova compra para evitar a ruptura do estoque antes da chegada do material.","C) O fornecedor entrega os materiais solicitados na delegacia regional.","D) O almoxarife decide descartar itens obsoletos por falta de espaço.","E) A anuidade dos corretores é reajustada para cobrir custos de materiais."], resposta_correta:1, explicacao:"Justificativa: Ponto de pedido é o nível de estoque que dispara o processo de compra, considerando o tempo de ressuprimento. Não confundir com estoque mínimo ou estoque máximo.", status:0, historico:0 },
{ id:377, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O indicador financeiro que mede a capacidade de uma organização de pagar suas dívidas de curto prazo com seus ativos de curto prazo é a:", imagem:null, alternativas:["A) Lucratividade bruta.","B) Liquidez Corrente.","C) Rentabilidade sobre o investimento.","D) Alavancagem operacional.","E) Margem de contribuição fixa."], resposta_correta:1, explicacao:"Justificativa: Liquidez Corrente = Ativo Circulante / Passivo Circulante. A Quadrix cobra esse termo técnico para cargos administrativos para testar a base de contabilidade básica/finanças.", status:0, historico:0 },
{ id:378, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um líder que delega a autoridade de decisão aos subordinados, permitindo que o grupo defina seus próprios passos com mínima interferência, adota um estilo:", imagem:null, alternativas:["A) Autocrático.","B) Democrático.","C) Laissez-faire (Liberal).","D) Transacional coercitivo.","E) Burocrático estrito."], resposta_correta:2, explicacao:"Justificativa: No estilo liberal (laissez-faire), a liberdade é total para o grupo. A pegadinha é confundir com o democrático, onde o líder ainda orienta e participa da decisão junto com o grupo.", status:0, historico:0 },
{ id:379, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A Avaliação de Desempenho 360 graus caracteriza-se por:", imagem:null, alternativas:["A) Ser realizada exclusivamente pelo superior imediato do servidor.","B) Envolver avaliações de superiores, pares, subordinados e, às vezes, clientes/usuários.","C) Focar apenas nos erros cometidos pelo funcionário no último ano.","D) Ser um processo secreto onde o avaliado não toma conhecimento do resultado.","E) Aplicar-se apenas a cargos de diretoria, sendo vedada para assistentes."], resposta_correta:1, explicacao:"Justificativa: A avaliação 360 graus busca uma visão circular e multirrelacional. A banca adora restringir o conceito (dizendo que é só o chefe que avalia) para tornar o item falso.", status:0, historico:0 },
{ id:380, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Gestão de Materiais e Almoxarifado", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O método de avaliação de estoque que considera que os primeiros itens a entrar no estoque devem ser os primeiros a sair (valorizando o estoque pelo preço mais recente) é o:", imagem:null, alternativas:["A) UEPS (Último que entra, primeiro que sai).","B) PEPS (Primeiro que entra, primeiro que sai).","C) MPM (Média Ponderada Móvel).","D) Custo Padrão Teórico.","E) Valor de Mercado Justo."], resposta_correta:1, explicacao:"Justificativa: PEPS (ou FIFO). No Brasil, para fins fiscais, o UEPS é proibido, e a Quadrix gosta de cobrar as siglas para ver se o candidato sabe o que cada letra significa.", status:0, historico:0 },
{ id:381, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Sobre a 'Amplitude Administrativa' (ou de controle), assinale a afirmação correta:", imagem:null, alternativas:["A) Refere-se à distância física entre a sede e as delegacias regionais do CRECI.","B) Quanto maior a amplitude, menor o número de subordinados por chefe.","C) Uma amplitude estreita gera estruturas organizacionais mais altas (verticais).","D) A amplitude ideal é de exatamente 10 funcionários para cada gestor administrativo.","E) É uma medida financeira que indica o alcance do orçamento do conselho."], resposta_correta:2, explicacao:"Justificativa: Amplitude estreita = poucos subordinados = mais níveis hierárquicos = estrutura alta/vertical. Inversão lógica clássica entre amplitude larga (achatada) e estreita (alta).", status:0, historico:0 },
{ id:382, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No contexto do fluxo de caixa, a 'Inadimplência' das anuidades dos corretores impacta diretamente:", imagem:null, alternativas:["A) O Ativo Não Circulante da autarquia.","B) A Liquidez Imediata e a disponibilidade de caixa para pagamentos correntes.","C) Apenas a imagem ética do conselho, sem repercussão financeira real.","D) O Passivo Exigível de longo prazo do órgão.","E) O valor de mercado das multas já aplicadas e transitadas em julgado."], resposta_correta:1, explicacao:"Justificativa: Inadimplência significa que o dinheiro previsto não entrou em caixa, afetando a liquidez imediata. Questão de microcontexto real para o cargo no CRECI.", status:0, historico:0 },
{ id:383, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise as assertivas abaixo quanto ao processo de Seleção de Pessoas:\nI. A entrevista é uma técnica subjetiva de seleção.\nII. Testes de conhecimento visam medir a aptidão potencial do candidato.\nIII. A dinâmica de grupo avalia o comportamento e a interação interpessoal.\nIV. A seleção é um processo de comparação entre os requisitos do cargo e o perfil do candidato.\nSão corretas as assertivas:", imagem:null, alternativas:["A) I e II.","B) III e IV.","C) I, III e IV.","D) II, III e IV.","E) I, II, III e IV."], resposta_correta:2, explicacao:"Justificativa: A II está incorreta porque testes de conhecimento medem capacidade ATUAL (adquirida), enquanto testes de psicometria/aptidão medem potencial. Distinção sutil que a Quadrix adora.", status:0, historico:0 },
{ id:384, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No contexto da gestão do CRECI-BA, os manuais administrativos funcionam como guias de conduta e padronização. Assinale a alternativa que descreve corretamente o 'Manual de Organização':", imagem:null, alternativas:["A) Detalha o passo a passo técnico de como preencher um auto de infração de fiscalização.","B) Descreve a estrutura da autarquia, as responsabilidades das unidades e as relações de autoridade.","C) Reúne exclusivamente os modelos de todos os documentos e formulários usados pelo conselho.","D) Define as metas estratégicas de longo prazo, substituindo o planejamento estratégico do órgão.","E) É um documento de circulação externa que visa orientar o corretor sobre como pagar a anuidade."], resposta_correta:1, explicacao:"Justificativa: O Manual de Organização foca na estrutura (organograma), funções e níveis de autoridade. A pegadinha da Quadrix é trocar sua definição pela do Manual de Procedimentos (opção A) ou de Formulários (opção C).", status:0, historico:0 },
{ id:385, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Os manuais administrativos oferecem diversas vantagens para a administração pública. No entanto, uma limitação inerente a esses documentos é que:", imagem:null, alternativas:["A) Eliminam definitivamente a necessidade de comunicação interpessoal entre os servidores do CRECI.","B) Garantem que os processos nunca precisem de atualizações frente às mudanças na legislação.","C) Podem levar à rigidez administrativa se não forem revisados periodicamente para se adaptar à realidade.","D) Impedem que novos servidores cometam erros operacionais, independentemente do treinamento.","E) São de implementação gratuita, não gerando custos de elaboração ou manutenção para a autarquia."], resposta_correta:2, explicacao:"Justificativa: Manuais podem burocratizar excessivamente o fluxo se forem muito rígidos. A banca costuma usar palavras como 'eliminam' ou 'garantem' (A e B) para criar alternativas falsas e absolutas.", status:0, historico:0 },
{ id:386, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Procedimentos Administrativos", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A tramitação de processos no CRECI-BA deve seguir um fluxo lógico e padronizado. O procedimento administrativo que consiste em listar todos os documentos que compõem um processo e sua respectiva ordem é chamado de:", imagem:null, alternativas:["A) Protocolização de saída.","B) Triagem de conveniência.","C) Indexação (ou Folheação).","D) Arquivamento temporário de urgência.","E) Despacho decisório interlocutório."], resposta_correta:2, explicacao:"Justificativa: A indexação organiza a ordem das peças do processo para facilitar a consulta. A Quadrix cria termos que 'soam' técnicos, como 'triagem de conveniência', para confundir o candidato.", status:0, historico:0 },
{ id:387, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise os itens sobre os objetivos dos manuais administrativos:\nI. Servir como instrumento de treinamento para novos colaboradores.\nII. Padronizar o atendimento ao público nas delegacias regionais.\nIII. Reduzir a necessidade de consultas constantes aos superiores sobre rotinas.\nAssinale a alternativa que apresenta a sequência correta de verdadeiro (V) ou falso (F):", imagem:null, alternativas:["A) V, V, V","B) V, F, V","C) F, V, F","D) V, V, F","E) F, F, V"], resposta_correta:0, explicacao:"Justificativa: Todos os itens são objetivos clássicos de manuais. A Quadrix tenta desmerecer o manual como ferramenta de treinamento (I) ou de independência funcional (III).", status:0, historico:0 },
{ id:388, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Procedimentos Administrativos", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Considere que o CRECI-BA decida revisar seus procedimentos de atendimento para torná-los mais rápidos. Este processo de análise e melhoria dos métodos de trabalho é objeto de estudo da:", imagem:null, alternativas:["A) Contabilidade Pública Gerencial.","B) Organização, Sistemas e Métodos (OSM).","C) Auditoria Fiscal de Campo.","D) Gestão de Marketing Institucional.","E) Psicologia Organizacional Comportamental."], resposta_correta:1, explicacao:"Justificativa: OSM é a área que lida com processos, manuais, formulários e fluxogramas. Questão de nível médio onde a banca mistura áreas da administração para testar a base teórica.", status:0, historico:0 },
{ id:389, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Sobre o Manual de Formulários, assinale a alternativa que apresenta sua principal utilidade prática:", imagem:null, alternativas:["A) Explicar a hierarquia de cargos e salários do conselho.","B) Apresentar o histórico detalhado da criação do COFECI.","C) Padronizar a coleta de dados e o fluxo de documentos, evitando redundâncias.","D) Substituir os manuais de procedimentos técnicos de fiscalização.","E) Registrar exclusivamente as multas aplicadas aos corretores inadimplentes."], resposta_correta:2, explicacao:"Justificativa: O manual de formulários visa uniformizar os impressos e telas de sistema. A Quadrix insere 'exclusivamente' (E) ou funções de outros manuais (A) para invalidar os itens.", status:0, historico:0 },
{ id:390, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Procedimentos Administrativos", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Na representação gráfica de procedimentos, o símbolo que normalmente indica o início ou o fim de um fluxo de trabalho em um fluxograma é o:", imagem:null, alternativas:["A) Retângulo (Ação/Processo).","B) Losango (Decisão).","C) Elipse ou Retângulo arredondado (Terminador).","D) Círculo pequeno (Conector).","E) Seta de fluxo (Sentido)."], resposta_correta:2, explicacao:"Justificativa: Elipses ou formas arredondadas iniciam e encerram o fluxo. A banca adora cobrar a simbologia básica de fluxogramas (ISO) em provas de nível administrativo.", status:0, historico:0 },
{ id:391, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um 'Manual de Políticas' em uma autarquia profissional como o CRECI serve para:", imagem:null, alternativas:["A) Listar os telefones e e-mails de todos os funcionários.","B) Estabelecer as diretrizes e os princípios que orientam o julgamento e a tomada de decisão.","C) Descrever minuciosamente o rito de protocolização de certidões.","D) Apresentar o balanço financeiro do exercício anterior aos conselheiros.","E) Servir como um dicionário de termos jurídicos usados nos editais."], resposta_correta:1, explicacao:"Justificativa: Políticas são diretrizes/orientações para decisões. Não confundir com procedimentos (detalhamento da ação). É uma inversão sutil muito explorada em provas recentes.", status:0, historico:0 },
{ id:392, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Procedimentos Administrativos", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise as assertivas sobre os manuais administrativos:\nI. O manual deve ser escrito em linguagem rebuscada e técnica para demonstrar autoridade.\nII. A distribuição do manual deve ser restrita apenas aos diretores da autarquia.\nIII. Os manuais ajudam a reduzir a 'memória institucional' baseada apenas na tradição oral.\nIV. Um bom manual deve prever todas as situações possíveis, sem exceções.\nEstão corretas apenas as assertivas:", imagem:null, alternativas:["A) I e III.","B) II e IV.","C) III, apenas.","D) I, II e III.","E) Todas as assertivas."], resposta_correta:2, explicacao:"Justificativa: I-F (Linguagem deve ser clara); II-F (Deve ser acessível a quem executa); III-V (Manual formaliza o conhecimento); IV-F (É impossível prever todas as situações). A Quadrix usa o 'apenas' e o 'todas' para derrubar o candidato.", status:0, historico:0 },
{ id:393, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A etapa da elaboração de um manual administrativo que consiste em verificar se o conteúdo reflete a realidade das tarefas executadas no dia a dia é a:", imagem:null, alternativas:["A) Redação final e impressão.","B) Distribuição em massa.","C) Validação ou Teste de campo.","D) Aprovação pela Diretoria Plenária.","E) Arquivamento histórico."], resposta_correta:2, explicacao:"Justificativa: Antes de oficializar, é preciso validar se o que está escrito funciona na prática. A banca tenta induzir que a 'Aprovação da Diretoria' (D) é a fase de verificação técnica, o que é erro.", status:0, historico:0 },
{ id:394, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Procedimentos Administrativos", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O procedimento de simplificação administrativa que visa eliminar passos desnecessários em um processo de fiscalização do CRECI, visando a eficiência, é tecnicamente conhecido como:", imagem:null, alternativas:["A) Burocratização preventiva.","B) Racionalização do trabalho.","C) Segregação de funções estáticas.","D) Centralização de despacho único.","E) Auditoria de conformidade punitiva."], resposta_correta:1, explicacao:"Justificativa: Racionalização é a busca pelo melhor método com menor esforço/custo. A banca usa o termo 'burocratização' de forma positiva em distratores para confundir.", status:0, historico:0 },
{ id:395, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um manual de procedimentos administrativos é considerado 'atualizado' quando:", imagem:null, alternativas:["A) Foi escrito há menos de dez anos por uma consultoria externa.","B) Possui todas as páginas carimbadas e assinadas pelo presidente.","C) Reflete as normas vigentes e as práticas operacionais atuais da organização.","D) É guardado em local seguro e de acesso restrito no setor de RH.","E) Contém fotografias de todos os setores e funcionários da autarquia."], resposta_correta:2, explicacao:"Justificativa: Atualização é sintonia entre norma e prática. A Quadrix tenta ligar atualização a 'aparência' (carimbos/assinaturas) ou 'segurança' (acesso restrito) para desviar o foco.", status:0, historico:0 },
{ id:396, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Procedimentos Administrativos", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Assinale a alternativa que apresenta um elemento essencial que deve constar em um Manual de Procedimentos do CRECI-BA:", imagem:null, alternativas:["A) A biografia completa de todos os conselheiros fundadores.","B) O valor detalhado do salário de cada servidor administrativo.","C) A descrição sequencial das tarefas, os responsáveis e os prazos de cada etapa.","D) O plano de marketing para as redes sociais pessoais do presidente.","E) A lista de todos os processos judiciais contra a autarquia em andamento."], resposta_correta:2, explicacao:"Justificativa: Quem faz, o que faz e em quanto tempo faz são os pilares do procedimento. A banca insere informações irrelevantes ou de cunho privado/financeiro nos distratores.", status:0, historico:0 },
{ id:397, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Considere as assertivas abaixo sobre os Manuais Administrativos:\nI. Facilitam a integração de novos servidores concursados.\nII. Servem como base para auditorias e controles internos.\nIII. Substituem integralmente a necessidade de supervisão direta.\nAssinale a alternativa correta:", imagem:null, alternativas:["A) Apenas I e II estão corretas.","B) Apenas II e III estão corretas.","C) Apenas I e III estão corretas.","D) Todas estão corretas.","E) Nenhuma está correta."], resposta_correta:0, explicacao:"Justificativa: A III está incorreta devido ao 'integralmente'. O manual auxilia, mas não elimina a figura do gestor/supervisor. Pegadinha de generalização clássica.", status:0, historico:0 },
{ id:398, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Procedimentos Administrativos", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No fluxo de um processo administrativo, o ato de encaminhar os autos de um setor para outro, registrando a movimentação no sistema, é chamado de:", imagem:null, alternativas:["A) Julgamento de mérito.","B) Tramitação (ou Movimentação).","C) Diligência externa.","D) Avocação de competência.","E) Sobrestamento temporário."], resposta_correta:1, explicacao:"Justificativa: Tramitar é fazer o processo andar fisicamente ou digitalmente entre as unidades. A Quadrix usa termos jurídicos como 'avocação' ou 'sobrestamento' para assustar o candidato de nível médio.", status:0, historico:0 },
{ id:399, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Sobre a flexibilidade dos manuais administrativos, é correto afirmar que:", imagem:null, alternativas:["A) Devem ser imutáveis para garantir a segurança jurídica absoluta da autarquia.","B) Devem ser revisados apenas se houver mudança de presidência no conselho.","C) Precisam permitir revisões periódicas para incorporar melhorias e novas legislações.","D) A revisão deve ser evitada para não confundir os servidores mais antigos.","E) Apenas o setor financeiro tem autoridade para sugerir mudanças em qualquer manual."], resposta_correta:2, explicacao:"Justificativa: Manuais são dinâmicos. A banca tenta vender a ideia de que o manual é uma 'lei pétrea' (A) ou que depende de 'política' (B) para ser alterado.", status:0, historico:0 },
{ id:400, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Procedimentos Administrativos", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Na elaboração de um fluxograma de atendimento no CRECI, um 'Losango' é utilizado para indicar:", imagem:null, alternativas:["A) O arquivamento definitivo de um documento físico.","B) Uma operação de cálculo matemático complexo.","C) Um ponto de decisão onde o fluxo pode seguir caminhos diferentes (Sim/Não).","D) O início obrigatório de todo e qualquer processo administrativo.","E) A assinatura do presidente em um despacho de certidão."], resposta_correta:2, explicacao:"Justificativa: Losango = Decisão/Questão. É o símbolo que cria ramificações no processo. Cobrança recorrente da Quadrix sobre simbologia de OSM.", status:0, historico:0 },
{ id:401, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um dos riscos de uma autarquia NÃO possuir manuais administrativos formais é:", imagem:null, alternativas:["A) O excesso de transparência nos gastos públicos.","B) A alta rotatividade de servidores, que passam a saber demais sobre o órgão.","C) A perda de conhecimento quando servidores experientes se aposentam (descontinuidade).","D) A redução da burocaacia, o que prejudica a fiscalização dos corretores.","E) O aumento imediato da arrecadação com anuidades atrasadas."], resposta_correta:2, explicacao:"Justificativa: Sem manual, o conhecimento fica na cabeça das pessoas (informalidade). Quando elas saem, o órgão 'esquece' como fazer. A Quadrix adora o tema 'continuidade administrativa'.", status:0, historico:0 },
{ id:402, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Procedimentos Administrativos", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise as frases abaixo quanto a verdadeiro (V) ou falso (F) sobre a padronização de processos:\n( ) Reduz a variabilidade na prestação do serviço ao cidadão.\n( ) Impede totalmente a criatividade do servidor em situações imprevistas.\n( ) Facilita a mensuração do desempenho e da produtividade do setor.\nAssinale a alternativa que apresenta a sequência correta:", imagem:null, alternativas:["A) V, V, V","B) V, F, V","C) F, V, F","D) V, V, F","E) F, F, V"], resposta_correta:1, explicacao:"Justificativa: V-F-V. A padronização não 'impede totalmente' a criatividade, ela apenas define o rito padrão. Novamente, a pegadinha está na palavra absoluta 'impede totalmente'.", status:0, historico:0 },
{ id:403, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Fundamentos da Administração", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O 'Manual de Integração' (ou de Boas-Vindas) tem como função primordial:", imagem:null, alternativas:["A) Descrever o rito de punição para infrações éticas graves.","B) Apresentar a missão, visão e valores da autarquia para o novo servidor.","C) Listar todos os fornecedores de material de escritório do conselho.","D) Definir as taxas de corretagem que podem ser cobradas no estado.","E) Substituir o contrato de trabalho formal do assistente administrativo."], resposta_correta:1, explicacao:"Justificativa: Integração foca na cultura e informações básicas para quem chega. A banca mistura com temas de fiscalização (A/D) ou operacionais (C) para confundir.", status:0, historico:0 },
{ id:404, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No contexto do CRECI-BA, a área de Organização e Métodos (O&M) propôs a 'Racionalização' de um processo de fiscalização. Esse conceito refere-se fundamentalmente a:", imagem:null, alternativas:["A) Adicionar novas etapas de verificação para garantir a segurança absoluta e irreversível do rito.","B) Substituir integralmente o trabalho humano por sistemas automatizados, eliminando a discricionariedade.","C) Otimizar o uso de recursos e simplificar o método de trabalho, visando a maior eficiência e menor custo.","D) Centralizar todas as decisões operacionais exclusivamente nas mãos da alta gestão da autarquia.","E) Documentar o processo atual de forma minuciosa, sem alterar nenhuma de suas fases originais."], resposta_correta:2, explicacao:"Justificativa: Racionalizar significa tornar mais eficiente, simplificando e otimizando o processo. Dica do Especialista: A Quadrix adora usar palavras absolutas como 'segurança absoluta', 'substituir integralmente' ou 'exclusivamente' (opções A, B e D) para criar distratores plausíveis, porém logicamente falsos em O&M.", status:0, historico:0 },
{ id:405, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O fluxograma é uma ferramenta essencial em O&M para mapear a tramitação de processos administrativos. O símbolo geométrico do 'Losango' é utilizado universalmente nesses diagramas para indicar:", imagem:null, alternativas:["A) O início ou término irreversível de um processo do conselho.","B) Um ponto de decisão ou questionamento que divide o fluxo em caminhos alternativos.","C) O arquivamento definitivo de um documento físico no almoxarifado.","D) A execução de uma operação manual rotineira pelo assistente administrativo.","E) A emissão obrigatória de um relatório impresso para a diretoria."], resposta_correta:1, explicacao:"Justificativa: Na simbologia padrão, o losango representa sempre uma decisão (geralmente uma pergunta de 'Sim' ou 'Não'). Dica do Especialista: A Quadrix cobra rotineiramente a diferença entre Retângulo (Ação/Operação), Losango (Decisão) e Elipse (Início/Fim).", status:0, historico:0 },
{ id:406, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise as assertivas sobre o uso de Formulários na Administração Pública: I. Um bom formulário deve coletar o máximo de informações possíveis, mesmo aquelas que não têm utilidade imediata. II. O formulário visa padronizar a coleta de dados e agilizar o fluxo de informações. III. O excesso de formulários em um setor é sempre indicador de alta eficiência administrativa. Está(ão) correta(s):", imagem:null, alternativas:["A) Apenas I.","B) Apenas II.","C) Apenas I e III.","D) Apenas II e III.","E) I, II e III."], resposta_correta:1, explicacao:"Justificativa: A assertiva I é falsa porque formulários devem coletar apenas dados estritamente necessários (evitar redundância). A III é falsa porque excesso de formulários indica burocracia disfuncional (papeleira). Dica do Especialista: A Quadrix usa a intuição do candidato contra ele mesmo, sugerindo que 'coletar o máximo de informações' é algo positivo, quando em O&M significa desperdício de tempo.", status:0, historico:0 },
{ id:407, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Acerca dos Manuais Administrativos, julgue como Verdadeiro (V) ou Falso (F): ( ) Consolidam as normas e procedimentos, servindo como memória institucional. ( ) Impedem totalmente a flexibilidade e a criatividade do servidor frente a imprevistos. ( ) São ferramentas estáticas que dispensam revisões periódicas. Assinale a sequência correta:", imagem:null, alternativas:["A) V, V, F","B) V, F, V","C) F, V, F","D) V, F, F","E) F, F, V"], resposta_correta:3, explicacao:"Justificativa: O manual orienta, mas não anula a criatividade frente a imprevistos não mapeados (F). Além disso, eles são dinâmicos e exigem atualização constante (F). Dica do Especialista: Fuja de alternativas que dizem que os manuais 'impedem totalmente' ou são 'estáticos/imutáveis'. A banca Quadrix ama usar essa restrição limitante.", status:0, historico:0 },
{ id:408, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Quando o CRECI-BA organiza sua estrutura administrativa dividindo-a em 'Departamento de Fiscalização', 'Departamento Financeiro' e 'Departamento de TI', ele está adotando o critério de departamentalização:", imagem:null, alternativas:["A) Geográfica (ou Territorial).","B) Por Clientes.","C) Funcional.","D) Matricial exclusiva.","E) Por Projetos."], resposta_correta:2, explicacao:"Justificativa: A divisão por especialidade técnica ou funções principais (TI, Financeiro, Fiscalização) caracteriza a departamentalização Funcional. Dica do Especialista: Departamentalização por Funções é a mais comum na área pública; a Quadrix sempre tenta confundi-la com a Matricial (que mistura função com projetos).", status:0, historico:0 },
{ id:409, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Considere o processo de Análise Administrativa para melhoria contínua. Assinale a alternativa que indica CORRETAMENTE a primeira etapa fundamental antes de sugerir qualquer mudança no fluxograma de atendimento do CRECI:", imagem:null, alternativas:["A) Implementação imediata de um novo software de gestão.","B) Treinamento dos servidores nas novas metodologias desenhadas.","C) Levantamento de dados e análise da situação atual (diagnóstico).","D) Demissão de colaboradores que apresentam resistência à mudança.","E) Padronização coercitiva das rotinas sem consulta aos envolvidos."], resposta_correta:2, explicacao:"Justificativa: Em O&M, não se propõe mudança sem antes fazer o levantamento (mapeamento) da situação atual (As-Is). Dica do Especialista: A banca sempre tenta colocar a 'Ação/Implantação' como primeira etapa para testar a impulsividade do candidato. Planejamento/Diagnóstico vem sempre primeiro.", status:0, historico:0 },
{ id:410, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Para mensurar o sucesso de um novo método de arquivamento, o analista observou que a equipe reduziu o uso de papel em 30% e cortou o tempo da tarefa pela metade, atingindo o resultado esperado. O conceito focado na 'economia de recursos' durante a execução é a:", imagem:null, alternativas:["A) Eficácia.","B) Efetividade.","C) Eficiência.","D) Excelência Absoluta.","E) Economicidade de Escopo."], resposta_correta:2, explicacao:"Justificativa: Eficiência é a relação custo/benefício, focando no uso racional dos recursos (como tempo e papel). Eficácia foca apenas em atingir a meta. Dica do Especialista: O trio Eficiência (meios/recursos), Eficácia (fins/metas) e Efetividade (impacto social) cai em 90% das provas da Quadrix.", status:0, historico:0 },
{ id:411, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Em um projeto de reforma da sede do conselho, utilizou-se o Gráfico de Gantt. Sobre essa ferramenta clássica de O&M, é correto afirmar que:", imagem:null, alternativas:["A) É um gráfico complexo utilizado exclusivamente para cálculos financeiros de retorno sobre investimento.","B) Relaciona as atividades de um projeto com o tempo necessário para sua execução, em um formato de barras horizontais.","C) Serve para mapear o fluxo lógico das decisões, substituindo o fluxograma tradicional.","D) Indica as causas raízes de um problema de atendimento, assemelhando-se ao diagrama de Ishikawa.","E) Demonstra a relação hierárquica de autoridade entre a diretoria e as delegacias regionais."], resposta_correta:1, explicacao:"Justificativa: O Gráfico de Gantt é essencialmente um cronograma visual de barras que liga atividades ao tempo. Dica do Especialista: A banca gosta de misturar ferramentas de gestão. O erro da E descreve o Organograma, e o erro da D descreve a Espinha de Peixe.", status:0, historico:0 },
{ id:412, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise as assertivas sobre o Arranjo Físico (Layout) em repartições públicas: I. Um layout inadequado pode causar fluxos de trabalho cruzados e retrabalho. II. O layout panorâmico (escritório aberto) facilita a comunicação, mas pode gerar perda de privacidade e ruído excessivo. III. A reorganização do layout deve ser feita exclusivamente por critérios estéticos para agradar ao público. Está(ão) correta(s):", imagem:null, alternativas:["A) Apenas a I.","B) Apenas a II.","C) Apenas I e II.","D) Apenas II e III.","E) I, II e III."], resposta_correta:2, explicacao:"Justificativa: A assertiva III está incorreta porque o layout deve priorizar a funcionalidade, o fluxo do trabalho e a ergonomia, e não 'exclusivamente' a estética. Dica do Especialista: 'Exclusivamente' é o gatilho matador da Quadrix. O item sobre escritórios abertos (panorâmicos) cobrando suas desvantagens (ruído) é clássico.", status:0, historico:0 },
{ id:413, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A delegação de autoridade é um tema central em O&M. Quando o presidente do conselho delega uma tarefa a um assistente, é correto afirmar segundo a teoria organizacional clássica que:", imagem:null, alternativas:["A) A responsabilidade final pela tarefa é transferida integralmente ao assistente, eximindo o presidente.","B) A delegação deve ser acompanhada da transferência da autoridade necessária para realizar a tarefa.","C) É vedada a delegação de tarefas operacionais, sendo permitida apenas a delegação de planejamento estratégico.","D) A delegação anula imediatamente a hierarquia formal do setor de trabalho.","E) O assistente ganha o poder de delegar indefinidamente a mesma tarefa para outras autarquias."], resposta_correta:1, explicacao:"Justificativa: Delega-se a autoridade (poder para agir), mas não se transfere a responsabilidade final (o gestor continua corresponsável). Dica do Especialista: O pilar das questões de delegação é a máxima: 'Delega-se autoridade, mas compartilha-se a responsabilidade'. A opção A é o erro mais clássico cobrado.", status:0, historico:0 },
{ id:414, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Gestão de Materiais e Almoxarifado", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Na gestão do almoxarifado do CRECI, a Curva ABC é aplicada para priorizar o controle de materiais. Segundo essa metodologia, os itens classificados como classe 'A' caracterizam-se por:", imagem:null, alternativas:["A) Compor a grande maioria da quantidade física do estoque, mas com impacto financeiro irrisório.","B) Exigir controles menos rigorosos, visto que são materiais de escritório de fácil reposição, como clipes de papel.","C) Representar um pequeno percentual da quantidade total de itens, mas concentrar a maior parte do valor financeiro do estoque.","D) Possuírem validade extremamente curta, demandando consumo imediato sob pena de perda.","E) Serem materiais obsoletos que devem ser descartados no próximo inventário."], resposta_correta:2, explicacao:"Justificativa: A Curva ABC é baseada no princípio de Pareto. Classe A: Pouca quantidade (cerca de 20%) e alto valor (cerca de 80%). Dica do Especialista: A banca costuma inverter o conceito, dizendo que a Classe A possui a 'maior quantidade' de itens (erro da alternativa A).", status:0, historico:0 },
{ id:415, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Gestão de Materiais e Almoxarifado", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise: I. O Estoque de Segurança visa proteger o conselho contra variações imprevisíveis no consumo ou atrasos do fornecedor. II. O Ponto de Pedido é o nível máximo que o almoxarifado pode comportar fisicamente. III. O Lote Econômico de Compras (LEC) busca equilibrar os custos de armazenagem e os custos de pedir. Está(ão) correta(s):", imagem:null, alternativas:["A) Apenas I.","B) Apenas II.","C) Apenas I e III.","D) Apenas II e III.","E) I, II e III."], resposta_correta:2, explicacao:"Justificativa: A assertiva II é falsa porque o Ponto de Pedido é o nível (gatilho) no qual um novo pedido de compra deve ser feito para não haver ruptura, e não a capacidade máxima física. Dica do Especialista: Memorize a diferença: Ponto de Pedido (momento de comprar) x Estoque Máximo (limite físico/financeiro).", status:0, historico:0 },
{ id:416, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Gestão de Materiais e Almoxarifado", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Dentre os métodos de avaliação contábil do estoque, aquele que apropria o custo da mercadoria vendida (ou consumida) pelos preços mais antigos e valoriza o estoque final pelos preços mais recentes de aquisição é o:", imagem:null, alternativas:["A) Custo Médio Ponderado.","B) UEPS (Último a Entrar, Primeiro a Sair).","C) PEPS (Primeiro a Entrar, Primeiro a Sair).","D) Just in Time (JIT).","E) Avaliação a Valor Presente Constante."], resposta_correta:2, explicacao:"Justificativa: No PEPS/FIFO, o que sai (consumo) é o mais velho (custo antigo), sobrando no almoxarifado o que entrou por último (custo recente). Dica do Especialista: A Quadrix elabora o texto de forma 'truncada' para forçar o aluno a pensar na composição do estoque final. Leitura atenta é crucial.", status:0, historico:0 },
{ id:417, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Gestão de Materiais e Almoxarifado", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Na classificação de materiais de consumo, um suprimento de impressora cujas características físico-químicas não se alteram substancialmente pelo tempo de guarda, mas que se esgota com o uso, deve ser considerado um material:", imagem:null, alternativas:["A) Permanente.","B) De Consumo.","C) Imaterial.","D) Imobilizado fixo.","E) Obsoleto por natureza."], resposta_correta:1, explicacao:"Justificativa: Materiais que perdem identidade física ou têm durabilidade inferior a 2 anos (como toners) são classificados como 'Material de Consumo' pela Lei 4.320/64. Dica do Especialista: A banca tenta induzir o erro misturando as definições contábeis de material Permanente (móveis, computadores) com de Consumo.", status:0, historico:0 },
{ id:418, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Gestão de Materiais e Almoxarifado", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Julgue V ou F sobre os tipos de Inventário Físico: ( ) O inventário anual, geralmente realizado ao fim do exercício, costuma exigir a paralisação do almoxarifado. ( ) O inventário rotativo ocorre de forma contínua durante o ano, dispensando paralisações totais. ( ) O único objetivo do inventário é punir servidores por desvios de material. A sequência correta é:", imagem:null, alternativas:["A) V, V, F","B) V, F, V","C) F, V, F","D) V, V, V","E) F, F, V"], resposta_correta:0, explicacao:"Justificativa: O objetivo do inventário é aferir a exatidão dos registros contábeis em relação ao físico, controlar validades e perdas, não apenas 'punir'. Dica do Especialista: A restrição 'único objetivo' (F) quebra a questão. Quadrix pune quem não percebe absolutismos na Administração de Materiais.", status:0, historico:0 },
{ id:419, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Gestão de Materiais e Almoxarifado", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A gestão de suprimentos lida constantemente com o 'Custo de Manutenção do Estoque' (ou Custo de Armazenagem). Assinale a alternativa que apresenta um componente direto desse custo:", imagem:null, alternativas:["A) Gastos com ligações telefônicas para solicitar orçamentos aos fornecedores.","B) Custo da emissão da nota de empenho no setor financeiro.","C) Seguros contra incêndio, aluguel do espaço físico e obsolescência.","D) Salário da equipe de licitação responsável por elaborar o edital de compras.","E) Multas contratuais aplicadas a fornecedores por atrasos nas entregas."], resposta_correta:2, explicacao:"Justificativa: Seguros, espaço (aluguel), perdas e capital empatado formam o Custo de Armazenagem. As opções A, B e D são 'Custos de Pedido' (ou aquisição). Dica do Especialista: Diferenciar custo de pedido (burocracia da compra) de custo de posse (guardar o material) é uma competência essencial exigida pela banca.", status:0, historico:0 },
{ id:420, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Gestão de Materiais e Almoxarifado", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Sobre os atributos de um bom sistema de Classificação de Materiais, assinale a alternativa que descreve corretamente o princípio da 'Abrangência':", imagem:null, alternativas:["A) O sistema deve prever apenas os itens adquiridos no exercício fiscal atual.","B) O sistema deve permitir a inclusão de novos materiais futuramente sem bagunçar a lógica original.","C) O sistema deve ser capaz de contemplar toda a variedade de itens existentes na autarquia.","D) O sistema deve possuir uma linguagem simples para facilitar a leitura por estagiários.","E) O sistema deve ser idêntico ao utilizado pela Receita Federal, independentemente da necessidade local."], resposta_correta:2, explicacao:"Justificativa: Abrangência é tratar do universo total de itens da organização. A opção B descreve a 'Flexibilidade' e a D descreve a 'Praticidade'. Dica do Especialista: A banca Quadrix faz o clássico 'jogo de cadeiras' com os conceitos de Flexibilidade, Abrangência e Praticidade para testar decoreba qualificada.", status:0, historico:0 },
{ id:421, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Gestão de Materiais e Almoxarifado", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A filosofia 'Just in Time' (JIT) quando aplicada à aquisição de suprimentos busca:", imagem:null, alternativas:["A) Maximizar o estoque de segurança para garantir que a autarquia nunca pare de funcionar.","B) Receber os materiais exatamente no momento de sua utilização, tendendo o estoque a zero.","C) Comprar materiais em lotes gigantescos para ganhar poder de barganha com o fornecedor.","D) Descentralizar todas as compras, permitindo que cada assistente compre seu material na papelaria da esquina.","E) Exigir que o fornecedor pague uma taxa de permanência se entregar o material antes do prazo."], resposta_correta:1, explicacao:"Justificativa: O núcleo do JIT (desenvolvido na Toyota) é produzir/fornecer no momento exato da demanda, eliminando estoques ociosos. Dica do Especialista: Alternativas que sugerem 'aumentar' ou 'maximizar' estoques (A e C) são flagrantemente antagônicas à filosofia Just in Time.", status:0, historico:0 },
{ id:422, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Gestão de Materiais e Almoxarifado", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No fluxo de administração de materiais, a fase de 'Recebimento' é crítica. Assinale a afirmação correta sobre os procedimentos dessa etapa:", imagem:null, alternativas:["A) O almoxarife deve atestar a nota fiscal imediatamente pelo valor integral, postergando a contagem física para o mês seguinte.","B) A inspeção qualitativa (qualidade e especificações técnicas) é dispensada se o fornecedor tiver ganhado a licitação.","C) Envolve a conferência quantitativa e qualitativa do material entregue, confrontando-o com a Nota de Empenho e a Nota Fiscal.","D) Os materiais rejeitados por defeito são incorporados ao patrimônio e, posteriormente, leiloados como sucata.","E) É uma função de competência exclusiva do Presidente do Conselho, sendo indelegável ao setor de logística."], resposta_correta:2, explicacao:"Justificativa: O recebimento sério exige conferência cruzada: físico x documento de compra (empenho) x documento de entrega (NF), avaliando quantidade e qualidade. Dica do Especialista: A banca constrói cenários onde o servidor age de forma irresponsável (A, B e D) para avaliar seu senso de legalidade no trato da coisa pública.", status:0, historico:0 },
{ id:423, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Gestão de Materiais e Almoxarifado", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A Codificação de materiais transforma a descrição de um item em um código representativo. O sistema de codificação mais utilizado na Administração Pública moderna, por permitir subdivisões hierárquicas em classes e subclasses através de números, é o:", imagem:null, alternativas:["A) Alfabético puro.","B) Alfanumérico misto em blocos livres.","C) Decimal (ou Numérico).","D) Hexadecimal criptografado.","E) Código de barras unificado aleatório."], resposta_correta:2, explicacao:"Justificativa: O sistema numérico decimal, como o Federal Supply Classification (FSC), agrupa itens por grandes grupos, classes e itens específicos através de uma cadeia numérica lógica (ex: 30.15.22). Dica do Especialista: Embora sistemas de código de barras ou RFID sejam tecnologias atuais, a base metodológica e estrutural da organização na gestão pública ainda é o sistema numérico decimal.", status:0, historico:0 },
{ id:424, categoria:"Conhecimentos Básicos", materia:"Língua Portuguesa", assunto:"Interpretação e Produção de Textos", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Ao analisar um gráfico de desempenho setorial em um relatório anual, o leitor observa que, embora a linha de produtividade seja ascendente, as barras de custo operacional mantêm-se estagnadas no topo. Com base nessa relação multimodal, infere-se que:", imagem:null, alternativas:["A eficiência operacional diminuiu no período.","O aumento da produtividade não demandou incremento proporcional de custos.","A estagnação dos custos indica necessariamente prejuízo financeiro.","O gráfico é redundante, pois linhas e barras expressam a mesma grandeza."], resposta_correta:1, explicacao: "A leitura conjunta (multimodal) mostra que a produtividade subiu sem que os custos acompanhassem a subida, indicando otimização.", status:0, historico:0 },
{ id:425, categoria:"Conhecimentos Básicos", materia:"Língua Portuguesa", assunto:"Texto e Discurso", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Em um e-mail institucional, a frase 'Seguem as minutas para apreciação e posterior submissão ao conselho' caracteriza-se primordialmente como um texto de natureza:", imagem:null, alternativas:["Narrativa, pois relata uma sequência de fatos passados.","Descritiva, focada em pormenorizar os objetos enviados.","Informativo-expositiva, visando a comunicação técnica e direta.","Argumentativa, pois tenta convencer o receptor sobre a validade das minutas."], resposta_correta:2, explicacao: "E-mails corporativos de envio de documentos possuem função predominantemente expositiva e informativa.", status:0, historico:0 },
{ id:426, categoria:"Conhecimentos Básicos", materia:"Língua Portuguesa", assunto:"Estilística e Funções da Linguagem", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"No trecho 'O setor de fiscalização é o coração da autarquia, pulsando em conformidade com as diretrizes do COFECI', verifica-se a presença da seguinte figura de linguagem:", imagem:null, alternativas:["Metonímia, pela substituição da parte pelo todo.","Hipérbole, ao exagerar a importância do setor.","Metáfora, ao estabelecer uma analogia implícita entre o setor e um órgão vital.","Pleonasmo, pela repetição desnecessária de ideias."], resposta_correta:2, explicacao: "A comparação implícita entre o setor e o coração configura uma metáfora.", status:0, historico:0 },
{ id:427, categoria:"Conhecimentos Básicos", materia:"Língua Portuguesa", assunto:"Semântica", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Assinale a alternativa em que o termo sublinhado foi empregado em sentido estritamente denotativo:", imagem:null, alternativas:["O corretor 'atropelou' os prazos regimentais por excesso de confiança.","A nova normativa 'acendeu' um debate acalorado entre os conselheiros.","O documento foi 'engavetado' pela presidência durante a última sessão.","A 'assinatura' do convênio ocorreu na última segunda-feira, às dez horas."], resposta_correta:3, explicacao: "Assinatura aqui é o ato físico/jurídico real (sentido literal), enquanto as outras opções usam termos figurados.", status:0, historico:0 },
{ id:428, categoria:"Conhecimentos Básicos", materia:"Língua Portuguesa", assunto:"Texto e Discurso", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix", enunciado:"Considere as afirmações: I. A coesão textual depende exclusivamente da pontuação. II. A coerência refere-se à manutenção lógica das ideias. III. Um texto multimodal dispensa o uso de linguagem verbal. Está(ão) correta(s):", imagem:null, alternativas:["Apenas a II.","Apenas a I e a II.","Apenas a II e a III.","Todas as afirmações."], resposta_correta:0, explicacao: "Apenas a II está correta. A coesão usa conectivos e a multimodalidade geralmente combina verbal e não-verbal.", status:0, historico:0 },
{ id:429, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Visando maior agilidade, o CRECI-BA decidiu alocar temporariamente especialistas de diversos setores (TI, Jurídico e Fiscalização) para um grande projeto de recadastramento estadual. Nessa configuração, o servidor passa a responder tanto ao seu chefe funcional quanto ao gerente do projeto. Essa estrutura organizacional é denominada:", imagem:null, alternativas:["Estrutura Linear.","Estrutura Divisional.","Estrutura Matricial.","Estrutura em Rede.","Estrutura Linha-Staff."], resposta_correta:2, explicacao: "A dupla subordinação (chefe de departamento + gerente de projeto) é a característica central da Estrutura Matricial. A Quadrix adora usar o termo 'temporariamente' ou 'projeto específico' para induzir o candidato a achar que é uma estrutura divisional, mas a manutenção da resposta ao chefe funcional crava a opção matricial.", status:0, historico:0 },
{ id:430, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise as assertivas sobre estruturas organizacionais: I. A estrutura funcional baseia-se no princípio da especialização das funções, permitindo que um subordinado receba orientações de diversos chefes especializados. II. O órgão de staff possui autoridade de linha, garantindo o direito de dar ordens impositivas aos departamentos operacionais. III. A estrutura linear é caracterizada pela unidade de comando e formato piramidal. Está(ão) correta(s):", imagem:null, alternativas:["Apenas a I.","Apenas a II.","Apenas I e III.","Apenas II e III.","I, II e III."], resposta_correta:2, explicacao: "A assertiva II é falsa porque órgãos de staff têm autoridade de aconselhamento (consultoria), e NÃO autoridade de linha (comando). Dica do Especialista: A banca sempre tenta 'dar poderes de chefia' ao staff para testar o candidato. A I e a III trazem conceitos clássicos e corretos de Fayol.", status:0, historico:0 },
{ id:431, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Julgue as frases com (V) para Verdadeiro e (F) para Falso: ( ) A departamentalização geográfica é ideal para órgãos públicos que atuam em extensas áreas territoriais, permitindo adaptação às necessidades locais. ( ) A departamentalização por clientes no conselho focaria em separar o atendimento entre 'Pessoa Física' e 'Pessoa Jurídica'. ( ) A departamentalização funcional prejudica a especialização do trabalho por focar excessivamente no produto final. A sequência correta é:", imagem:null, alternativas:["V, V, F.","V, F, V.","F, V, F.","V, V, V.","F, F, V."], resposta_correta:0, explicacao: "A última é falsa porque a departamentalização funcional é justamente a que MAIS favorece a especialização técnica (agrupando pessoas da mesma área, como TI com TI). A Quadrix usa o verbo 'prejudica' para inverter o benefício principal do modelo funcional.", status:0, historico:0 },
{ id:432, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A 'Amplitude de Controle' (ou administrativa) refere-se ao número de subordinados que um gestor consegue supervisionar com eficiência. É correto afirmar que, no âmbito da autarquia:", imagem:null, alternativas:["Quanto maior a amplitude de controle, mais verticalizada e alta será a estrutura organizacional.","Trabalhos altamente padronizados e rotineiros permitem uma amplitude de controle mais larga.","A descentralização de decisões exige, obrigatoriamente, uma amplitude de controle estreita em todos os níveis.","Uma amplitude de controle estreita reduz os custos administrativos por diminuir o número de chefias.","A amplitude ideal de controle no setor público é universal e independe do nível de treinamento da equipe."], resposta_correta:1, explicacao: "Trabalhos rotineiros e subordinados bem treinados não exigem supervisão constante, permitindo que um chefe gerencie muitas pessoas (amplitude larga). A Quadrix inverte lógicas matemáticas: na opção A, amplitude larga gera estrutura 'achatada' (horizontal), e não vertical.", status:0, historico:0 },
{ id:433, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O CRECI-BA implementou um programa de descentralização, transferindo a autoridade para a resolução de certidões para os delegados regionais. Uma das desvantagens inerentes a esse processo de descentralização é:", imagem:null, alternativas:["O distanciamento das decisões em relação ao local onde os fatos ocorrem.","O aumento do tempo de espera do usuário devido à burocracia regional.","A dificuldade na padronização dos processos e uniformidade das decisões.","A desmotivação dos servidores do escalão inferior por falta de autonomia.","O acúmulo excessivo de tarefas exclusivamente na cúpula diretiva do conselho."], resposta_correta:2, explicacao: "A descentralização gera agilidade, motiva a base e aproxima a decisão do fato (eliminando A, B, D e E como desvantagens). O grande risco (desvantagem) cobrado pelas bancas é a perda da padronização, já que várias pessoas passam a decidir autonomamente.", status:0, historico:0 },
{ id:434, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A estrutura organizacional em rede (network) tem ganhado espaço na administração moderna. Assinale a característica que define este modelo:", imagem:null, alternativas:["Centralização irrestrita de todos os recursos tangíveis no núcleo da organização.","Contratação externa (terceirização) de grande parte de suas funções não essenciais.","Formato hierárquico rígido de comando e controle, assemelhando-se à estrutura linear.","Impossibilidade de adaptação rápida a mudanças no ambiente macroeconômico.","Foco exclusivo na produção industrial, não se aplicando a organizações de serviços."], resposta_correta:1, explicacao: "A estrutura em rede baseia-se num núcleo central pequeno que terceiriza (conecta via rede) as atividades de suporte, focando apenas no seu 'core business'. A Quadrix costuma tentar associar 'rede' à burocracia rígida para fisgar os desatentos.", status:0, historico:0 },
{ id:435, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Embora o conselho possua um organograma oficial (organização formal), os servidores frequentemente resolvem problemas complexos através de suas redes de amizades internas. Sobre a organização informal, é correto afirmar:", imagem:null, alternativas:["Ela deve ser sumariamente eliminada pelos gestores por atentar contra o princípio da legalidade.","Ela é documentada nos manuais de procedimentos aprovados pela presidência.","Ela transcende a hierarquia formal e baseia-se em afinidades e interações espontâneas.","Ela atrasa invariavelmente os fluxos de trabalho institucionais.","Ela é representada pelos fluxogramas do setor de Organização e Métodos."], resposta_correta:2, explicacao: "A organização informal surge espontaneamente, não está no papel (organograma/manuais) e não pode ser eliminada. A banca insere palavras como 'invariavelmente' e 'sumariamente eliminada' para forçar o aluno a rejeitar a organização informal, que na verdade muitas vezes agiliza o trabalho.", status:0, historico:0 },
{ id:436, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No planejamento das ações do conselho, as decisões que afetam a autarquia de forma global, com foco no longo prazo e interação com o ambiente externo, são tomadas no nível:", imagem:null, alternativas:["Operacional.","Tático.","Supervisório.","Estratégico.","Setorial."], resposta_correta:3, explicacao: "Nível Estratégico = Global, longo prazo, ambiente externo (Cúpula). Nível Tático = Setorial/Departamental, médio prazo. Nível Operacional = Tarefas, curto prazo. Questão de conhecimento basilar, mas que a banca às vezes disfarça em microtextos enormes.", status:0, historico:0 },
{ id:437, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Durante uma consultoria no CRECI, o analista detectou que os servidores estavam desmotivados pontualmente devido ao atraso no pagamento de diárias, alterando o 'humor' do ambiente. Contudo, os valores de integridade e a missão do conselho permaneciam inabaláveis. O texto ilustra a diferença clássica entre:", imagem:null, alternativas:["Clima Organizacional (superficial e mutável) e Cultura Organizacional (profunda e enraizada).","Cultura Organizacional (passageira) e Clima Organizacional (estrutural).","Liderança Transacional (focada em valores) e Liderança Carismática (focada em pagamentos).","Motivação Intrínseca (dependente de salário) e Motivação Extrínseca (valores morais).","Empowerment (atraso financeiro) e Accountability (missão inabalável)."], resposta_correta:0, explicacao: "O Clima é o 'humor' da organização (mutável e reativo a fatores como salário). A Cultura é a 'personalidade' (crenças, valores, difícil de mudar). A Quadrix inverte frequentemente esses dois conceitos (como visto na alternativa B).", status:0, historico:0 },
{ id:438, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Segundo a Teoria dos Dois Fatores de Frederick Herzberg, o aumento do salário e a melhoria das condições físicas da sede do CRECI-BA provocarão, nos servidores:", imagem:null, alternativas:["Uma elevação imediata e duradoura da motivação e do engajamento técnico.","A autoatualização, alcançando o topo da pirâmide de necessidades.","A ausência de insatisfação, mas não necessariamente gerarão satisfação e motivação duradoura.","A insatisfação aguda, visto que são considerados fatores desmotivacionais.","A consolidação do sentimento de responsabilidade e crescimento profissional."], resposta_correta:2, explicacao: "Para Herzberg, salário e condições de trabalho são fatores HIGIÊNICOS (extrínsecos). Eles apenas evitam que o funcionário fique insatisfeito, mas não têm o poder de gerar motivação profunda. Motivação real vem de fatores motivacionais (reconhecimento, a própria tarefa). Dica: essa é a maior pegadinha de RH da banca.", status:0, historico:0 },
{ id:439, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise: I. A Liderança Autocrática foca estritamente nas tarefas, centralizando o poder de decisão. II. Na Liderança Laissez-faire (Liberal), a equipe possui pouca liberdade de atuação, dependendo sempre do líder. III. A Liderança Situacional defende que o estilo do líder deve se adaptar ao nível de maturidade do subordinado. Está(ão) correta(s):", imagem:null, alternativas:["Apenas I.","Apenas II e III.","Apenas I e III.","Apenas III.","I, II e III."], resposta_correta:2, explicacao: "A assertiva II é falsa porque na liderança liberal a equipe possui TOTAL liberdade e o líder age apenas quando solicitado. A I e a III trazem as definições canônicas de autocracia e teoria situacional (Hersey e Blanchard).", status:0, historico:0 },
{ id:440, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Durante a avaliação de desempenho anual, um gestor atribui nota máxima em todos os quesitos a um assistente administrativo pelo simples fato de o funcionário ser extremamente pontual, ignorando suas falhas na redação de atas. O erro de avaliação (viés de percepção) cometido pelo gestor é conhecido como:", imagem:null, alternativas:["Efeito Halo (ou Efeito de Halo).","Tendência Central.","Erro de Recência.","Efeito de Contraste.","Projeção Psicológica."], resposta_correta:0, explicacao: "O Efeito Halo ocorre quando uma única característica positiva (ser pontual) 'cega' o avaliador, que estende essa nota positiva para todos os outros quesitos não relacionados. A banca Quadrix utiliza microcontextos (historinhas) para cobrar esses vieses acadêmicos.", status:0, historico:0 },
{ id:441, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A comunicação eficaz no setor público é prejudicada por barreiras. Quando um analista jurídico do conselho utiliza termos em latim ('data venia', 'periculum in mora') ao atender um corretor leigo, gerando incompreensão, ocorreu uma típica barreira:", imagem:null, alternativas:["Física, devido à acústica do ambiente.","Psicológica, por conta do preconceito do corretor.","Hierárquica, baseada no nível de cargo do servidor.","Semântica, relacionada ao significado e complexidade das palavras.","Fisiológica, ligada à audição do emissor."], resposta_correta:3, explicacao: "Barreiras semânticas referem-se aos códigos, jargões, idiomas e significados das mensagens. É o clássico 'falar difícil' que não atinge o receptor. A Quadrix cria cenários óbvios de outras barreiras para tentar despistar (como acústica para barreira física).", status:0, historico:0 },
{ id:442, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A prática gerencial do 'Empowerment' (Empoderamento) implementada na equipe de fiscalização do CRECI consiste em:", imagem:null, alternativas:["Aumentar a supervisão microscópica sobre os passos do fiscal.","Delegar poder, autoridade e responsabilidade aos colaboradores para tomada de decisões.","Centralizar o atendimento em uma única central automatizada.","Punir severamente qualquer erro cometido durante operações de campo.","Reduzir os salários em troca de flexibilidade de horários."], resposta_correta:1, explicacao: "Empowerment significa dar autonomia, poder e informações para que a base possa tomar decisões sem precisar subir toda a cadeia hierárquica. A Quadrix testa se o candidato confunde empoderamento com abandono ou com controle absoluto (A).", status:0, historico:0 },
{ id:443, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No ingresso de um novo servidor, além do contrato formal de posse, estabelece-se o 'Contrato Psicológico'. No âmbito das relações humanas no trabalho, este contrato refere-se:", imagem:null, alternativas:["Ao documento assinado pelo setor de Recursos Humanos e pelo médico do trabalho.","Ao conjunto de expectativas não escritas e mútuas entre o indivíduo e a organização.","À imposição unilateral de metas impossíveis por parte da alta gestão.","Ao acordo financeiro sobre horas extras previamente homologado no sindicato.","Aos testes psicotécnicos aplicados durante o concurso público."], resposta_correta:1, explicacao: "O contrato psicológico é a expectativa tácita, não documentada, do que a empresa espera do funcionário (dedicação) e do que o funcionário espera da empresa (reconhecimento, justiça). A banca joga o candidato para o lado formal e burocrático (opções A e D) para errar o item.", status:0, historico:0 },
{ id:444, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Segundo Daniel Goleman, a Inteligência Emocional no ambiente de trabalho divide-se em aptidões pessoais e sociais. A capacidade do servidor de compreender os sentimentos, necessidades e perspectivas do corretor que atende no balcão é classificada como:", imagem:null, alternativas:["Autoconhecimento.","Autocontrole.","Automotivação.","Empatia.","Habilidade Tecnológica."], resposta_correta:3, explicacao: "Compreender e colocar-se no lugar do outro (perceber seus sentimentos e pontos de vista) é a essência da Empatia, que compõe a inteligência interpessoal de Goleman. A banca fornece conceitos corretos de outras frentes (autoconhecimento) para confundir o candidato.", status:0, historico:0 },
{ id:445, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Na literatura administrativa, há uma diferenciação clara entre 'Grupos de Trabalho' e 'Equipes de Trabalho'. Assinale a alternativa que apresenta uma característica exclusiva das EQUIPES:", imagem:null, alternativas:["O foco no desempenho individual de cada membro.","A presença de sinergia positiva, onde o resultado do todo é maior que a soma das partes.","A responsabilidade pelo resultado é estritamente individual.","Os membros compartilham informações, mas não possuem um objetivo coletivo engajador.","A liderança é invariavelmente imposta e autocrática."], resposta_correta:1, explicacao: "Sinergia positiva e responsabilidade mútua (coletiva) são as marcas registradas de uma Equipe. Grupos apenas compartilham informações para que cada um faça sua parte (sem sinergia real). A Quadrix sempre pede a distinção Grupo x Equipe.", status:0, historico:0 },
{ id:446, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"De acordo com o modelo de Bruce Tuckman sobre o desenvolvimento de equipes, o estágio caracterizado pelo surgimento de conflitos internos, disputas por liderança e resistência às normas iniciais é o estágio de:", imagem:null, alternativas:["Formação (Forming).","Desempenho (Performing).","Normatização (Norming).","Tormenta ou Conflito (Storming).","Desintegração (Adjourning)."], resposta_correta:3, explicacao: "O Storming (Tormenta) é a fase natural onde os membros já se conhecem um pouco e começam a disputar espaço e liderança. Somente após isso vem a Normatização. A Quadrix explora esse modelo em questões de nível superior e médio exigente.", status:0, historico:0 },
{ id:447, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um fenômeno perigoso em equipes altamente coesas do setor público é o 'Pensamento de Grupo' (Groupthink). Esse conceito ocorre quando:", imagem:null, alternativas:["A equipe analisa todas as opções criticamente e gera conflitos saudáveis constantes.","A busca pela harmonia e pelo consenso na equipe supera a avaliação realista de alternativas, suprimindo opiniões divergentes.","O líder delega todas as tarefas, promovendo a inovação radical e a quebra de regras.","Os membros da equipe trabalham de forma isolada, comunicando-se apenas por ofícios formais.","O grupo se desintegra rapidamente devido a rivalidades políticas intensas."], resposta_correta:1, explicacao: "Groupthink é a 'cegueira coletiva'. O desejo de não contrariar o grupo faz com que ideias ruins sejam aprovadas sem questionamento (ex: ninguém quer ser o chato que discorda). A banca usa isso para mostrar que coesão em excesso tem lado negativo.", status:0, historico:0 },
{ id:448, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Julgue (V) ou (F): ( ) A visão interacionista moderna considera que todo e qualquer conflito é prejudicial e deve ser erradicado da autarquia. ( ) A abordagem de resolução de conflitos 'Ganha-Ganha' exige colaboração mútua e foco nos interesses reais, e não em posições fixas. ( ) Evitar um conflito (fuga) pode ser uma estratégia válida quando o assunto for trivial e não valer o desgaste. A sequência correta é:", imagem:null, alternativas:["F, V, V.","V, F, V.","V, V, V.","F, F, F.","F, V, F."], resposta_correta:0, explicacao: "A primeira é falsa: a visão interacionista afirma que um nível mínimo de conflito é necessário para evitar a apatia e gerar inovação (conflito funcional). Dica: a Quadrix pune quem acha que conflito é sempre ruim.", status:0, historico:0 },
{ id:449, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O CRECI formou um grupo com funcionários de TI, do Jurídico e da Fiscalização para resolver o problema crônico de atrasos nas análises de processos. Após 3 meses, o problema foi resolvido e o grupo foi desfeito. Essa estrutura temporária e multifuncional é tecnicamente chamada de:", imagem:null, alternativas:["Equipe Autogerenciada Permanente.","Círculo de Qualidade.","Equipe de Força-Tarefa (Task Force).","Comitê Estatutário Diretor.","Equipe Virtual de Atendimento."], resposta_correta:2, explicacao: "Força-tarefa é uma equipe multifuncional temporária criada para resolver um problema específico e que é desfeita após a conclusão. A Quadrix descreve o cenário perfeitamente para testar o reconhecimento do conceito.", status:0, historico:0 },
{ id:450, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A 'Coesão' de uma equipe pode ser definida como o grau em que os membros são atraídos entre si e motivados a permanecer no grupo. Assinale a alternativa que apresenta um fator que TENDENCIALMENTE AUMENTA a coesão da equipe:", imagem:null, alternativas:["O aumento excessivo do tamanho da equipe, passando de 5 para 30 membros operacionais.","A ausência total de metas claras e indicadores de sucesso.","Uma forte ameaça externa, como críticas severas da imprensa ou pressão do COFECI.","O estímulo constante à competição predatória e individualista entre os próprios membros.","A diversidade extrema de objetivos pessoais conflitantes no grupo."], resposta_correta:2, explicacao: "Ameaças externas (um inimigo comum) unem a equipe, aumentando a coesão. Pense no efeito 'estamos juntos nessa crise'. A banca sabe que o candidato pode ver a palavra 'ameaça' e descartar a alternativa por parecer negativa.", status:0, historico:0 },
{ id:451, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Dentro de uma equipe de trabalho, membros assumem diferentes papéis. Aquele membro cujo comportamento foca em mediar conflitos internos, encorajar a participação dos mais tímidos e manter a harmonia do grupo está exercendo um papel orientado primordialmente:", imagem:null, alternativas:["Para a tarefa técnica.","Para as relações (manutenção do grupo).","Para o bloqueio sistêmico.","Para o status hierárquico.","Para o boicote disfuncional."], resposta_correta:1, explicacao: "Existem papéis de tarefa (foco no que deve ser feito) e papéis de manutenção/relações (foco em como as pessoas se sentem e interagem). O mediador cuida das relações. Questão teórica refinada frequentemente abordada pela Quadrix.", status:0, historico:0 },
{ id:452, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Atendimento ao Público", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Ao atender um corretor idoso que possui extrema dificuldade com o sistema digital do CRECI, o servidor público deve balizar sua conduta pelo conceito de 'Empatia'. No contexto do atendimento ao público, ser empático significa:", imagem:null, alternativas:["Demonstrar pena e realizar o trabalho pelo cidadão, isentando-o de suas responsabilidades legais.","Compreender as limitações do cidadão, colocando-se em seu lugar para oferecer um suporte humanizado e eficiente.","Tratar o idoso com rapidez extrema para não atrasar a fila, mantendo o distanciamento afetivo.","Usar linguagem técnica jurídica para demonstrar a autoridade do órgão público.","Ignorar as regras do conselho para favorecer o idoso em detrimento dos demais na fila."], resposta_correta:1, explicacao: "Empatia é compreender a perspectiva do outro e adequar o suporte, sem quebrar as regras legais (o que elimina a E) ou inferiorizar o usuário com 'pena' (eliminando a A).", status:0, historico:0 },
{ id:453, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A área de Relações Públicas (RP) em uma autarquia pública diferencia-se da Publicidade tradicional porque as Relações Públicas focam prioritariamente em:", imagem:null, alternativas:["Vender espaços em revistas para corretores de imóveis aumentarem seus lucros.","Construir e preservar a imagem institucional e o relacionamento de confiança com os diversos públicos (stakeholders).","Pagar por anúncios apelativos em horário nobre de televisão para garantir arrecadação.","Ocultar as falhas operacionais do conselho da mídia e da sociedade em geral.","Produzir materiais promocionais exclusivamente para o presidente do órgão (marketing pessoal)."], resposta_correta:1, explicacao: "Relações Públicas visam a imagem, a reputação e a transparência com o público, enquanto a publicidade/propaganda tradicional foca mais na venda de produtos/serviços pagos. A Quadrix explora a confusão entre RP e Marketing Pessoal ilícito (opção E).", status:0, historico:0 },
{ id:454, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise: I. O atendimento público de qualidade é um direito do cidadão e um dever do Estado (e de suas autarquias). II. A cidadania ativa pressupõe que o usuário atue apenas como receptor passivo dos serviços, sem direito a avaliá-los. III. A cortesia no atendimento é um princípio ético, mas que pode ser flexibilizado caso o servidor esteja sobrecarregado. Está(ão) correta(s):", imagem:null, alternativas:["Apenas I.","Apenas II e III.","Apenas I e III.","Apenas III.","I, II e III."], resposta_correta:0, explicacao: "A II está errada porque cidadania ativa exige a participação e o controle social (avaliação). A III está errada pois a cortesia e a urbanidade não podem ser suspensas por motivo de sobrecarga funcional. A banca força o candidato a justificar falhas éticas através do volume de trabalho.", status:0, historico:0 },
{ id:455, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Organização Administrativa", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No relacionamento com a sociedade, a Ouvidoria possui um papel distinto do Serviço de Atendimento ao Consumidor/Cidadão (SAC). É uma característica essencial da Ouvidoria em instituições públicas:", imagem:null, alternativas:["Atuar na linha de frente para resolver dúvidas simples de senhas e boletos instantaneamente.","Funcionar como uma instância de recurso e de defesa dos direitos do cidadão, sugerindo melhorias nos processos institucionais a partir das reclamações.","Ser um órgão subordinado e controlado diretamente pelo setor que está sendo alvo da reclamação.","Limitar-se a arquivar elogios, descartando sumariamente as denúncias anônimas fundamentadas.","Defender incondicionalmente a instituição contra o cidadão em disputas judiciais."], resposta_correta:1, explicacao: "O SAC resolve o imediato (1ª instância). A Ouvidoria analisa problemas crônicos, atua como 2ª instância e tem o dever de ser propositiva (melhorar a máquina pública). A banca ama essa diferença estrutural.", status:0, historico:0 },
{ id:456, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Para as Relações Públicas do CRECI, é crucial entender a diferença entre Identidade e Imagem. É correto afirmar que:", imagem:null, alternativas:["A Imagem é o que a organização 'é' de fato; a Identidade é como a sociedade a percebe.","Ambas são sinônimos perfeitos criados pelo setor de publicidade.","A Identidade é o conjunto de atributos e valores reais que a organização constrói; a Imagem é a forma como o público externo percebe e interpreta esses atributos.","A Identidade Corporativa pode ser comprada rapidamente através de uma logomarca nova, enquanto a Imagem leva décadas.","A Imagem institucional não sofre qualquer impacto por atitudes não éticas de servidores isolados."], resposta_correta:2, explicacao: "Identidade = Essência (quem nós somos). Imagem = Percepção (como eles nos veem). A Quadrix inverte essas definições sistematicamente na opção A para pegar os apressados.", status:0, historico:0 },
{ id:457, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No jargão de atendimento ao público e gestão de serviços, o conceito de 'Momento da Verdade' (de Jan Carlzon) refere-se:", imagem:null, alternativas:["À auditoria financeira realizada pelo TCU no fim do ano fiscal.","Ao instante em que o funcionário confessa um erro ético perante o conselho.","A qualquer episódio em que o cidadão entra em contato com qualquer aspecto da organização e forma uma impressão sobre a qualidade de seu serviço.","Ao momento em que o corretor assina o termo de posse da carteira profissional.","À fase de investigação conclusiva de um processo de exercício ilegal da profissão."], resposta_correta:2, explicacao: "A teoria de Carlzon diz que o serviço é avaliado em milhares de 'momentos da verdade', que é qualquer ponto de contato (site lento, recepção suja, atendente grosseiro). A banca cria opções literais (D, E) para disfarçar o conceito acadêmico.", status:0, historico:0 },
{ id:458, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um servidor recebe a ligação de um corretor extremamente exaltado e agressivo devido a um atraso sistêmico. A técnica de comunicação assertiva orienta que o servidor deve:", imagem:null, alternativas:["Desligar o telefone imediatamente, pois a autarquia não tolera críticas.","Responder no mesmo tom de agressividade para demonstrar que o Estado detém o poder de polícia.","Escutar ativamente, não levar para o lado pessoal, reconhecer a frustração do usuário e focar na solução objetiva do problema.","Concordar com o usuário que o sistema do órgão é de fato 'um lixo' para acalmá-lo rapidamente.","Transferir a ligação para outro colega sem nenhum aviso prévio, evitando o desgaste emocional."], resposta_correta:2, explicacao: "A assertividade no serviço público exige controle emocional, empatia tática e foco em resolução, sem ser passivo (aceitar insultos concordando) nem agressivo (revirando). A Quadrix usa situações extremas para testar o bom senso e o profissionalismo exigido em manuais de ética.", status:0, historico:0 },
{ id:459, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O setor de fiscalização do CRECI-BA precisa comunicar formalmente ao setor de RH uma solicitação interna. Considerando as diretrizes da 3ª edição do Manual de Redação da Presidência da República, o documento administrativo correto para essa comunicação é:", imagem:null, alternativas:["O Memorando, por ser o documento padrão para comunicações estritamente internas.","A Circular, pois a comunicação deve transitar abertamente por toda a autarquia.","O Ofício, que passou a ser o documento padrão e único para comunicações oficiais, abolindo-se o Memorando.","O Aviso, pois trata-se de comunicação entre chefias que possuem exatamente a mesma hierarquia.","A Portaria, visto que qualquer solicitação de RH altera imediatamente a situação estatutária do servidor."], resposta_correta:2, explicacao: "A 3ª edição do MRPR aboliu a distinção entre Ofício, Memorando e Aviso. Agora, usa-se o 'Padrão Ofício' para comunicações internas e externas. A Quadrix ama usar o 'Memorando' como alternativa para fisgar candidatos desatualizados.", status:0, historico:0 },
{ id:460, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Durante um atendimento no CRECI, o corretor, que já possuía um histórico de infrações, interpretou um ofício padrão de recadastramento como uma 'ameaça pessoal de cassação' devido ao seu nervosismo e experiências negativas prévias. O texto ilustra a ocorrência de uma barreira de comunicação do tipo:", imagem:null, alternativas:["Física, decorrente de problemas na impressão do ofício.","Psicológica, gerada por emoções, preconceitos e experiências passadas do receptor.","Semântica, relacionada ao uso excessivo de jargões jurídicos incompreensíveis.","Fisiológica, causada por um déficit de leitura do corretor.","Tecnológica, devido ao envio do ofício por meio eletrônico em vez de papel."], resposta_correta:1, explicacao: "Barreiras psicológicas envolvem sentimentos, emoções e defesas mentais (como medo ou preconceito) que distorcem a mensagem real. A banca descreve microcontextos reais para testar se o candidato não confunde com barreira semântica (linguagem).", status:0, historico:0 },
{ id:461, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Ao assinar um Ofício destinado ao Governador do Estado da Bahia, o Presidente do CRECI-BA deve encerrar o documento utilizando obrigatoriamente o seguinte fecho para comunicações oficiais:", imagem:null, alternativas:["'Respeitosamente,', por se tratar de autoridade superior na hierarquia do protocolo de Estado.","'Atenciosamente,', pois na administração pública moderna todos são tratados com absoluta igualdade hierárquica.","'Saudações Cordiais,', que é o fecho padrão para o poder executivo estadual.","'Com estima e consideração,', utilizado exclusivamente para autoridades políticas.","'Sem mais para o momento,', garantindo a concisão exigida pela norma culta."], resposta_correta:0, explicacao: "O MRPR define apenas dois fechos: 'Atenciosamente' (para autoridades de mesma hierarquia ou inferiores) e 'Respeitosamente' (para autoridades superiores). O Governador de Estado é autoridade superior ao presidente de uma autarquia regional. Dica: Fuja de alternativas com saudações afetuosas.", status:0, historico:0 },
{ id:462, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A 'Ata' é um documento de registro fundamental nas sessões plenárias do conselho. Assinale a característica que NÃO se aplica à redação de uma Ata formal:", imagem:null, alternativas:["Ausência de parágrafos com recuo, sendo o texto escrito em bloco único e contínuo.","Proibição absoluta de entrelinhas, rasuras ou uso de corretivos líquidos.","Uso de números sempre escritos por extenso para evitar adulterações futuras.","Inclusão de espaços em branco significativos entre as pautas para facilitar a adição posterior de informações esquecidas.","Omissão de adjetivos inúteis e de opiniões pessoais do secretário que a redige."], resposta_correta:3, explicacao: "Ata não pode ter NENHUM espaço em branco, recuo ou entrelinha, justamente para impedir que algo seja adicionado fraudulentamente após as assinaturas. A Quadrix inverte a lógica dizendo que os espaços 'facilitam' para induzir ao erro.", status:0, historico:0 },
{ id:463, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Julgue as sentenças com (V) para Verdadeiro e (F) para Falso quanto aos fluxos de comunicação: ( ) O fluxo descendente transmite diretrizes, metas e normativas da diretoria para a base. ( ) O fluxo ascendente é caracterizado exclusivamente pelo envio de punições aos superiores. ( ) O fluxo horizontal ocorre entre servidores de um mesmo nível hierárquico, visando a coordenação de tarefas. A sequência correta é:", imagem:null, alternativas:["V, V, F.","F, F, V.","V, F, V.","V, V, V.","F, V, F."], resposta_correta:2, explicacao: "A segunda é falsa porque o fluxo ascendente (de baixo para cima) leva sugestões, relatórios, reclamações e feedbacks, mas NUNCA 'punições' para superiores. A banca usa o absurdo hierárquico ('punir o chefe') camuflado pela palavra 'exclusivamente'.", status:0, historico:0 },
{ id:464, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise as assertivas sobre os atributos da Redação Oficial: I. A 'Concisão' exige que o texto seja o mais curto possível, autorizando a omissão de dados essenciais para economizar papel. II. A 'Impessoalidade' determina a ausência de impressões individuais do servidor, focando apenas no interesse público. III. A 'Clareza' significa que o documento deve ser compreendido de imediato pelo leitor, evitando-se o hermetismo e o vocabulário restrito. Está(ão) correta(s):", imagem:null, alternativas:["Apenas a I.","Apenas a II.","Apenas I e II.","Apenas II e III.","I, II e III."], resposta_correta:3, explicacao: "A assertiva I é falsa. Concisão é transmitir o MÁXIMO de informação com o MÍNIMO de palavras, MAS sem jamais omitir dados essenciais. Textos curtos mas incompletos não são concisos, são falhos. Pegadinha clássica de inversão de conceito.", status:0, historico:0 },
{ id:465, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O Presidente do CRECI necessita praticar dois atos: o primeiro é aplicar uma penalidade a um servidor administrativo (ato interno); o segundo é fixar as novas taxas de serviço para todos os corretores do estado (ato geral/externo). Os documentos adequados para essas ações são, respectivamente:", imagem:null, alternativas:["Aviso e Ofício.","Portaria e Resolução.","Parecer e Despacho.","Circular e Edital.","Certidão e Alvará."], resposta_correta:1, explicacao: "Portaria é o ato interno para nomeações, punições e diretrizes para servidores. Resolução é o ato normativo de efeitos gerais e externos (ex: taxas para toda a categoria). A banca mistura os documentos para testar o domínio da amplitude do ato.", status:0, historico:0 },
{ id:466, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A comunicação informal nas autarquias, comumente chamada de 'rádio peão' ou rede de rumores, caracteriza-se por:", imagem:null, alternativas:["Ser um canal oficial documentado nos manuais de OSM do conselho.","Circular de forma extremamente lenta e sempre respeitar a cadeia de comando.","Ser impossível de erradicar, sendo mais veloz que a formal, embora frequentemente carregue distorções.","Dever ser eliminada sumariamente através de punições rigorosas a quem conversar nos corredores.","Substituir legalmente as portarias e os ofícios em casos de urgência máxima."], resposta_correta:2, explicacao: "A rede informal (rumores) é espontânea, inerradicável e muito rápida, porém propensa a fofocas e erros. A alternativa D atrai o candidato que acredita no autoritarismo burocrático como solução de gestão.", status:0, historico:0 },
{ id:467, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Ao redigir um documento no qual se fala A RESPEITO DO (sobre o) Presidente da República, mas que não é endereçado diretamente a ele, o pronome de tratamento correto a ser utilizado no corpo do texto é:", imagem:null, alternativas:["Vossa Excelência.","Sua Excelência.","Vossa Senhoria.","Ouvidoria de Sua Excelência.","Ilustríssimo Senhor."], resposta_correta:1, explicacao: "Regra de ouro: 'Vossa' é usado quando se fala DIRETAMENTE com a pessoa. 'Sua' é usado quando se fala SOBRE a pessoa com um terceiro. A Quadrix explora implacavelmente essa sutileza gramatical e de protocolo.", status:0, historico:0 },
{ id:468, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O 'Parecer' emitido pelo setor jurídico do CRECI-BA em um processo de fiscalização tem a natureza de um ato:", imagem:null, alternativas:["Normativo, pois cria leis imediatas que obrigam toda a sociedade.","Punitivo, visto que aplica multas automaticamente.","Enunciativo, pois expressa uma opinião técnica ou jurídica que fundamentará a decisão final.","Ordinatório, pois disciplina o funcionamento interno do RH.","Declaratório vitalício, semelhante a uma certidão de nascimento."], resposta_correta:2, explicacao: "Parecer é um ato enunciativo (emite conhecimento/opinião técnica). Ele não decide, não pune e não cria leis. Ele apenas orienta a autoridade que vai decidir (dar o Despacho). A banca sempre tenta dar poderes decisórios ao Parecer.", status:0, historico:0 },
{ id:469, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O uso do e-mail (correio eletrônico) na administração pública tornou-se a principal forma de comunicação. Sobre o e-mail oficial, é correto afirmar:", imagem:null, alternativas:["Por sua agilidade, está isento das regras gramaticais e do padrão culto da língua.","Dispensa completamente o uso de bloco de assinatura, pois o nome do remetente já consta no cabeçalho.","Possui valor documental oficial e deve atender aos mesmos requisitos de impessoalidade e clareza do Padrão Ofício.","Pode ser utilizado livremente para propagandas políticas de servidores, desde que após o expediente.","Não pode conter arquivos anexos que ultrapassem 1 Megabyte por força de lei federal."], resposta_correta:2, explicacao: "O e-mail OFICIAL é um documento como qualquer outro (Padrão Ofício). Ele exige norma culta, impessoalidade e bloco de assinatura padronizado. A banca cria o distrator A para tentar legitimar o desleixo comum no uso privado do e-mail.", status:0, historico:0 },
{ id:470, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Assinale a alternativa que diferencia corretamente a Comunicação Interna da Comunicação Externa (Relações Públicas) em um conselho de classe:", imagem:null, alternativas:["A interna foca exclusivamente em multar funcionários; a externa em perdoar corretores.","A interna busca o engajamento, alinhamento e motivação dos servidores; a externa foca na construção de imagem, transparência e prestação de contas à sociedade.","A interna deve ser feita obrigatoriamente por jornais impressos; a externa apenas por redes sociais.","A externa é de responsabilidade exclusiva do setor de RH; a interna cabe ao Presidente.","Não há diferença prática, ambas utilizam a mesma linguagem coloquial para gerar proximidade."], resposta_correta:1, explicacao: "Definição acadêmica perfeita: Comunicação Interna = clima, engajamento e processos. RP (Externa) = imagem, stakeholders e transparência. A Quadrix tenta esvaziar a função de RP reduzindo-a a mídias sociais (C) ou punições (A).", status:0, historico:0 },
{ id:471, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Ao redigir um ofício para um Senador da República, o vocativo (saudação inicial) que deve constar no início do documento, conforme o MRPR atualizado, é:", imagem:null, alternativas:["Excelentíssimo Senhor Senador,","Senhor Senador,","Digníssimo Senador,","Ilustríssimo Senhor Senador,","Vossa Excelência,"], resposta_correta:1, explicacao: "A 3ª edição do MRPR restringiu o vocativo 'Excelentíssimo Senhor' APENAS aos Chefes de Poder (Presidente da República, Presidente do STF e Presidente do Congresso). Para todas as demais autoridades, usa-se 'Senhor + Cargo' (Senhor Senador). Pegadinha dificílima e muito cobrada.", status:0, historico:0 },
{ id:472, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um corretor de imóveis solicita ao CRECI um documento oficial que comprove que não existem processos ético-disciplinares contra ele nos arquivos da autarquia. O documento administrativo que atende a esse pedido é a(o):", imagem:null, alternativas:["Atestado Médico.","Parecer Jurídico.","Certidão Negativa.","Portaria de Absolvição.","Circular Externa."], resposta_correta:2, explicacao: "A Certidão é o documento pelo qual a administração atesta um fato que consta em seus registros ou livros. Como não há processos, é uma 'Certidão Negativa'. A Quadrix usa o Parecer (B) e a Portaria (D) como distratores de poder.", status:0, historico:0 },
{ id:473, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No contexto de Relações Públicas, quando o CRECI-BA emite um 'Press Release' (Comunicado à Imprensa), o objetivo central é:", imagem:null, alternativas:["Comprar espaço publicitário pago na capa de um jornal local.","Fornecer informações oficiais e pautar a mídia com notícias de interesse do conselho e da sociedade.","Punir jornalistas que falaram mal da autarquia em edições passadas.","Convocar os servidores para uma reunião interna de alinhamento tático.","Impedir que os cidadãos tenham acesso aos dados financeiros do órgão."], resposta_correta:1, explicacao: "Press Release é uma ferramenta de Assessoria de Imprensa (RP) usada para gerar mídia espontânea (não paga), fornecendo os fatos sob a ótica oficial do órgão. O erro da opção A é confundir RP com Publicidade Paga.", status:0, historico:0 },
{ id:474, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Quanto à formatação visual exigida pelo Padrão Ofício, assinale a alternativa que apresenta uma generalização indevida cobrada em provas:", imagem:null, alternativas:["A fonte recomendada é Calibri ou Carlito, tamanho 12, para o texto principal.","Deve-se utilizar alinhamento justificado no texto do documento.","As notas de rodapé, quando existirem, devem ser digitadas em tamanho 10.","Para símbolos não previstos nas fontes padrão, pode-se usar a fonte Symbol.","O uso de fontes artísticas como 'Comic Sans' é obrigatório em circulares comemorativas internas."], resposta_correta:4, explicacao: "A redação oficial abomina o uso de fontes artísticas ou informais, mesmo em datas comemorativas, pois fere o princípio da impessoalidade e formalidade. A Quadrix cria a exceção falsa 'comemorativa' para validar um absurdo técnico.", status:0, historico:0 },
{ id:475, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise: I. É o documento pelo qual a autoridade competente profere uma decisão em um processo administrativo. II. É a correspondência oficial que transmite ordens ou avisos iguais a vários destinatários simultaneamente. As definições I e II correspondem, respectivamente, a:", imagem:null, alternativas:["Despacho e Circular.","Ata e Ofício.","Parecer e Edital.","Portaria e Relatório.","Certidão e Alvará."], resposta_correta:0, explicacao: "Despacho = Decisão da autoridade no processo. Circular = Envio do mesmo texto para várias pessoas (círculo). A banca exige o reconhecimento limpo e direto da definição jurídica dos atos.", status:0, historico:0 },
{ id:476, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Na teoria da comunicação, o elemento que permite ao emissor (CRECI) confirmar se o receptor (Corretor) compreendeu a mensagem enviada, ajustando o canal ou o código caso haja falhas, é o(a):", imagem:null, alternativas:["Ruído físico.","Redundância extrema.","Feedback (Retroalimentação).","Barreira semântica.","Canal unidirecional."], resposta_correta:2, explicacao: "O Feedback é o retorno da mensagem. Ele transforma a comunicação de uma via de mão única (informação) para uma via de mão dupla (comunicação real). A banca tenta confundir feedback com 'redundância'.", status:0, historico:0 },
{ id:477, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O Manual de Redação proíbe o uso de expressões consagradas pelo burocratismo rançoso. Assinale a alternativa que contém uma expressão inicial CORRETA e moderna para um ofício de encaminhamento:", imagem:null, alternativas:["'Tenho a honra de encaminhar...'","'Cumpre-me o dever indeclinável de enviar...'","'Encaminho...'","'Venho por meio desta mui respeitosamente solicitar...'","'Serve a presente para enviar...'"], resposta_correta:2, explicacao: "A concisão exige ir direto ao ponto. 'Encaminho...' ou 'Informo...' substitui toda a bajulação inútil do português arcaico (opções A, B, D e E). A Quadrix sempre pede a identificação do 'burocratismo'.", status:0, historico:0 },
{ id:478, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Durante a explicação das novas taxas no balcão, o corretor não consegue escutar o assistente do CRECI devido ao forte barulho de uma britadeira na rua em frente à sede. Neste caso específico, a falha na comunicação decorre de um ruído:", imagem:null, alternativas:["Semântico.","Psicológico.","Fisiológico.","Físico.","Cultural."], resposta_correta:3, explicacao: "O barulho ambiental (britadeira, telefone tocando alto, interferência na rádio) é o exemplo clássico de barreira/ruído FÍSICO. Não confundir com fisiológico (surdez/dor no emissor ou receptor).", status:0, historico:0 },
{ id:479, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O setor de protocolo do CRECI-BA é a porta de entrada de documentos institucionais. Na fase de 'Classificação' das correspondências recebidas, o servidor deve separar os documentos de caráter ostensivo dos de caráter sigiloso. Sobre essa rotina, é correto afirmar:", imagem:null, alternativas:["A) As correspondências sigilosas devem ser abertas imediatamente pelo protocolo para fins de registro detalhado no sistema central.","B) A classificação tem por objetivo definir exclusivamente o grau de sigilo, ignorando a natureza do assunto para não atrasar a entrega.","C) Correspondências particulares (pessoais) devem ser encaminhadas aos destinatários sem que o protocolo as abra, respeitando a inviolabilidade.","D) Toda e qualquer correspondência ostensiva deve ser lida na íntegra pelo servidor do protocolo para a confecção de um resumo analítico extenso.","E) Documentos com a marcação de sigilo só podem ser abertos pelo presidente do conselho, sendo expressamente vedada a delegação."], resposta_correta:2, explicacao: "Correspondências de natureza particular (pessoal) ou sigilosas NÃO são abertas pelo protocolo. O erro da 'D' é dizer 'lida na íntegra' e 'resumo extenso', pois o protocolo lê apenas o suficiente para classificar o assunto. A Quadrix tenta forçar que o protocolo abre tudo (A) sob a desculpa de alimentar o sistema.", status:0, historico:0 },
{ id:480, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Julgue as sentenças com (V) para Verdadeiro e (F) para Falso quanto ao processo de Autuação e Juntada: ( ) A autuação consiste na abertura do processo, momento em que o documento recebe capa, numeração de folhas e registro formal. ( ) É expressamente proibida a juntada por anexação de um processo a outro, devendo-se utilizar apenas a apensação em caráter definitivo. ( ) O termo 'desentranhamento' refere-se à retirada de peças de um processo, que só pode ocorrer mediante justificativa, deixando-se um termo no local. A sequência correta é:", imagem:null, alternativas:["V, F, V.","V, V, F.","F, V, V.","V, F, F.","F, F, V."], resposta_correta:0, explicacao: "A segunda é Falsa porque a Anexação é a juntada DEFINITIVA (mesma matéria), enquanto a Apensação é a juntada PROVISÓRIA (matérias conexas, mas processos mantêm independência). A Quadrix inverte rotineiramente as definições de Anexação e Apensação para testar o candidato.", status:0, historico:0 },
{ id:481, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O 'Registro' é uma das operações fundamentais do Protocolo. No fluxo de controle de documentos do conselho, efetuar o registro significa:", imagem:null, alternativas:["A) Destruir as vias originais após a digitalização para garantir a economicidade de espaço físico no arquivo.","B) Reproduzir o documento em dezenas de vias para entrega simultânea a todos os conselheiros regionais.","C) Cadastrar os dados básicos do documento (número, origem, assunto, data) em um sistema para formar o seu histórico e controlar o trâmite.","D) Classificar o documento de acordo com a tabela de temporalidade para envio imediato e direto ao arquivo morto.","E) Entregar fisicamente o documento ao setor destinatário, exigindo a assinatura e carimbo do chefe imediato no livro."], resposta_correta:2, explicacao: "Registro é a anotação dos dados do documento no sistema (antigo livro de protocolo) para controle. A alternativa 'E' descreve a fase de Distribuição, e a 'D' descreve o Arquivamento. A Quadrix joga com essas três definições para causar confusão mental no candidato.", status:0, historico:0 },
{ id:482, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O setor responsável pela expedição enviará uma remessa de ofícios a corretores de imóveis. Assinale a afirmativa correta sobre as boas práticas na fase de expedição de documentos:", imagem:null, alternativas:["A) A expedição envolve apenas o envio via Correios (postal), excluindo-se o envio digital ou por mensageiro interno.","B) Antes do envio, o setor deve realizar a triagem de saída, verificando se o documento possui assinatura da autoridade e se os anexos citados estão presentes.","C) O registro de saída deve omitir o nome do destinatário para garantir a aplicação irrestrita da Lei Geral de Proteção de Dados (LGPD).","D) Correspondências devolvidas pelos Correios devem ser incineradas sumariamente para manter o fluxo físico organizado na recepção.","E) A triagem de saída foi um procedimento eliminado pelas normativas recentes para agilizar a prestação do serviço público."], resposta_correta:1, explicacao: "A triagem de saída é essencial para não enviar um envelope vazio ou sem assinatura. O erro da 'C' é usar a LGPD como distrator para justificar a falta de registro (absurdo). Dica do especialista: a Quadrix usa 'LGPD' em várias matérias fora de contexto para atrair os incautos.", status:0, historico:0 },
{ id:483, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise as assertivas sobre as movimentações protocolares: I. A 'Distribuição' é a entrega dos documentos aos setores internos do próprio órgão. II. A 'Expedição' é o envio de documentos oficiais para pessoas ou órgãos externos. III. A 'Redistribuição' ocorre invariavelmente quando um documento externo é devolvido pelos Correios. Está(ão) correta(s):", imagem:null, alternativas:["A) I e II.","B) II e III.","C) I e III.","D) Apenas II.","E) I, II e III."], resposta_correta:0, explicacao: "A assertiva III é falsa. 'Redistribuição' é o repasse de um documento de um setor INTERNO para outro setor INTERNO (ex: Fiscalização percebe que o caso é de Cobrança e redistribui). A banca usa a palavra absoluta 'invariavelmente' para vincular a um conceito errado (devolução dos Correios).", status:0, historico:0 },
{ id:484, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um Conselho optou por descentralizar o protocolo, criando protocolos setoriais em cada departamento. Do ponto de vista administrativo, o uso de fluxos descentralizados de protocolo tem como desvantagem potencial:", imagem:null, alternativas:["A) A lentidão extrema no atendimento direto e primário ao cidadão nas delegacias regionais.","B) A dificuldade de padronização dos registros e a perda de controle global sobre a tramitação dos processos pela cúpula.","C) O aumento do tempo de deslocamento físico dos documentos entre a recepção central e a mesa do servidor.","D) A impossibilidade legal de uso de sistemas informatizados de Gestão Eletrônica de Documentos (GED).","E) A total eliminação da fase de autuação, tornando os processos ilegais e sem capa identificadora."], resposta_correta:1, explicacao: "A descentralização acelera o fluxo local (derrubando a 'C' e 'A'), mas o seu calcanhar de Aquiles é a dificuldade de manter um padrão e um controle global centralizado. A Quadrix cria desvantagens irreais e absurdas (como 'impossibilidade legal' ou 'ilegalidade do processo') para preencher os distratores.", status:0, historico:0 },
{ id:485, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Gestão de Documentos (Arquivologia)", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um corretor responde a um processo ético-disciplinar no CRECI e, posteriormente, protocoliza um novo requerimento sobre o exato mesmo tema. O diretor decide juntar os dois processos de forma DEFINITIVA. A técnica protocolar correta para essa juntada em caráter permanente é a:", imagem:null, alternativas:["A) Apensação subsidiária.","B) Anexação processual.","C) Autuação em apenso.","D) Desentranhamento sequencial.","E) Reconstituição de autos."], resposta_correta:1, explicacao: "Anexação é a juntada DEFINITIVA (o processo secundário é incorporado ao principal e perde a capa). Apensação é a juntada PROVISÓRIA (processos andam amarrados, mas mantêm suas capas e numerações independentes). É a questão de arquivo/protocolo mais cobrada por esta banca.", status:0, historico:0 },
{ id:486, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Gestão de Documentos (Arquivologia)", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Durante a autuação de um processo administrativo físico, o servidor comete um erro na numeração de uma das folhas. Segundo as normas arquivísticas gerais, o procedimento correto a adotar é:", imagem:null, alternativas:["A) Arrancar a folha errada imediatamente e solicitar que o corretor emita o documento novamente do zero.","B) Usar corretivo líquido de forma abundante para apagar o erro e reescrever o número correto por cima.","C) Cancelar o número errado com um traço (ou 'X'), escrever o número correto ao lado ou acima e apor sua rubrica.","D) Deixar o número errado como está e passar a numerar com letras do alfabeto (A, B, C) a partir daquela página.","E) Encerrar o volume processual naquele momento e abrir um volume secundário para esconder a falha."], resposta_correta:2, explicacao: "A regra sagrada do processo público: não se usa corretivo e não se arranca folha. O erro é inutilizado com um traço e o servidor se identifica (rubrica). A banca Quadrix testa o 'bom senso' administrativo, oferecendo alternativas esdrúxulas (arrancar folha, usar corretivo líquido).", status:0, historico:0 },
{ id:487, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O assistente recebe um malote contendo: ofícios ostensivos do COFECI, processos sigilosos de fiscalização e correspondências particulares nominais a alguns servidores (como contas de luz). O procedimento inicial correto a ser adotado para as correspondências PARTICULARES é:", imagem:null, alternativas:["A) Abri-las, carimbar a data do conselho, ler o conteúdo para segurança e enviar ao destinatário.","B) Não abri-las e entregá-las aos destinatários o mais rápido possível, sem necessidade de autuá-las ou registrá-las no sistema do órgão.","C) Devolvê-las aos Correios, pois constitui crime inafiançável receber documento particular na sede de uma autarquia pública.","D) Remetê-las ao setor de Recursos Humanos para que sejam indexadas à ficha funcional do servidor antes da entrega final.","E) Registrar o conteúdo no sistema do CRECI como 'Documento Ostensivo Indireto', para fins de estrita transparência pública."], resposta_correta:1, explicacao: "Correspondência particular (pessoal) não pertence à administração. O protocolo apenas atua como 'carteiro interno': não abre, não lê e não cadastra no sistema oficial. A banca usa a 'transparência pública' (E) ou 'crime inafiançável' (C) como distratores morais poderosos.", status:0, historico:0 },
{ id:488, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A 'Distribuição' (ou tramitação interna) é a fase na qual o documento sai do protocolo e segue para o setor competente. Considerando o princípio do controle na administração, é correto afirmar:", imagem:null, alternativas:["A) Um documento distribuído não pode, sob nenhuma hipótese legal, retornar ao setor de protocolo geral.","B) A distribuição é o ato final da gestão de documentos, substituindo e anulando a necessidade da fase de arquivamento.","C) O sistema de controle de tramitação deve permitir saber exatamente com qual servidor ou em qual setor o documento se encontra no momento da consulta.","D) A entrega do documento no setor de destino deve ser feita de forma verbal e desacompanhada de recibo para agilizar a burocracia.","E) Documentos rotulados como 'urgentes' devem ser distribuídos de forma anônima para evitar pressão de corretores lobistas."], resposta_correta:2, explicacao: "O grande objetivo da fase de trâmite é a rastreabilidade (saber quem está com o documento e onde). A Quadrix utiliza absolutismos para criar alternativas erradas gritantes: 'nenhuma hipótese' (A), anular arquivo (B), 'dispensa recibo' (D) ou distribuição 'anônima' (E).", status:0, historico:0 },
{ id:489, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Atendimento ao Público", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A 'Presteza' é um dos atributos fundamentais da qualidade no atendimento em órgãos públicos. No contexto do CRECI-BA, agir com presteza significa:", imagem:null, alternativas:["A) Atender o corretor com a máxima rapidez possível, mesmo que isso implique suprimir etapas de verificação documental para evitar filas.","B) Demonstrar prontidão, boa vontade e agilidade na prestação do serviço, sem contudo comprometer a precisão e a legalidade do ato.","C) Focar exclusivamente no público externo, visto que as solicitações de colegas de outros setores (público interno) não possuem prazo legal de atendimento.","D) Transferir imediatamente qualquer problema complexo para a chefia superior, garantindo que o tempo de contato com o usuário seja mínimo.","E) Concordar invariavelmente com as solicitações do usuário para evitar desgastes e garantir um atendimento célere."], resposta_correta:1, explicacao: "Presteza é agir com prontidão e zelo, mas NUNCA pulando etapas legais (erro da A). A Quadrix sempre tenta associar 'agilidade' à 'quebra de regras' ou 'subserviência' (erro da E) para pegar candidatos desatentos.", status:0, historico:0 },
{ id:490, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um corretor chega ao balcão de atendimento visivelmente frustrado, relatando que não consegue emitir uma certidão pelo site há dois dias. O servidor, aplicando o conceito de 'Empatia', deve:", imagem:null, alternativas:["A) Concordar que o sistema do conselho é ineficiente e orientá-lo a formalizar uma denúncia contra o setor de TI.","B) Demonstrar pena da situação do corretor e emitir o documento gratuitamente, isentando-o das taxas regimentais.","C) Interromper a fala do usuário para explicar tecnicamente o funcionamento dos servidores de rede do órgão.","D) Colocar-se no lugar do usuário, compreender sua frustração, manter a calma e buscar ativamente a resolução do problema.","E) Ignorar a emoção do usuário e focar exclusivamente no preenchimento silencioso do formulário, demonstrando total frieza profissional."], resposta_correta:3, explicacao: "Empatia é a capacidade de se colocar no lugar do outro e compreender seus sentimentos. O erro da A e B é confundir empatia com quebra de ética corporativa ou 'pena'. A Quadrix usa o verbo 'ignorar' (E) para descrever a falsa ideia de objetividade.", status:0, historico:0 },
{ id:491, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Atendimento ao Público", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Julgue as sentenças com (V) ou (F) sobre o atendimento a públicos internos e externos: ( ) O público interno é composto pelos próprios servidores e departamentos da autarquia; a excelência no trato com eles reflete diretamente na qualidade do serviço prestado ao cidadão. ( ) O princípio da impessoalidade deve ser aplicado rigorosamente no atendimento ao público externo, mas é facultativo nas relações entre o público interno. ( ) O cliente interno é apenas um colega de trabalho, não possuindo o mesmo direito à presteza e cortesia que o corretor de imóveis. A sequência correta é:", imagem:null, alternativas:["A) V, V, F.","B) V, F, F.","C) F, V, V.","D) V, F, V.","E) F, F, F."], resposta_correta:1, explicacao: "A segunda e a terceira são falsas. A impessoalidade (não favorecer/prejudicar por razões pessoais) aplica-se a TODOS, inclusive colegas. E o cliente interno tem total direito à cortesia. A banca adora hierarquizar o público externo como 'superior' ao interno, o que é um erro de gestão.", status:0, historico:0 },
{ id:492, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Atendimento ao Público", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Na rotina de atendimento telefônico de uma repartição pública, algumas expressões demonstram falta de profissionalismo e devem ser evitadas. Assinale a alternativa que apresenta a conduta CORRETA ao transferir uma ligação:", imagem:null, alternativas:["A) Dizer 'Um minutinho, vou passar pro cara da TI', utilizando linguagem coloquial para gerar proximidade.","B) Informar ao usuário o nome e o setor para o qual a ligação será transferida, aguardando sua concordância antes de concluir a ação.","C) Transferir a chamada imediatamente sem avisar o requerente, garantindo a redução do Tempo Médio de Atendimento (TMA).","D) Dizer 'Não é problema meu, vou passar pra quem resolve', deixando clara a divisão de competências.","E) Colocar o usuário em espera por tempo indeterminado até que o setor de destino atenda, sem retornar à linha para dar satisfações."], resposta_correta:1, explicacao: "A etiqueta telefônica exige informar o destino da transferência e evitar gírias ('cara da TI') ou jargões defensivos ('não é problema meu'). A Quadrix pune a alternativa C ('transferir imediatamente sem avisar') porque foca na métrica em detrimento da qualidade humana.", status:0, historico:0 },
{ id:493, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Atendimento ao Público", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise as assertivas sobre os atributos do atendimento: I. A 'Discrição' envolve manter em sigilo as informações particulares e profissionais dos corretores a que o servidor tem acesso. II. A 'Cortesia' exige que o servidor concorde incondicionalmente com as opiniões e demandas do cidadão. III. A 'Objetividade' significa ir direto ao ponto, não permitindo que o usuário tire dúvidas adicionais. Está(ão) correta(s):", imagem:null, alternativas:["A) Apenas a I.","B) Apenas a II.","C) Apenas I e III.","D) Apenas II e III.","E) I, II e III."], resposta_correta:0, explicacao: "A II é falsa pois cortesia é educação e respeito, não subserviência ou concordância incondicional. A III é falsa pois objetividade é ser claro e focado, mas sem impedir o esclarecimento de dúvidas. A Quadrix distorce o conceito de objetividade para fazê-lo parecer grosseria.", status:0, historico:0 },
{ id:494, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A comunicação não verbal corresponde à maior parte do impacto de uma mensagem no atendimento presencial. Sobre a postura profissional no balcão do CRECI, assinale a atitude inadequada:", imagem:null, alternativas:["A) Manter contato visual com o interlocutor, demonstrando atenção e interesse.","B) Adotar uma postura ereta e voltada para o usuário, sinalizando receptividade.","C) Cruzar os braços e evitar olhar nos olhos para demonstrar concentração exclusiva no raciocínio lógico.","D) Apresentar expressões faciais condizentes com a seriedade ou empatia que a situação exige.","E) Gesticular de forma moderada, evitando movimentos bruscos que possam indicar impaciência."], resposta_correta:2, explicacao: "Braços cruzados e falta de contato visual são barreiras não verbais clássicas que indicam distanciamento, defensiva ou desinteresse. A Quadrix tenta justificar essa postura errada com uma desculpa intelectual ('concentração exclusiva').", status:0, historico:0 },
{ id:495, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No contexto das relações interpessoais no trabalho, a comunicação assertiva é o meio-termo ideal entre a passividade e a agressividade. Um servidor assertivo diante de uma ofensa de um usuário:", imagem:null, alternativas:["A) Oculta seu desconforto e atende o usuário chorando silenciosamente para não gerar conflitos.","B) Retribui a ofensa no mesmo tom para preservar a autoridade moral da instituição pública.","C) Expressa seus limites com firmeza e respeito, exigindo urbanidade para dar prosseguimento ao atendimento.","D) Abandona o balcão imediatamente e se recusa a voltar ao trabalho pelo resto do expediente.","E) Concorda que o órgão é falho para acalmar o usuário, assumindo a culpa institucional injustamente."], resposta_correta:2, explicacao: "A assertividade envolve impor limites e defender seus direitos (exigir respeito) de forma educada, direta e não agressiva. A passividade (A e E) e a agressividade (B e D) são comportamentos disfuncionais amplamente cobrados em provas.", status:0, historico:0 },
{ id:496, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um corretor exige prioridade no atendimento alegando ter amizade pessoal com o Presidente do CRECI-BA. O assistente administrativo, atuando com ética e qualidade, deve:", imagem:null, alternativas:["A) Atendê-lo imediatamente para evitar retaliações funcionais, preservando seu próprio cargo.","B) Informar com polidez que o atendimento segue a ordem de chegada e as prioridades legais, independentemente de relações pessoais.","C) Debochar da situação em voz alta para que os demais usuários na fila julguem o corretor infrator.","D) Exigir que o corretor ligue para o presidente ali mesmo para comprovar a suposta amizade.","E) Encaminhar o corretor para a Ouvidoria por tentativa de suborno e trancar as portas do setor."], resposta_correta:1, explicacao: "A resposta correta aplica o Princípio da Impessoalidade aliada à Cortesia e Firmeza. A Quadrix cria alternativas extremas (subserviência na A, agressividade na C e D, exagero na E) para testar o equilíbrio do candidato perante 'carteiradas'.", status:0, historico:0 },
{ id:497, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A 'Apresentação Pessoal' é um dos itens avaliados na qualidade do serviço público presencial. Sobre este aspecto, é correto afirmar:", imagem:null, alternativas:["A) Refere-se exclusivamente ao uso de roupas de grife ou de alto valor agregado financeiro.","B) Um servidor com boa apresentação pessoal é aquele que adota os modismos estéticos mais recentes.","C) Envolve a asseio corporal, o uso de trajes adequados ao ambiente de trabalho e, se fornecido, o uso correto do uniforme.","D) A apresentação pessoal não tem qualquer impacto na credibilidade da informação transmitida ao cidadão.","E) Exige que as mulheres usem invariavelmente maquiagem forte e os homens, terno e gravata, independentemente da função."], resposta_correta:2, explicacao: "Apresentação pessoal é adequação (bom senso, higiene, discrição e uniforme). O erro da banca é sempre usar palavras como 'exclusivamente' (A) ou 'invariavelmente' (E) para associar apresentação à ostentação financeira.", status:0, historico:0 },
{ id:498, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Atendimento ao Público", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Julgue as sentenças (V) ou (F) referentes aos atributos do atendimento: ( ) A comunicabilidade é a capacidade de transmitir ideias de forma clara, garantindo que o receptor compreenda a mensagem. ( ) A tolerância no atendimento exige que o servidor suporte passivamente abusos verbais e agressões físicas. ( ) O interesse manifesta-se quando o servidor busca genuinamente solucionar a demanda, em vez de atuar como mero repassador de papéis. A sequência correta é:", imagem:null, alternativas:["A) V, V, F.","B) V, F, V.","C) F, F, V.","D) V, V, V.","E) F, V, F."], resposta_correta:1, explicacao: "A segunda é falsa. Tolerância significa ter paciência com ritmos diferentes, dificuldades de compreensão e diversidades do público, mas JAMAIS significa aceitar abusos verbais ou físicos (o que exige intervenção policial/segurança).", status:0, historico:0 },
{ id:499, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Atendimento ao Público", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No contexto da excelência em serviços, o conceito de 'Cadeia de Clientes Internos' sugere que:", imagem:null, alternativas:["A) O atendimento de má qualidade prestado pelo setor de RH à equipe de fiscalização não afeta o serviço prestado ao corretor na rua.","B) O cidadão externo é o único cliente real; os servidores são apenas recursos humanos descartáveis.","C) Todo servidor é, ao mesmo tempo, fornecedor de serviços para uma etapa e cliente interno de outra, impactando o resultado final do órgão.","D) A comunicação entre os setores deve ser bloqueada para evitar vazamento de dados estratégicos.","E) Clientes internos pagam taxas administrativas diretamente ao conselho para receberem seus salários em dia."], resposta_correta:2, explicacao: "A cadeia de clientes internos significa que o trabalho de um (fornecedor) é o insumo do outro (cliente). Se a TI falha com o Atendimento, o Atendimento falhará com o Cidadão. A Quadrix tenta isolar os setores nas opções A e B.", status:0, historico:0 },
{ id:500, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um assistente atende 50 corretores por dia gastando muito papel, errando dados que geram retrabalho e sem resolver o problema de nenhum deles definitivamente. Outro atende 20 corretores por dia, utilizando o sistema perfeitamente e resolvendo todas as demandas. Comparando os dois sob a ótica da qualidade, o primeiro servidor foi:", imagem:null, alternativas:["A) Eficaz e Eficiente.","B) Apenas Eficaz, pois atingiu um número alto.","C) Ineficiente (desperdício) e Ineficaz (não resolveu).","D) Eficiente (foi rápido) e Eficaz (gerou retrabalho).","E) Efetivo, pois impactou muitas pessoas na fila."], resposta_correta:2, explicacao: "Eficiência é o uso racional de recursos (o 1º gastou muito papel e errou). Eficácia é o atingimento da meta/resolução (o 1º não resolveu). Logo, ele foi ineficiente e ineficaz. A Quadrix tenta associar 'rapidez' automaticamente a eficiência.", status:0, historico:0 },
{ id:501, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Atendimento ao Público", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Considere as normas de etiqueta para atendimento telefônico institucional. É considerado um ERRO técnico:", imagem:null, alternativas:["A) Atender o telefone prontamente, preferencialmente até o terceiro toque.","B) Identificar a instituição, o próprio nome e proferir uma saudação inicial (Ex: 'CRECI Bahia, João, bom dia').","C) Sorrir durante a fala, pois a expressão facial influencia o tom de voz percebido pelo interlocutor.","D) Utilizar o botão de 'Mudo' ou 'Espera' ao consultar informações com um colega, em vez de tapar o bocal com a mão.","E) Mastigar balas ou gomas de mascar durante a ligação para manter o hálito fresco e a voz relaxada."], resposta_correta:4, explicacao: "Mastigar, comer ou beber durante o atendimento telefônico é uma falta grave de etiqueta e prejudica a dicção (comunicabilidade). A banca mistura 'hálito fresco', que é válido no presencial, para justificar o erro no telefone.", status:0, historico:0 },
{ id:502, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Atendimento ao Público", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A 'Escuta Ativa' é uma técnica de comunicação fundamental no atendimento ao público. Ela ocorre quando o servidor:", imagem:null, alternativas:["A) Finge prestar atenção enquanto digita uma mensagem no celular pessoal, para otimizar o tempo.","B) Ouve pacientemente, formula perguntas para esclarecer pontos dúbios e confirma com o usuário se compreendeu a real necessidade.","C) Escuta apenas as primeiras palavras do corretor e já o interrompe, entregando um formulário padrão.","D) Ouve o relato do cidadão rebatendo mentalmente cada argumento, preparando-se apenas para vencer a discussão.","E) Exige que o usuário escreva tudo em um papel, pois a escuta verbal é irrelevante no serviço público moderno."], resposta_correta:1, explicacao: "A Escuta Ativa requer atenção plena, validação (feedback) e real interesse na mensagem do outro, não apenas ouvir fisiologicamente. A Quadrix tenta disfarçar a falta de escuta com 'otimização de tempo' (A e C).", status:0, historico:0 },
{ id:503, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise: I. Os conflitos no ambiente de trabalho são invariavelmente destrutivos e devem ser suprimidos pela chefia. II. O preconceito e os estereótipos são barreiras graves às relações interpessoais saudáveis. III. A empatia colabora para a redução de atritos com clientes internos e externos. Está(ão) correta(s):", imagem:null, alternativas:["A) Apenas a II.","B) Apenas I e II.","C) Apenas II e III.","D) Apenas I e III.","E) I, II e III."], resposta_correta:2, explicacao: "A I é falsa. O conflito, quando gerenciado (conflito funcional), pode gerar inovação, debates construtivos e quebra de estagnação. A palavra 'invariavelmente' e 'suprimidos' são os gatilhos de erro Quadrix.", status:0, historico:0 },
{ id:504, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Atendimento ao Público", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Na gestão da qualidade em serviços, a reclamação de um corretor de imóveis deve ser encarada pela autarquia como:", imagem:null, alternativas:["A) Um ataque pessoal e direto à moral do servidor que o atendeu.","B) Um incômodo burocrático que deve ser desestimulado mediante a cobrança de taxas de recurso.","C) Uma oportunidade de melhoria (feedback), revelando falhas nos processos que podem ser corrigidas.","D) Uma prova irrefutável de que o serviço público é estruturalmente inferior ao setor privado.","E) Uma falha na segurança institucional que justifica a expulsão imediata do cidadão da sede."], resposta_correta:2, explicacao: "Na visão da qualidade total, a reclamação é um 'presente' (feedback negativo) que aponta onde o serviço falhou, permitindo a correção sistêmica. A banca sempre tenta colocar a reclamação como algo que deve ser punido ou ocultado.", status:0, historico:0 },
{ id:505, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Durante seu intervalo de almoço na copa do CRECI, um assistente administrativo comenta em voz alta com colegas sobre a enorme dívida financeira e as infrações éticas de um famoso corretor da cidade. Essa conduta fere diretamente o atributo de qualidade conhecido como:", imagem:null, alternativas:["A) Objetividade.","B) Tolerância.","C) Presteza.","D) Discrição.","E) Comunicabilidade."], resposta_correta:3, explicacao: "A discrição proíbe expor, comentar ou fofocar sobre a vida privada, financeira ou profissional dos usuários a que se tem acesso devido ao cargo. A Quadrix cria o cenário do 'intervalo' para fazer o candidato achar que fora do balcão a regra não vale.", status:0, historico:0 },
{ id:506, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No atendimento presencial, a legislação garante prioridade para idosos, gestantes, lactantes e pessoas com deficiência. A aplicação desse atendimento prioritário é a materialização do princípio ético/administrativo da:", imagem:null, alternativas:["A) Eficiência financeira, pois esses usuários pagam anuidades mais caras.","B) Equidade, que consiste em tratar desigualmente os desiguais, na medida de suas desigualdades, para nivelar o acesso.","C) Parcialidade ilícita, visto que a Constituição exige igualdade absoluta sem qualquer distinção.","D) Segregação social compensatória, adotada provisoriamente apenas nos meses de alta demanda.","E) Comunicabilidade restrita, visto que essas pessoas não podem utilizar o portal digital da autarquia."], resposta_correta:1, explicacao: "A igualdade formal (todos na mesma fila) difere da Equidade (Igualdade Material), que reconhece as limitações e dá prioridade para igualar as condições de acesso. A banca tenta tratar a prioridade legal como 'Parcialidade' (C).", status:0, historico:0 },
{ id:507, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um servidor está com sérios problemas financeiros e familiares. Ao chegar para trabalhar no balcão do conselho, ele deve:", imagem:null, alternativas:["A) Desabafar seus problemas com os primeiros usuários do dia para gerar conexão e desculpar-se pela lentidão.","B) Descontar sua frustração nos processos, agilizando-os sem ler, para ir embora mais cedo.","C) Manter a inteligência emocional e a compartimentação, impedindo que seus problemas pessoais afetem a qualidade do serviço e o trato com o cidadão.","D) Transferir todos os seus atendimentos para os colegas alegando incapacidade civil momentânea não atestada por médico.","E) Informar ao público, com voz ríspida, que não está em um bom dia e exigir silêncio absoluto no recinto."], resposta_correta:2, explicacao: "A compartimentação (separar o pessoal do profissional) e o autocontrole (inteligência emocional) são pilares da postura profissional. A Quadrix usa a alternativa A ('desabafar para gerar conexão') como um distrator fortíssimo apelando para a 'humanização' distorcida.", status:0, historico:0 },
{ id:508, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Atendimento ao Público", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Julgue as sentenças (V) ou (F) relativas às falhas no atendimento: ( ) A robotização no atendimento (uso de roteiros decorados sem empatia) gera distanciamento e insatisfação do usuário. ( ) O uso de jargões técnicos complexos demonstra grande competência e facilita imensamente a comunicação com o público leigo. ( ) O jogo de empurra (transferir o usuário de setor em setor sem resolver o problema) é uma violação do princípio da eficiência e do foco no cidadão. A sequência correta é:", imagem:null, alternativas:["A) V, V, F.","B) V, F, V.","C) F, F, V.","D) V, F, F.","E) F, V, V."], resposta_correta:1, explicacao: "A segunda é falsa. Jargões técnicos com público leigo caracterizam ruído (barreira semântica) e violam a comunicabilidade. A Quadrix sempre afirma que 'falar difícil é bom para impor autoridade'.", status:0, historico:0 },
{ id:509, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Atendimento ao Público", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um corretor liga para a autarquia procurando informações específicas sobre um departamento que está em horário de almoço. A atitude que demonstra MAIOR profissionalismo e atenção por parte da telefonista/recepcionista é:", imagem:null, alternativas:["A) Dizer 'Não tem ninguém lá, ligue depois' e bater o telefone.","B) Orientar: 'Eles saíram para almoçar, o senhor quer aguardar na linha por uma hora?'.","C) Informar a ausência temporária do setor e oferecer-se para anotar o recado, o nome e o telefone do usuário, garantindo o retorno da ligação.","D) Fornecer o número do celular pessoal do analista do departamento para que o cidadão o incomode no almoço.","E) Mentir dizendo que o setor foi extinto para evitar que o corretor ligue novamente naquele dia."], resposta_correta:2, explicacao: "No atendimento de excelência, não se deixa o problema com o cliente. A proatividade em anotar o recado e assumir o compromisso do retorno ('follow-up') é a atitude correta. As demais violam a presteza, a discrição (D) ou a verdade (E).", status:0, historico:0 },
{ id:510, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No contexto do atendimento público, agir com 'Objetividade' é muitas vezes confundido com agir de forma grosseira. Na verdade, ser objetivo significa:", imagem:null, alternativas:["A) Reduzir as respostas a 'sim' ou 'não', recusando-se a dar maiores explicações legais.","B) Atender o cidadão com foco na resolução exata de sua demanda, evitando rodeios desnecessários, mas mantendo a clareza e a polidez.","C) Ignorar os cumprimentos de bom dia para focar apenas na digitação da matrícula do corretor.","D) Encaminhar o usuário sempre para o portal da internet, recusando o atendimento presencial sob a justificativa de economia de tempo.","E) Obrigar o cidadão a resumir sua história em apenas dez segundos, cronometrados pelo servidor."], resposta_correta:1, explicacao: "Objetividade é ir direto ao ponto (foco na demanda) sem perder a educação. A Quadrix cria alternativas (A, C e E) que descrevem grosseria, rispidez e arrogância, maquiando-as com o nome de 'objetividade'.", status:0, historico:0 },
{ id:511, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Atendimento ao Público", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Na gestão contemporânea, um serviço público que atinge o nível de 'Excelência' (Qualidade Total) é aquele que:", imagem:null, alternativas:["A) Apenas cumpre o mínimo estipulado na lei, sem qualquer valor agregado.","B) Exige que o usuário elogie o servidor na ouvidoria sob pena de não entregar o documento.","C) Supera as expectativas do usuário, antecipando-se às suas necessidades e entregando um serviço eficiente e humanizado.","D) Transfere a execução do trabalho para o próprio cidadão, através de totens de autoatendimento complexos e sem suporte.","E) Elimina as filas de espera mediante a aprovação indiscriminada de todos os requerimentos ilegais."], resposta_correta:2, explicacao: "Excelência não é apenas 'não errar' (fazer o básico), mas 'superar a expectativa' e 'surpreender positivamente' (fazer além com proatividade). A Quadrix opõe a excelência à limitação burocrática do item A.", status:0, historico:0 },
{ id:512, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Atendimento ao Público", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise: I. O treinamento de habilidades comportamentais (soft skills) é tão importante quanto o treinamento técnico (hard skills) para os servidores de atendimento. II. A motivação do público interno é irrelevante, desde que existam câmeras vigiando o atendimento no balcão. III. Conflitos mal resolvidos entre departamentos (ex: RH x Financeiro) não afetam a percepção de qualidade do cidadão lá na ponta. Está(ão) correta(s):", imagem:null, alternativas:["A) Apenas a I.","B) Apenas a II.","C) Apenas I e III.","D) Apenas II e III.","E) I, II e III."], resposta_correta:0, explicacao: "A II é falsa, pois o controle coercitivo (câmeras) não substitui a motivação real, e funcionários desmotivados atendem mal. A III é falsa pois falhas sistêmicas internas SEMPRE vazam para o cliente externo (atrasos, erros).", status:0, historico:0 },
{ id:513, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Durante a triagem na recepção do CRECI-BA, a atendente percebe que um idoso está muito confuso sobre qual documento preencher. A atitude proativa que reflete 'Atenção e Presteza' é:", imagem:null, alternativas:["A) Apontar para o painel de avisos na parede e pedir que ele leia com mais atenção.","B) Exigir que ele retorne outro dia acompanhado de um advogado para evitar atrasos na fila.","C) Sair de sua posição passiva, ler os documentos com o idoso, identificar a necessidade e orientá-lo passo a passo no preenchimento correto.","D) Fazer o preenchimento por ele, assinando o documento em seu lugar para agilizar o fluxo, assumindo falsidade ideológica justificada pela boa ação.","E) Ignorar a confusão do idoso e chamar a próxima senha do painel eletrônico."], resposta_correta:2, explicacao: "A proatividade correta exige guiar e orientar (C). O erro da D é cometer uma ilegalidade (assinar pelo outro) sob a desculpa de presteza, que é uma das 'pegadinhas' éticas mais perigosas da banca.", status:0, historico:0 },
{ id:514, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um corretor tem um pedido de inscrição indeferido por falta de diploma válido e insiste que o servidor deve 'dar um jeitinho'. A resposta ASSERTIVA do servidor é:", imagem:null, alternativas:["A) 'Sinto muito, eu até queria te ajudar, mas meu chefe é muito chato e não deixa.' (Terceiriza a culpa)","B) 'Compreendo a sua urgência, senhor, mas a lei exige o diploma para o registro. Assim que trouxer o documento, liberaremos sua inscrição.' (Firmeza e empatia)","C) 'Você acha que eu vou perder meu cargo por sua causa? Saia daqui agora!' (Agressividade)","D) 'Vou protocolar aqui e a gente vê o que acontece, não se preocupe.' (Falsa esperança)","E) 'Se o senhor quiser, pode tentar falar com o diretor, às vezes ele libera.' (Omissão de responsabilidade)"], resposta_correta:1, explicacao: "A assertividade defende a regra legal assumindo a responsabilidade da instituição, com educação, sem terceirizar culpas (A e E), sem agressão (C) e sem dar falsas esperanças (D).", status:0, historico:0 },
{ id:515, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Atendimento ao Público", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O conceito de 'Padronização do Atendimento' em autarquias públicas significa:", imagem:null, alternativas:["A) Tratar todos os cidadãos como números, abolindo a personalização e o contato visual.","B) Definir procedimentos, roteiros e níveis mínimos de qualidade que garantam um serviço uniforme e eficiente, independentemente do servidor que está no balcão.","C) Decorar frases prontas ('telemarketing robótico') que impedem o servidor de pensar em soluções fora do script, mesmo quando a lei permite.","D) Usar o mesmo tom de voz agressivo para todos os contribuintes inadimplentes, garantindo igualdade no tratamento punitivo.","E) Obrigação de usar exclusivamente sistemas eletrônicos, eliminando por completo o atendimento humano presencial."], resposta_correta:1, explicacao: "Padronizar é criar diretrizes de qualidade para que o serviço não dependa do 'humor' do servidor no dia. A Quadrix tenta ligar padronização a 'robotização' (A e C) ou a 'eliminação do humano' (E).", status:0, historico:0 },
{ id:516, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Julgue (V) ou (F): ( ) Fazer o uso de gírias e expressões chulas gera proximidade e é altamente recomendado para quebrar o gelo com o corretor. ( ) O uso de aparelho celular pessoal durante o atendimento presencial demonstra extrema falta de interesse e cortesia com o cidadão. ( ) Separar o atendimento (resolução técnica) do tratamento (forma humana como a pessoa é recebida) é o primeiro passo para entender a qualidade total. A sequência correta é:", imagem:null, alternativas:["A) V, V, F.","B) V, F, V.","C) F, V, F.","D) F, V, V.","E) F, F, V."], resposta_correta:3, explicacao: "A primeira é falsa: gírias/expressões chulas ferem a formalidade e a comunicabilidade profissional. O uso de celular desrespeita o usuário (V). A distinção entre atendimento (técnica) e tratamento (empatia) é vital em serviços (V).", status:0, historico:0 },
{ id:517, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No fechamento do expediente, com o sistema lento e uma fila imensa, o servidor começa a demonstrar irritação, suspirando alto e batendo os carimbos com força. Esse comportamento evidencia uma falha grave na sua:", imagem:null, alternativas:["A) Habilidade técnica de digitação avançada.","B) Memória institucional sobre os fluxos processuais.","C) Inteligência emocional e autocontrole frente à pressão do ambiente.","D) Formação acadêmica em Direito Administrativo.","E) Capacidade de usar softwares de gestão documental."], resposta_correta:2, explicacao: "O descontrole físico e sonoro (suspiros, bater carimbos) sinaliza falta de controle emocional (Inteligência Emocional de Goleman), afetando a percepção de qualidade do cliente, mesmo que o servidor seja tecnicamente brilhante.", status:0, historico:0 },
{ id:518, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No setor de protocolo, um assistente possui três tarefas simultâneas: atender um corretor no balcão, responder um e-mail com prazo de 2 dias e arquivar caixas antigas. A priorização correta, sob a ótica do atendimento ao público, deve focar primordialmente no(a):", imagem:null, alternativas:["A) Arquivamento das caixas, para deixar a mesa visualmente bonita para o diretor.","B) Correção dos e-mails, pois a comunicação escrita deixa registros legais contra a autarquia.","C) Atendimento ao cidadão no balcão, visto que o cliente presencial exige presteza imediata e contato visual ininterrupto.","D) Divisão exata do tempo, fazendo as três atividades ao mesmo tempo (multitarefa absoluta) para ganhar eficiência quantitativa.","E) Suspensão de todas as tarefas para solicitar reforço humano antes de tomar qualquer atitude."], resposta_correta:2, explicacao: "Quem está presente na sua frente tem prioridade absoluta de atenção (presteza e cortesia). Multitarefas extremas (D) enquanto atende alguém geram percepção de abandono e descaso no cidadão. A banca Quadrix testa o 'bom senso' administrativo.", status:0, historico:0 },
{ id:519, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A 'Janela de Johari' é uma ferramenta clássica para entender a eficácia no comportamento interpessoal. Julgue as sentenças (V) ou (F): ( ) A 'Área Aberta' representa comportamentos e sentimentos conhecidos pelo próprio indivíduo e pelos outros membros da equipe. ( ) A 'Área Cega' abrange as características que o indivíduo conhece perfeitamente sobre si, mas oculta deliberadamente dos colegas de trabalho. ( ) O processo de dar e receber feedback tem como objetivo primordial ampliar a Área Aberta e reduzir as demais áreas. A sequência correta é:", imagem:null, alternativas:["A) V, V, F.","B) V, F, V.","C) F, V, F.","D) F, F, V.","E) V, V, V."], resposta_correta:1, explicacao: "A segunda é Falsa porque a Área Cega é aquilo que os OUTROS veem em você, mas VOCÊ NÃO VÊ (ex: um tique nervoso, uma postura arrogante). O que você conhece e esconde é a 'Área Secreta/Oculta'. A Quadrix inverte essas duas áreas sistematicamente.", status:0, historico:0 },
{ id:520, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um analista do CRECI-BA, ao cometer um erro grave na formatação de uma planilha, afirma imediatamente que 'o erro só ocorreu porque a equipe de TI não atualizou o software', recusando-se a assumir a falha. Do ponto de vista do comportamento interpessoal, ele utilizou um mecanismo de defesa conhecido como:", imagem:null, alternativas:["A) Racionalização.","B) Formação Reativa.","C) Projeção.","D) Sublimação.","E) Introjeção."], resposta_correta:2, explicacao: "A Projeção ocorre quando o indivíduo atribui aos outros (ou ao ambiente) a culpa, os defeitos ou os sentimentos inaceitáveis que, na verdade, são seus. A banca usa historinhas de 'terceirização de culpa' para cobrar esse mecanismo freudiano clássico.", status:0, historico:0 },
{ id:521, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No desenvolvimento de equipes, é crucial distinguir Empatia de Simpatia. Assinale a alternativa que define CORRETAMENTE a Empatia no contexto profissional:", imagem:null, alternativas:["A) É o envolvimento emocional profundo e o sofrimento conjunto com o problema do colega.","B) É a capacidade cognitiva e afetiva de compreender a perspectiva e os sentimentos do outro, sem necessariamente concordar ou sofrer a mesma dor.","C) É a concordância absoluta com as opiniões dos demais membros da equipe para evitar o surgimento de conflitos.","D) É o ato de sentir pena do colega de trabalho e assumir a execução das tarefas dele para aliviá-lo da pressão.","E) É um traço de personalidade estático, impossível de ser desenvolvido por meio de treinamentos organizacionais."], resposta_correta:1, explicacao: "A empatia é a compreensão do quadro de referência do outro (colocar-se no lugar), mantendo a isenção objetiva. A opção A define 'Simpatia/Compaixão'. A opção D define 'Piedade'. A Quadrix tenta fazer o candidato achar que empatia exige 'sofrer junto'.", status:0, historico:0 },
{ id:522, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise as atitudes de um servidor ao receber um feedback negativo do seu chefe: I. Escuta ativamente até o final sem interromper, mesmo discordando inicialmente. II. Concorda imediatamente com tudo para encerrar a conversa rápido e evitar atritos. III. Faz perguntas abertas (Ex: 'Você pode me dar um exemplo?') para compreender melhor a crítica. Representa(m) 'Comportamento Receptivo':", imagem:null, alternativas:["A) Apenas a I.","B) Apenas a II.","C) Apenas I e III.","D) Apenas II e III.","E) I, II e III."], resposta_correta:2, explicacao: "O comportamento receptivo envolve escuta ativa e busca por esclarecimento (I e III). A atitude II reflete passividade/fuga (comportamento defensivo disfarçado), e não receptividade genuína. A banca usa a 'fuga de conflito' como distrator positivo.", status:0, historico:0 },
{ id:523, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A eficácia do trabalho em equipe é frequentemente associada à 'Sinergia'. Em termos de comportamento interpessoal e produtividade, a sinergia ocorre quando:", imagem:null, alternativas:["A) Todos os membros do grupo realizam exatamente a mesma tarefa simultaneamente para ganhar velocidade.","B) A soma dos esforços individuais isolados é exatamente igual ao resultado alcançado pelo grupo.","C) A interação e a colaboração entre os membros produzem um resultado maior e melhor do que a soma das partes individuais (2+2=5).","D) O líder centraliza todas as decisões, garantindo que não haja divergência de opiniões.","E) A equipe é isenta de qualquer tipo de conflito ou debate ideológico durante sua existência."], resposta_correta:2, explicacao: "Sinergia é o fenômeno onde o 'todo é maior que a soma das partes' devido à colaboração e ao complemento de habilidades. A alternativa B descreve o trabalho em grupo simples (sem sinergia). A Quadrix sempre usa a metáfora matemática para sinergia.", status:0, historico:0 },
{ id:524, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O modelo dos 'Cinco Grandes Fatores' (Big Five) é amplamente utilizado para mapear personalidades nas equipes. O fator que descreve o grau em que uma pessoa é organizada, disciplinada, confiável e orientada para objetivos é denominado:", imagem:null, alternativas:["A) Extroversão.","B) Afabilidade (ou Agradabilidade).","C) Neuroticismo (ou Estabilidade Emocional).","D) Conscienciosidade (ou Realização).","E) Abertura à Experiência."], resposta_correta:3, explicacao: "Conscienciosidade é o traço do foco, da disciplina e do dever (altamente desejado no serviço público). A banca cobra a literalidade desse modelo psicológico que substituiu teorias antigas nos editais modernos.", status:0, historico:0 },
{ id:525, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Sobre o processo de 'Feedback' nas relações interpessoais no CRECI, assinale a alternativa que apresenta uma característica do feedback CONSTRUTIVO:", imagem:null, alternativas:["A) Foca na personalidade do indivíduo (Ex: 'Você é um irresponsável').","B) É generalista e vago, para não ofender diretamente o servidor (Ex: 'Seu trabalho está meio ruim').","C) É descritivo e focado em comportamentos observáveis (Ex: 'Você entregou o relatório com 3 dias de atraso').","D) É acumulado ao longo do ano para ser entregue de uma só vez na avaliação de desempenho.","E) É dado invariavelmente em público para que sirva de exemplo pedagógico aos demais."], resposta_correta:2, explicacao: "O feedback eficaz deve atacar o comportamento (o que a pessoa fez), e nunca a identidade (o que a pessoa é - opção A). Além disso, deve ser específico, imediato e preferencialmente no particular. Inversões clássicas da banca.", status:0, historico:0 },
{ id:526, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A técnica da 'Paráfrase' é um excelente recurso de eficácia interpessoal utilizado para demonstrar escuta ativa. Parafrasear um colega significa:", imagem:null, alternativas:["A) Repetir exatamente as mesmas palavras dele, como um eco, para provar que estava prestando atenção.","B) Expressar a ideia central do que ele acabou de dizer utilizando suas próprias palavras, validando a compreensão.","C) Interrompê-lo no meio da frase para antecipar a conclusão de seu raciocínio, ganhando tempo.","D) Ignorar o conteúdo verbal e focar exclusivamente na linguagem corporal demonstrada por ele.","E) Discordar frontalmente da ideia proposta antes mesmo que ele termine a explicação."], resposta_correta:1, explicacao: "Paráfrase não é repetir como um papagaio (erro da A), mas sim reformular a ideia central para checar se o entendimento foi correto ('Então, o que você quer dizer é que...'). Ferramenta essencial de empatia cobrada pela Quadrix.", status:0, historico:0 },
{ id:527, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Julgue as sentenças (V) ou (F) baseando-se nos estudos de Fela Moscovici sobre Competência Interpessoal: ( ) A competência interpessoal consiste na habilidade de lidar eficazmente com relações interpessoais e lidar com outras pessoas de forma adequada. ( ) É uma habilidade inata, determinada exclusivamente pela genética, impossível de ser aprimorada por treinamento. ( ) Compreende duas dimensões: percepção (entender a si e ao outro) e habilidade comportamental (agir adequadamente). A sequência correta é:", imagem:null, alternativas:["A) V, V, F.","B) V, F, V.","C) F, F, V.","D) V, V, V.","E) F, V, F."], resposta_correta:1, explicacao: "A segunda é falsa porque competência interpessoal (soft skill) pode e DEVE ser treinada e aprimorada (não é destino genético). A Quadrix insere a palavra 'exclusivamente' para amarrar o candidato ao determinismo biológico.", status:0, historico:0 },
{ id:528, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um assistente perdeu o prazo para envio de ofícios importantes. Ao ser questionado, ele argumentou que 'foi melhor assim, pois os corretores nem leem esses ofícios de qualquer forma'. Esse comportamento de criar desculpas lógicas e plausíveis para justificar falhas é o mecanismo de:", imagem:null, alternativas:["A) Negação.","B) Racionalização.","C) Introjeção.","D) Deslocamento.","E) Repressão."], resposta_correta:1, explicacao: "Racionalização é a criação de desculpas 'racionais' ou lógicas para atenuar a dor de uma falha ou de uma atitude reprovável. A banca adora esse mecanismo porque é muito comum no serviço público (o famoso 'mas todo mundo faz assim').", status:0, historico:0 },
{ id:529, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise as assertivas sobre 'Segurança Psicológica' nas equipes de trabalho: I. É a crença compartilhada de que a equipe é um ambiente seguro para assumir riscos interpessoais (ex: dar ideias, admitir erros). II. Equipes com alta segurança psicológica tendem a ter baixa performance, pois a falta de punições gera indolência. III. O medo do julgamento dos colegas e da chefia é o principal fator que destrói a segurança psicológica. Está(ão) correta(s):", imagem:null, alternativas:["A) Apenas a I.","B) Apenas a II.","C) Apenas I e III.","D) Apenas II e III.","E) I, II e III."], resposta_correta:2, explicacao: "A II é falsa pois os estudos de Harvard (Projeto Aristóteles) provaram que equipes com MAIOR segurança psicológica têm a MAIOR performance, pois os membros não gastam energia se defendendo e inovam mais. A Quadrix tenta atrelar medo à produtividade.", status:0, historico:0 },
{ id:530, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Dois diretores do conselho divergem sobre onde alocar o orçamento: infraestrutura ou tecnologia. Após dialogarem, chegam a uma solução inovadora que atende plenamente aos interesses de ambos, sem que nenhum precise ceder em seus objetivos vitais. Esse estilo de gestão de conflito é a:", imagem:null, alternativas:["A) Competição (Ganha-Perde).","B) Acomodação (Perde-Ganha).","C) Evasão ou Fuga (Perde-Perde).","D) Compromisso ou Acordo (Ganha pouco-Ganha pouco).","E) Colaboração ou Integração (Ganha-Ganha)."], resposta_correta:4, explicacao: "Na Colaboração, as partes unem forças para achar uma solução 100% satisfatória para ambos. Não confundir com Compromisso (onde ambos abrem mão de algo/cedem). A banca descreve o cenário exato para testar essa sutil diferença.", status:0, historico:0 },
{ id:531, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A empatia no relacionamento interpessoal é dividida didaticamente pela psicologia organizacional. A capacidade de entender intelectualmente o que o outro está pensando ou como ele vê o mundo, sem necessariamente sentir a emoção dele, é chamada de:", imagem:null, alternativas:["A) Empatia Afetiva.","B) Empatia Cognitiva.","C) Simpatia Contagiosa.","D) Compaixão Ativa.","E) Projeção Empática."], resposta_correta:1, explicacao: "Empatia Cognitiva = entender intelectualmente a perspectiva alheia. Empatia Afetiva = compartilhar a carga emocional (sentir junto). A Quadrix introduziu esses termos técnicos recentes em suas cobranças para fugir do senso comum.", status:0, historico:0 },
{ id:532, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um membro da equipe de fiscalização fala muito bem inglês. Seus colegas, impressionados com essa habilidade, passam a acreditar automaticamente que ele também é excelente em matemática e redação, promovendo-o a líder, mesmo sem evidências. Esse viés de percepção é o(a):", imagem:null, alternativas:["A) Estereótipo.","B) Efeito de Contraste.","C) Efeito Halo.","D) Profecia Autorrealizadora.","E) Efeito de Recência."], resposta_correta:2, explicacao: "O Efeito Halo é a generalização a partir de UMA única característica (neste caso, positiva) que contamina a percepção global sobre o indivíduo. Historinha clássica da banca para cobrar vieses cognitivos.", status:0, historico:0 },
{ id:533, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Julgue (V) ou (F) sobre o papel da Confiança nas equipes: ( ) A confiança baseada na dissuasão (medo da punição) é a mais frágil, típica de relacionamentos novos ou estritamente formais. ( ) A confiança baseada no conhecimento surge quando o comportamento do outro se torna previsível devido ao histórico de convivência. ( ) A confiança baseada na identificação exige que os membros percam sua individualidade e pensem exatamente igual. A sequência correta é:", imagem:null, alternativas:["A) V, V, F.","B) F, V, V.","C) V, F, V.","D) V, V, V.","E) F, F, F."], resposta_correta:0, explicacao: "A terceira é falsa, pois a confiança baseada na identificação (o nível mais alto) significa que as partes entendem e respeitam as intenções do outro, mas não exige perda de individualidade ou 'pensamento de rebanho'.", status:0, historico:0 },
{ id:534, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O presidente do CRECI repreendeu severamente o coordenador de RH em uma reunião. O coordenador, não podendo revidar ao presidente, volta à sua sala e grita com o estagiário por um motivo fútil. Esse mecanismo clássico de comportamento defensivo é o(a):", imagem:null, alternativas:["A) Sublimação.","B) Racionalização.","C) Negação.","D) Deslocamento.","E) Formação Reativa."], resposta_correta:3, explicacao: "Deslocamento é a transferência da frustração/agressividade de uma fonte ameaçadora (o presidente) para um alvo mais seguro ou vulnerável (o estagiário). A Quadrix ama essa historinha da 'hierarquia do grito'.", status:0, historico:0 },
{ id:535, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Para que o trabalho em equipe atinja a excelência interpessoal, é necessário superar as disfunções de grupo (Patrick Lencioni). Assinale a alternativa que apresenta a disfunção estrutural mais básica que corrói o relacionamento e as demais etapas do trabalho em equipe:", imagem:null, alternativas:["A) A busca obsessiva por resultados globais.","B) A ausência de confiança mútua (medo da vulnerabilidade).","C) O excesso de comprometimento com os prazos.","D) A responsabilização constante entre os pares.","E) A presença de conflitos de ideias (fricção construtiva)."], resposta_correta:1, explicacao: "Sem confiança (a base da pirâmide de Lencioni), as pessoas não demonstram vulnerabilidade, o que gera medo de conflito, falta de comprometimento e fuga de responsabilidade. As demais opções são fatores POSITIVOS (virtudes).", status:0, historico:0 },
{ id:536, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise: I. Equipes altamente homogêneas (membros que pensam e agem igual) tomam decisões mais rápidas, porém com menor inovação. II. A diversidade (cognitiva e cultural) em equipes aumenta o potencial de inovação, mas exige maior competência interpessoal para gerir os conflitos inerentes. III. A diversidade deve ser evitada no serviço público para garantir a aplicação do princípio da impessoalidade. Está(ão) correta(s):", imagem:null, alternativas:["A) Apenas a I.","B) Apenas a III.","C) Apenas I e II.","D) Apenas II e III.","E) I, II e III."], resposta_correta:2, explicacao: "A III é absurdamente falsa, pois impessoalidade não significa padronização de perfis humanos, e sim tratamento neutro. A I e II descrevem perfeitamente a dinâmica entre homogeneidade (agilidade sem inovação) e diversidade (inovação com atrito gerencial).", status:0, historico:0 },
{ id:537, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um comportamento considerado RECEPTIVO e maduro durante a interação entre colegas de autarquia ocorre quando o indivíduo:", imagem:null, alternativas:["A) Antecipa-se à fala do colega, completando suas frases para demonstrar inteligência e empatia.","B) Justifica imediatamente suas atitudes assim que a crítica inicia, protegendo sua imagem profissional.","C) Filtra as informações recebidas, escutando apenas o que confirma suas convicções prévias.","D) Tolera a ambiguidade e acolhe pontos de vista divergentes antes de formular um julgamento definitivo.","E) Sorri o tempo todo durante uma discussão séria para camuflar o seu descontentamento real."], resposta_correta:3, explicacao: "Tolerar a ambiguidade (segurar o impulso de julgar imediatamente) e acolher a divergência é o ápice do comportamento maduro e receptivo. Completar frases (A), justificar-se (B) e sorrir falso (E) são comportamentos disfuncionais e defensivos.", status:0, historico:0 },
{ id:538, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um servidor recém-empossado sente muita insegurança em sua capacidade técnica, mas tenta demonstrar para a equipe uma postura de extrema autoconfiança e arrogância, escondendo seus medos. Na Janela de Johari, esse medo oculto reside na:", imagem:null, alternativas:["A) Área Aberta.","B) Área Cega.","C) Área Oculta (ou Secreta / Façada).","D) Área Desconhecida.","E) Área Sublimada."], resposta_correta:2, explicacao: "A Área Oculta (ou Façada) contém aquilo que o indivíduo SABE sobre si mesmo, mas ESCONDE dos outros (seus medos, intenções ocultas, segredos). Conceito clássico da Quadrix para mapeamento comportamental.", status:0, historico:0 },
{ id:539, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Julgue (V) ou (F) sobre traços de personalidade no trabalho em equipe: ( ) Indivíduos introvertidos são incapazes de exercer a liderança de equipes. ( ) Pessoas com alto nível de neuroticismo lidam melhor com o estresse e a pressão do atendimento ao público. ( ) A 'Afabilidade' excessiva pode ser prejudicial se impedir o servidor de cobrar resultados ou dizer 'não' a pedidos inadequados. A sequência correta é:", imagem:null, alternativas:["A) F, F, V.","B) F, V, V.","C) V, F, V.","D) F, F, F.","E) V, V, V."], resposta_correta:0, explicacao: "A 1ª é falsa (introvertidos podem ser excelentes líderes focados em empatia e escuta). A 2ª é falsa (alto neuroticismo = alta instabilidade emocional, logo, lidam MAL com estresse). A 3ª é verdadeira, pois concordância cega por afabilidade gera passividade.", status:0, historico:0 },
{ id:540, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"No modelo de Inteligência Emocional de Daniel Goleman, a habilidade de canalizar emoções fortes (como raiva ou ansiedade) de forma construtiva, não permitindo que elas sabotem o relacionamento com a equipe, é denominada:", imagem:null, alternativas:["A) Autoconhecimento.","B) Autocontrole (ou Autorregulação).","C) Empatia.","D) Habilidade Social.","E) Automotivação."], resposta_correta:1, explicacao: "Autoconhecimento é PERCEBER a raiva. Autocontrole é GERENCIAR a raiva (não explodir). A banca explora essa sutil diferença, pois muitos candidatos marcam autoconhecimento achando que abrange tudo.", status:0, historico:0 },
{ id:541, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um colega pede que você faça o trabalho dele pelo terceiro dia consecutivo. Uma resposta pautada na ASSERTIVIDADE seria:", imagem:null, alternativas:["A) Fazer o trabalho em silêncio, pois a harmonia da equipe é o mais importante no setor público.","B) Dizer de forma sarcástica: 'Claro, majestade, mais alguma ordem para o seu escravo hoje?'.","C) Reclamar para os outros colegas pelas costas dele, mas sorrir e aceitar o trabalho quando ele pedir.","D) Dizer educada e firmemente: 'Não poderei fazer. Percebo que você está atarefado, mas tenho meus próprios prazos a cumprir'.","E) Denunciá-lo à corregedoria do CRECI imediatamente por assédio moral continuado."], resposta_correta:3, explicacao: "A assertividade defende os próprios direitos de forma direta, clara e respeitosa (D). A alternativa A é passividade; B e E são agressivas; C é passivo-agressiva (fofoca).", status:0, historico:0 },
{ id:542, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Ao lidar com um colega de equipe que está enfrentando problemas graves de saúde na família, agir com 'Compaixão / Simpatia' em oposição à mera 'Empatia' envolve:", imagem:null, alternativas:["A) Compreender a dor dele racionalmente, mas exigir a mesma produtividade de sempre.","B) Sentir-se tocado pela dor dele e agir ativamente para ajudá-lo a aliviar a carga de trabalho.","C) Ocultar a situação do chefe para evitar que ele seja demitido.","D) Ignorar as próprias tarefas para resolver exclusivamente os problemas pessoais dele.","E) Tratar o assunto de forma estritamente legal, indicando os artigos de licença médica."], resposta_correta:1, explicacao: "A Empatia é a compreensão (colocar-se no lugar). A Compaixão/Simpatia dá um passo além, envolvendo o sentimento afetivo e a AÇÃO VOLUNTÁRIA de querer aliviar a dor do outro (ajudar na carga). A Quadrix cobra esse degrau a mais da compaixão.", status:0, historico:0 },
{ id:543, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Comunicação Organizacional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise o peso dos elementos na comunicação interpessoal face a face (Regra de Mehrabian). Em situações de conflito ou expressão de sentimentos na equipe, o impacto da mensagem é transmitido PRINCIPALMENTE:", imagem:null, alternativas:["A) Exclusivamente pelas palavras escolhidas (conteúdo verbal).","B) Pela clareza lógica dos argumentos escritos apresentados.","C) Pela linguagem corporal (expressão facial, postura) e pelo tom de voz.","D) Pelo nível hierárquico formal do emissor.","E) Pelo ambiente físico e isolamento acústico da sala de reunião."], resposta_correta:2, explicacao: "A regra de Albert Mehrabian afirma que, em comunicações emocionais, 55% do impacto é linguagem corporal, 38% tom de voz e apenas 7% as palavras faladas. A banca ama essa proporção para ressaltar a importância do 'não verbal'.", status:0, historico:0 },
{ id:544, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um servidor está visivelmente sobrecarregado, cometendo erros e prestes a ter um colapso (burnout). No entanto, quando a equipe tenta ajudá-lo, ele afirma energicamente: 'Eu estou ótimo, não preciso de ajuda, tenho tudo sob absoluto controle'. Esse mecanismo de defesa é a:", imagem:null, alternativas:["A) Sublimação.","B) Negação.","C) Racionalização.","D) Fixação.","E) Projeção."], resposta_correta:1, explicacao: "A Negação é o mecanismo de recusar-se a reconhecer uma realidade dolorosa ou ameaçadora que é óbvia para todos os outros. 'Não há problema algum' é a frase típica. Microcontexto altamente previsível em provas organizacionais.", status:0, historico:0 },
{ id:545, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Julgue as afirmativas (V) ou (F) sobre o 'Rapport' no trabalho em equipe: ( ) Rapport é o processo de construir uma conexão harmoniosa, confiança e espelhamento positivo com o outro. ( ) É uma técnica de manipulação antiética, estritamente proibida em conselhos de classe. ( ) Estabelecer rapport exige atenção à linguagem corporal e verbal do interlocutor, criando sintonia. A sequência correta é:", imagem:null, alternativas:["A) V, F, V.","B) F, V, F.","C) V, V, V.","D) F, F, F.","E) V, V, F."], resposta_correta:0, explicacao: "A segunda é falsa, pois rapport não é manipulação antiética, é uma habilidade social saudável e recomendada para atendimento e trabalho em equipe. A Quadrix tenta diabolizar ferramentas da PNL/Psicologia para testar o candidato.", status:0, historico:0 },
{ id:546, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Postura e Imagem Institucional", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A 'Coesão de Equipe' é fundamental para o sucesso organizacional. Assinale a alternativa que NÃO constitui um fator gerador de coesão entre os servidores:", imagem:null, alternativas:["A) Presença de um objetivo comum claro e desafiador.","B) Baixa frequência de interações pessoais para evitar atritos operacionais.","C) Sucesso histórico em projetos anteriores realizados juntos.","D) Existência de uma ameaça ou competição externa à equipe.","E) Afinidade de valores e concordância com a cultura da autarquia."], resposta_correta:1, explicacao: "A coesão exige alta interação, comunicação e convívio (tempo juntos). Reduzir as interações (B) destrói a coesão e cria 'ilhas' isoladas. Cuidado: ameaça externa (D) AUMENTA a coesão (efeito 'estamos todos no mesmo barco').", status:0, historico:0 },
{ id:547, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise os papéis desempenhados pelos membros em uma equipe madura: I. Papéis de Manutenção: focam em encorajar, mediar conflitos e apoiar os colegas. II. Papéis de Tarefa: focam em buscar informações, opinar e coordenar atividades para atingir a meta. III. Papéis de Bloqueio (Individuais): focam em autoafirmação, dominação e fuga, sendo altamente benéficos. Está(ão) correta(s):", imagem:null, alternativas:["A) Apenas a I.","B) Apenas a II.","C) Apenas I e II.","D) Apenas II e III.","E) I, II e III."], resposta_correta:2, explicacao: "A III é falsa. Papéis individuais/bloqueio (dominar, agredir, fugir) focam no ego e são DISFUNCIONAIS (destroem a equipe). Apenas os papéis de Tarefa e de Manutenção/Relação são positivos. Generalização teórica muito explorada em bancas analíticas.", status:0, historico:0 },
{ id:548, categoria:"Conhecimentos Específicos", materia:"Administração pessoal e material", assunto:"Trabalho em Equipe e Relações Interpessoais", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Para transformar um ambiente dominado por comportamentos defensivos em um ambiente receptivo, a gestão do conselho deve promover prioritariamente:", imagem:null, alternativas:["A) Um clima de avaliação punitiva contínua, garantindo o medo salutar.","B) A competição predatória entre os setores para estimular o individualismo.","C) A comunicação baseada na descrição de fatos, empatia e foco na resolução de problemas.","D) A aplicação de advertências públicas ao primeiro sinal de erro operacional.","E) O estabelecimento de dogmas inquestionáveis, reduzindo a liberdade de expressão."], resposta_correta:2, explicacao: "A comunicação descritiva (falar de fatos, não de personalidades) e o foco no problema (não nos culpados) desarmam a atitude defensiva. Avaliações punitivas (A) e exposição pública (D) criam paranoia organizacional e destroem a receptividade.", status:0, historico:0 },
{ id:549, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O Artigo 47 da Lei das Contravenções Penais (LCP) tipifica o exercício ilegal de profissão ou atividade. Assinale a alternativa que apresenta a correta previsão normativa dessa infração:", imagem:null, alternativas:["A) Pune-se exclusivamente a conduta de exercer a profissão de forma reiterada, sendo o mero anúncio publicitário considerado atípico.","B) A infração exige a comprovação de lucro, honorários ou vantagem financeira para que a sua consumação seja reconhecida.","C) Caracteriza-se por exercer profissão ou atividade econômica ou anunciar que a exerce, sem preencher as condições legais.","D) A sanção cominada é a pena de reclusão, de quinze dias a três meses, cumulada obrigatoriamente com multa.","E) Trata-se de crime inafiançável e imprescritível contra a organização do trabalho nacional."], resposta_correta:2, explicacao: "A LCP (Art. 47) pune tanto o 'exercício' quanto o mero 'anúncio' da profissão. O erro da D é usar a palavra 'reclusão' (contravenção gera prisão simples) e 'cumulada' (a lei diz 'ou multa'). A Quadrix sempre tenta invalidar o 'anúncio' como infração.", status:0, historico:0 },
{ id:550, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Com relação ao crime tipificado no art. 205 do Código Penal (Exercício de atividade com infração de decisão administrativa), é correto afirmar que:", imagem:null, alternativas:["A) A decisão que impede o exercício da atividade deve ser, invariavelmente, proferida por um juiz de direito em sentença penal.","B) O crime consuma-se de forma idêntica à contravenção do art. 47, bastando que o indivíduo anuncie que exerce a profissão proibida.","C) A pena prevista não admite a aplicação de multa como sanção alternativa, sendo a prisão rigorosamente obrigatória.","D) Trata-se de crime próprio, pois exige que o agente infrator esteja sob o efeito de uma decisão administrativa impeditiva anterior.","E) Qualquer cidadão que atue sem diploma comete este crime, independentemente de processos disciplinares prévios no conselho."], resposta_correta:3, explicacao: "O Art. 205 é crime próprio: exige uma qualidade específica do agente (estar impedido por decisão ADMINISTRATIVA). Pessoas sem diploma que nunca foram julgadas pelo conselho cometem a contravenção do Art. 47, e não o crime do Art. 205. Erro da A: não é decisão judicial.", status:0, historico:0 },
{ id:551, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Situação Hipotética: João, que nunca estudou a área imobiliária, abre um escritório e atua como corretor. Maria, corretora inscrita, teve seu registro suspenso por 90 dias após processo ético no CRECI, mas continuou atendendo clientes. Sob a ótica penal, João e Maria cometem, respectivamente:", imagem:null, alternativas:["A) Crime do Art. 205 do CP e Contravenção do Art. 47 da LCP.","B) Contravenção do Art. 47 da LCP e Crime do Art. 205 do CP.","C) Ambos cometem a Contravenção do Art. 47 da LCP.","D) Ambos cometem o Crime do Art. 205 do Código Penal.","E) Fraude processual e Falsidade Ideológica."], resposta_correta:1, explicacao: "João não tem condições legais (Art. 47 LCP). Maria tem as condições, mas está impedida por uma 'decisão administrativa' do CRECI (Art. 205 CP). A Quadrix ama cobrar essa distinção usando microcontextos e personagens.", status:0, historico:0 },
{ id:552, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Julgue as sentenças (V) ou (F) acerca das penas previstas: ( ) O Art. 205 do Código Penal comina pena de detenção, de três meses a dois anos, ou multa. ( ) O Art. 47 da Lei das Contravenções Penais comina pena de prisão simples, de quinze dias a três meses, ou multa. ( ) A legislação penal não faz distinção de severidade entre os dois ilícitos, aplicando-se a ambos a pena de reclusão em regime fechado. A sequência correta é:", imagem:null, alternativas:["A) V, V, F.","B) V, F, V.","C) F, V, F.","D) F, F, F.","E) V, V, V."], resposta_correta:0, explicacao: "As duas primeiras trazem a literalidade das leis. A terceira é falsa porque há distinção clara (Crime = Detenção; Contravenção = Prisão Simples), e nenhuma delas prevê Reclusão. A Quadrix testa a memorização exata da natureza da pena.", status:0, historico:0 },
{ id:553, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um estudante universitário publica em suas redes sociais: 'Sou o melhor corretor de imóveis da região, agende sua visita!'. Ele ainda não obteve o registro no CRECI e não realizou nenhuma venda. De acordo com a Lei das Contravenções Penais (Art. 47), a conduta do estudante é:", imagem:null, alternativas:["A) Atípica, pois a contravenção exige a concretização de pelo menos um negócio jurídico para se consumar.","B) Punível, visto que a lei criminaliza expressamente o ato de 'anunciar que a exerce' sem o preenchimento das condições legais.","C) Atípica, pois as redes sociais são ambientes virtuais imunes à legislação penal brasileira.","D) Punível pelo Art. 205 do Código Penal, pois o anúncio fere a decisão administrativa de fiscalização.","E) Punível apenas mediante advertência civil, sendo vedada a aplicação de prisão simples neste caso."], resposta_correta:1, explicacao: "O Art. 47 da LCP pune não só o exercício, mas também o mero anúncio ('ou anunciar que a exerce'). O erro da A é exigir a venda (lucro/efetivação). Pegadinha clássica em provas para Conselhos Regionais.", status:0, historico:0 },
{ id:554, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise as assertivas sobre as infrações contra a organização do trabalho: I. As contravenções penais são popularmente conhecidas como 'crimes anões' ou 'delitos liliputianos'. II. O crime de exercício de atividade com infração de decisão administrativa (Art. 205, CP) exige que a proibição seja definitiva; suspensões temporárias não configuram o tipo. III. A pena de multa é uma alternativa ('ou multa') tanto no Art. 205 do CP quanto no Art. 47 da LCP. Está(ão) correta(s):", imagem:null, alternativas:["A) Apenas a I.","B) Apenas I e II.","C) Apenas I e III.","D) Apenas II e III.","E) I, II e III."], resposta_correta:2, explicacao: "A assertiva II é falsa porque o Art. 205 abrange decisões administrativas temporárias (como suspensão de 30 dias) ou definitivas (cassação). A Quadrix insere a palavra 'definitiva' para restringir indevidamente o alcance da lei.", status:0, historico:0 },
{ id:555, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um profissional com registro no CRECI foi surpreendido atuando durante o período em que seu registro estava cancelado por uma decisão final do Plenário do Conselho. O advogado de defesa alega que o crime do Art. 205 do CP não ocorreu porque o CRECI não é um órgão do Poder Judiciário. A tese da defesa é:", imagem:null, alternativas:["A) Correta, visto que apenas sentenças de juízes togados podem gerar impedimentos penais.","B) Correta, pois os conselhos de classe possuem natureza puramente privada e não administrativa.","C) Incorreta, pois a lei penal criminaliza exatamente o desrespeito a uma decisão emanada de autoridade judiciária ou militar.","D) Incorreta, visto que o Art. 205 do CP tipifica expressamente o descumprimento de decisão 'administrativa', sendo o CRECI uma autarquia com tal poder.","E) Correta, pois o cancelamento do registro descaracteriza a profissão, transformando a conduta em estelionato comum."], resposta_correta:3, explicacao: "O Art. 205 do Código Penal tutela o respeito às decisões da Administração Pública. Sendo o CRECI uma autarquia federal, sua decisão é administrativa e seu descumprimento atrai a tipificação deste artigo.", status:0, historico:0 },
{ id:556, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Sobre a tentativa no âmbito da infração prevista no artigo 47 da Lei das Contravenções Penais (Exercício ilegal de profissão), assinale a afirmação correta sob a ótica do ordenamento jurídico penal brasileiro:", imagem:null, alternativas:["A) A tentativa é punida com a mesma pena da contravenção consumada, sem redução.","B) A tentativa é punível com a pena correspondente à contravenção consumada, diminuída de um a dois terços.","C) Não é punível a tentativa de contravenção penal, por expressa disposição da Parte Geral da própria LCP.","D) A tentativa apenas será punida se o agente utilizar grave ameaça contra o fiscal do conselho.","E) É aplicada a pena de multa em dobro nos casos em que a tentativa for confessada pelo infrator."], resposta_correta:2, explicacao: "O Art. 4º da LCP é categórico: 'Não é punível a tentativa de contravenção'. É a 'pegadinha suprema' das bancas, pois no Código Penal a tentativa de crime é punida (Art. 14, II), mas em contravenções, nunca.", status:0, historico:0 },
{ id:557, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Ao analisar a redação do Art. 205 do Código Penal ('Exercer atividade, de que está impedido por decisão administrativa'), nota-se uma generalização indevida comumente usada em recursos de candidatos. É incorreto afirmar que o tipo penal abrange:", imagem:null, alternativas:["A) O exercício de medicina por profissional suspenso pelo Conselho Regional de Medicina (CRM).","B) O corretor de imóveis exercendo a profissão sob suspensão cautelar do CRECI.","C) Um engenheiro trabalhando após ter o registro cassado definitivamente pelo CREA.","D) O cidadão comum que dirige veículo automotor após ter a CNH suspensa pelo DETRAN.","E) O cidadão que nunca se formou em direito, mas atua como advogado em fóruns locais."], resposta_correta:4, explicacao: "O cidadão que NUNCA se formou não tem uma 'decisão administrativa' que o impeça; ele simplesmente não tem as condições legais (LCP Art. 47). As bancas cobram essa diferença de enquadramento (Art. 205 exige ser alguém anteriormente habilitado e agora impedido).", status:0, historico:0 },
{ id:558, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Em uma prova objetiva, a banca substituiu sutilmente o conectivo da sanção penal. Qual das alternativas apresenta a pena do Art. 47 da LCP de forma absolutamente fiel à lei?", imagem:null, alternativas:["A) Prisão simples, de quinze dias a três meses, E multa.","B) Prisão simples, de quinze dias a três meses, OU multa.","C) Detenção, de quinze dias a três meses, OU multa.","D) Reclusão, de quinze dias a três meses, E multa.","E) Prisão simples, de um a seis meses, cumulada com multa."], resposta_correta:1, explicacao: "A lei prevê pena alternativa ('OU multa'). A Quadrix adora usar a conjunção aditiva ('E multa') para transformar a alternativa em falsa, exigindo alto nível de atenção do candidato.", status:0, historico:0 },
{ id:559, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Julgue (V) ou (F): ( ) O crime do Art. 205 do CP tutela, de forma primária, a integridade física dos clientes atendidos pelo profissional irregular. ( ) A LCP no art. 47 aplica-se exclusivamente às profissões que exigem diploma de ensino superior. ( ) O termo 'atividade econômica' presente no art. 47 abrange inclusive ofícios que não dependem de conselho de classe, desde que subordinados a condições legais. A sequência correta é:", imagem:null, alternativas:["A) V, V, F.","B) F, F, V.","C) V, F, V.","D) F, V, F.","E) F, F, F."], resposta_correta:1, explicacao: "A 1ª é falsa (tutela a Organização do Trabalho / Administração Pública, e não a integridade física). A 2ª é falsa (qualquer profissão ou atividade que a lei imponha condições, como taxista ou despachante, não só nível superior). A 3ª é verdadeira.", status:0, historico:0 },
{ id:560, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um corretor suspenso tenta argumentar que a decisão do CRECI que o impediu de trabalhar foi injusta e com falhas processuais. Por isso, continuou trabalhando. Configurada a situação perante o juiz criminal (Art. 205 do CP), o argumento do corretor:", imagem:null, alternativas:["A) Absolve-o automaticamente, pois a justiça penal revisa o mérito das decisões dos conselhos de classe.","B) É irrelevante para a consumação do crime, visto que a lei penal exige apenas a existência formal da decisão administrativa impeditiva, não cabendo ao infrator descumpri-la por conta própria.","C) Desclassifica o crime para a contravenção do Art. 47 da LCP, em razão do estado de necessidade.","D) Torna a conduta atípica, pois a discordância afasta o dolo (elemento subjetivo do tipo).","E) Justifica a aplicação exclusiva da pena de multa, convertendo a detenção em advertência verbal."], resposta_correta:1, explicacao: "O desrespeito à decisão administrativa consuma o crime. Se o profissional acha a decisão injusta, deve recorrer administrativamente ou judicialmente (mandado de segurança), mas não pode descumpri-la 'fazendo justiça com as próprias mãos'.", status:0, historico:0 },
{ id:561, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A doutrina penal classifica os delitos em comuns ou próprios. Considerando o sujeito ativo das infrações em estudo, assinale a alternativa correta:", imagem:null, alternativas:["A) O Art. 47 da LCP e o Art. 205 do CP são crimes próprios, exigindo qualificação especial do agente.","B) O Art. 47 da LCP e o Art. 205 do CP são crimes comuns, podendo ser praticados por qualquer pessoa.","C) O Art. 47 da LCP é infração penal comum (qualquer um que não preencha os requisitos) e o Art. 205 do CP é crime próprio (apenas quem sofreu decisão administrativa).","D) O Art. 47 da LCP exige que o autor seja funcionário público, configurando crime próprio.","E) O Art. 205 do CP é crime comum, consumado sempre que a sociedade é lesada por um serviço mal prestado."], resposta_correta:2, explicacao: "O Art. 47 da LCP pode ser cometido por qualquer pessoa sem habilitação (comum). O Art. 205 do CP exige que o agente tenha recebido uma decisão administrativa contra ele (próprio). Conceito doutrinário avançado frequentemente usado pela Quadrix.", status:0, historico:0 },
{ id:562, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise as afirmativas referentes aos elementos normativos do Art. 47 da LCP: I. A expressão 'condições a que por lei está subordinado' engloba resoluções e portarias dos conselhos, desde que amparadas em lei federal. II. O simples aconselhamento esporádico e gratuito a um amigo sobre a compra de um imóvel configura o exercício habitual exigido pela contravenção. III. O dolo exigido para a contravenção penal é a vontade livre e consciente de exercer a profissão ciente da falta de habilitação. Está(ão) correta(s):", imagem:null, alternativas:["A) Apenas I.","B) Apenas I e III.","C) Apenas II e III.","D) Apenas III.","E) I, II e III."], resposta_correta:1, explicacao: "A II é falsa porque o exercício da profissão exige caráter de habitualidade ou anúncio público, e não um favor esporádico e isolado entre amigos (ato não profissional). O item I e III estão corretos.", status:0, historico:0 },
{ id:563, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"João e Carlos foram pegos em uma blitz do CRECI. João tinha o registro cassado há 1 ano (Art. 205 CP). Carlos era estudante de ensino médio anunciando imóveis no Facebook (Art. 47 LCP). Considerando as penas aplicáveis e a eventual necessidade de fiança ou transação penal, essas infrações são consideradas:", imagem:null, alternativas:["A) Crimes Hediondos.","B) Infrações de Maior Potencial Ofensivo, julgadas na Justiça Federal comum.","C) Infrações de Menor Potencial Ofensivo, sujeitas aos benefícios da Lei dos Juizados Especiais Criminais (Lei 9.099/95).","D) Faltas exclusivamente administrativas, não gerando antecedentes criminais.","E) Crimes de responsabilidade civil extracontratual."], resposta_correta:2, explicacao: "Tanto a pena do Art. 205 (máximo 2 anos) quanto a do Art. 47 (máximo 3 meses) enquadram-se como Infrações de Menor Potencial Ofensivo (pena máxima até 2 anos), permitindo transação penal nos Juizados Especiais Criminais (JECRIM).", status:0, historico:0 },
{ id:564, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A Quadrix costuma realizar inversões sutis de conceitos. Assinale a alternativa que descreve a exata consequência penal para o infrator do Art. 205 do Código Penal:", imagem:null, alternativas:["A) Aplicação de detenção (3 meses a 2 anos) OU multa, não havendo cumulatividade obrigatória.","B) Aplicação de prisão simples (15 dias a 3 meses) E multa, exigindo o pagamento de fiança imediata.","C) Aplicação de reclusão inafiançável, pois atenta contra a ordem econômica da União.","D) Apenas aplicação de multa, visto que o Código Penal descriminalizou as condutas de baixo risco.","E) Conversão automática da pena em serviços comunitários prestados exclusivamente no conselho de classe."], resposta_correta:0, explicacao: "A literalidade da lei para o Art. 205 é: 'Pena - detenção, de três meses a dois anos, OU multa'. O conector 'ou' indica alternatividade imposta pelo juiz. As bancas trocam 'detenção' por 'reclusão' ou 'prisão simples'.", status:0, historico:0 },
{ id:565, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Situação Hipotética: Um indivíduo exerce a corretagem com um diploma falso, sem nunca ter se inscrito no CRECI. Neste caso complexo de concurso de crimes, o ato específico de trabalhar sem preencher as condições legais atrai a aplicação do(a):", imagem:null, alternativas:["A) Artigo 205 do Código Penal (Infração de decisão administrativa).","B) Artigo 47 da Lei das Contravenções Penais (Exercício ilegal).","C) Princípio da insignificância, extinguindo a pena.","D) Súmula Vinculante de anistia profissional.","E) Tipo penal de apropriação indébita previdenciária."], resposta_correta:1, explicacao: "Embora ele possa responder por uso de documento falso (crime à parte), o ato de atuar sem o preenchimento legal recai no Art. 47 da LCP. Não é o 205 porque não houve decisão administrativa prévia suspendendo-o.", status:0, historico:0 },
{ id:566, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Sobre as Contravenções Penais, especialmente o Art. 47 (Exercício ilegal da profissão), marque a alternativa correta referente aos limites da lei:", imagem:null, alternativas:["A) A lei brasileira não faz qualquer distinção entre crime e contravenção, sendo ambos sinônimos processuais.","B) A pena de prisão simples prevista na LCP deve ser cumprida, desde o início, em regime fechado rigoroso.","C) As contravenções penais são puníveis apenas quando praticadas com dolo específico de enriquecimento ilícito.","D) A lei de contravenções aplica-se somente aos fatos ocorridos no território nacional, não havendo extraterritorialidade para elas.","E) O artigo 47 da LCP foi revogado tacitamente pela Constituição Federal de 1988, que garante o livre exercício profissional irrestrito."], resposta_correta:3, explicacao: "A Lei de Contravenções Penais (LCP) só se aplica no Brasil (Art. 2º da LCP: 'A lei brasileira só é aplicável à contravenção praticada no território nacional'). O erro da E é que a CF/88 diz 'atendidas as qualificações que a lei estabelecer'.", status:0, historico:0 },
{ id:567, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Julgue (V) ou (F): ( ) Para que ocorra a infração do art. 205 do CP, a decisão administrativa deve ter sido devidamente notificada/cientificada ao profissional. ( ) Se o infrator ignorava completamente a suspensão por falha do conselho na intimação, afasta-se o dolo. ( ) O art. 47 da LCP pune o leigo que tenta atuar na profissão de forma amadora. A sequência correta é:", imagem:null, alternativas:["A) V, V, V.","B) F, V, V.","C) V, F, V.","D) V, V, F.","E) F, F, F."], resposta_correta:0, explicacao: "Todas são verdadeiras. Sem a intimação da decisão, não há o dolo (conhecimento do impedimento) no Art. 205. Já o Art. 47 atinge diretamente o leigo/amador que tenta atuar sem registro.", status:0, historico:0 },
{ id:568, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A Quadrix frequentemente testa a atenção aos verbos nucleares do tipo penal. No Artigo 47 da LCP ('Exercer profissão...'), assinale o núcleo verbal adicional que NÃO encontra correspondência direta no Artigo 205 do Código Penal:", imagem:null, alternativas:["A) Omitir.","B) Facilitar.","C) Anunciar.","D) Falsificar.","E) Retardar."], resposta_correta:2, explicacao: "O Art. 47 da LCP pune 'Exercer... OU ANUNCIAR que a exerce'. O Art. 205 do CP fala apenas em 'Exercer atividade...'. O verbo 'anunciar' é a armadilha mais famosa da LCP nas provas.", status:0, historico:0 },
{ id:569, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um ex-corretor, revoltado com a cassação de seu registro, continua a intermediar vendas em clara afronta à decisão do Plenário do CRECI. A natureza jurídica da pena que lhe pode ser imposta (Art. 205 do CP) é de:", imagem:null, alternativas:["A) Prisão Simples.","B) Detenção.","C) Reclusão.","D) Banimento comercial.","E) Perda automática de todos os bens civis."], resposta_correta:1, explicacao: "O crime do Art. 205 do CP prevê pena de DETENÇÃO. A Quadrix cria alternativas usando penas restritivas de liberdade com nomenclaturas incorretas (prisão simples é para contravenção; reclusão é para crimes mais graves).", status:0, historico:0 },
{ id:570, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Na tipificação do Art. 47 da Lei das Contravenções Penais, a expressão 'atividade econômica' tem por objetivo:", imagem:null, alternativas:["A) Limitar a punição apenas a empresários de grande porte, excluindo autônomos.","B) Garantir que atividades lucrativas não regulamentadas por conselhos fiquem imunes à fiscalização.","C) Ampliar a proteção legal, punindo o exercício de atividades comerciais ou industriais que exijam licenciamento ou alvará estatal, não se limitando às profissões liberais.","D) Isentar de pena profissionais liberais (como advogados e corretores), focando apenas no comércio varejista.","E) Exigir que a Polícia Federal atue exclusivamente na cobrança de impostos sonegados."], resposta_correta:2, explicacao: "O Art. 47 abrange 'profissão' (ex: corretor, médico) E 'atividade econômica' (ex: dirigir lotação, ter um comércio que exija licença específica). A Quadrix usa o termo para ver se o candidato conhece a abrangência da lei.", status:0, historico:0 },
{ id:571, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Caso um indivíduo atue como corretor de imóveis portando um registro que não preenche as condições legais, a autoridade policial lavrará:", imagem:null, alternativas:["A) Um Termo Circunstanciado de Ocorrência (TCO), dada a natureza de menor potencial ofensivo da infração do art. 47 da LCP.","B) Um mandado de prisão preventiva inafiançável, devido ao risco à ordem pública.","C) Um auto de infração civil, visto que o Código Penal descriminalizou todas as contravenções.","D) Uma carta de fiança com valor mínimo de 100 salários mínimos obrigatórios.","E) Um ofício de deportação caso o falso corretor seja residente em outro estado da federação."], resposta_correta:0, explicacao: "Contravenções Penais (e crimes com pena máxima até 2 anos) seguem o rito da Lei 9.099/95, sendo lavrado um Termo Circunstanciado de Ocorrência (TCO), e não um auto de prisão em flagrante rigoroso, desde que o autor se comprometa a ir ao Juizado.", status:0, historico:0 },
{ id:572, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise: I. O infrator do Art. 205 (CP) fere a autoridade e a decisão da Administração Pública. II. O infrator do Art. 47 (LCP) fere o poder de polícia do Estado em regulamentar o exercício profissional. III. A pena do Art. 47 (LCP) é mais grave que a do Art. 205 (CP), pois a contravenção é mais lesiva. Está(ão) correta(s):", imagem:null, alternativas:["A) Apenas a I.","B) Apenas I e II.","C) Apenas II e III.","D) Apenas I e III.","E) I, II e III."], resposta_correta:1, explicacao: "A III é manifestamente falsa. O Crime (Art. 205) é muito mais grave (Detenção de até 2 anos) do que a Contravenção (Art. 47 - Prisão Simples de até 3 meses). A banca inverte a hierarquia penal para gerar confusão.", status:0, historico:0 },
{ id:573, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A exigência do art. 47 da LCP ('sem preencher as condições a que por lei está subordinado o seu exercício') encontra seu fundamento constitucional na norma que estabelece que:", imagem:null, alternativas:["A) O trabalho é proibido no Brasil, salvo autorização militar.","B) É livre o exercício de qualquer trabalho, ofício ou profissão, atendidas as qualificações profissionais que a lei estabelecer.","C) Apenas os sindicatos podem limitar o acesso ao mercado de trabalho.","D) A Constituição proíbe qualquer tipo de conselho de classe ou autarquia fiscalizadora.","E) O direito ao trabalho é absoluto e não pode ser regulamentado por leis infraconstitucionais."], resposta_correta:1, explicacao: "É a aplicação do Art. 5º, XIII, da Constituição Federal. A liberdade profissional é uma norma de eficácia contida, podendo a lei exigir qualificações (como o registro no CRECI). A contravenção pune quem atua sem respeitar essas qualificações.", status:0, historico:0 },
{ id:574, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um cidadão insatisfeito com o CRECI decide revogar por conta própria a suspensão administrativa que lhe foi imposta e volta a trabalhar no mesmo dia. Essa 'revogação unilateral' pelo próprio apenado:", imagem:null, alternativas:["A) É lícita se ele considerar a decisão administrativa inconstitucional.","B) Afasta o dolo e torna o fato atípico perante o Código Penal.","C) É irrelevante para o Direito Penal, consumando plenamente o delito do Art. 205 do Código Penal.","D) Transforma a infração em mero desacato verbal sem previsão de prisão.","E) Transfere a competência do julgamento para a Justiça do Trabalho."], resposta_correta:2, explicacao: "Ninguém pode fazer 'justiça com as próprias mãos' e descumprir ordem administrativa impeditiva sem ordem judicial. A atitude consuma o crime do art. 205 de forma cristalina. Distratores miram na ideia do 'cidadão rebelde amparado pela lei' (absurdo jurídico).", status:0, historico:0 },
{ id:575, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Julgue (V) ou (F): ( ) O crime do art. 205 (CP) exige apenas a pena de multa nos casos em que não há reincidência. ( ) A pena de prisão simples (LCP) não pode ser cumprida em regime fechado. ( ) Apenas o STF tem competência para julgar infrações da Lei de Contravenções Penais. A sequência correta é:", imagem:null, alternativas:["A) F, V, F.","B) V, V, F.","C) F, F, V.","D) V, F, V.","E) F, V, V."], resposta_correta:0, explicacao: "A 1ª é Falsa (a multa é alternativa, mas o juiz pode aplicar a detenção dependendo da gravidade, mesmo sendo primário). A 2ª é Verdadeira (prisão simples = regime aberto ou semiaberto, nunca fechado). A 3ª é Falsa (JECRIM ou Justiça Comum julgam, não o STF originariamente).", status:0, historico:0 },
{ id:576, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Sobre a diferença entre os sujeitos passivos das infrações, assinale a alternativa correta:", imagem:null, alternativas:["A) No art. 47 da LCP, a vítima (sujeito passivo) é exclusivamente o corretor de imóveis concorrente.","B) No art. 205 do CP, o sujeito passivo é o Estado (Administração Pública) e, secundariamente, as pessoas prejudicadas pelo profissional impedido.","C) O Ministério Público é proibido de atuar nesses crimes por serem de ação penal privada.","D) Ambas as infrações não possuem vítimas, sendo chamados de 'crimes de vácuo jurídico'.","E) O sujeito passivo é sempre o Presidente da República, por ser o chefe máximo do executivo."], resposta_correta:1, explicacao: "Crimes contra a organização do trabalho/administração têm o Estado como vítima principal (coletividade). A Quadrix tenta restringir a vítima a uma pessoa privada (como um concorrente na opção A) para testar a base de direito penal do aluno.", status:0, historico:0 },
{ id:577, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O Art. 47 da LCP utiliza o verbo 'anunciar' que a exerce. Qual das condutas abaixo melhor ilustra essa tipificação isolada?", imagem:null, alternativas:["A) Realizar cem transações imobiliárias em segredo absoluto sem nunca revelar ser corretor.","B) Colocar um letreiro na porta de casa escrito 'Corretor de Imóveis' sem possuir registro no CRECI, mesmo sem ter captado clientes ainda.","C) Ter o registro suspenso e atender um cliente antigo sigilosamente.","D) Recusar-se a pagar a anuidade do conselho de classe por discordar dos valores.","E) Emitir pareceres jurídicos para tribunais superiores."], resposta_correta:1, explicacao: "O ato do 'letreiro' consuma o núcleo 'anunciar que a exerce' do art. 47 da LCP, independentemente do sucesso comercial. A opção A ilustra o 'exercer' e a C ilustra o crime do art. 205 do CP. Microcontexto clássico da banca.", status:0, historico:0 },
{ id:578, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Direito Penal e Contravenções", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Sintetizando os conhecimentos sobre as legislações penal e contravencional atinentes à profissão, identifique a afirmativa irretocável em provas do Instituto Quadrix:", imagem:null, alternativas:["A) O legislador igualou as penas do Art. 205 (CP) e Art. 47 (LCP) no ano de 2020, unificando os regimes de reclusão.","B) O exercício de atividade com infração de decisão administrativa (Art. 205) é materialmente um crime de desobediência qualificado focado na organização do trabalho, não se confundindo com o amadorismo leigo do Art. 47 (LCP).","C) É admitida a tentativa em ambas as infrações, com redução automática de metade da pena se o infrator for primário.","D) A multa, em ambas as legislações, é uma penalidade que foi extinta pelo STJ, aplicando-se apenas a prisão.","E) O Art. 205 abrange decisões de síndicos de condomínios fechados contra operários de obra."], resposta_correta:1, explicacao: "Resumo perfeito e 'irretocável': O art. 205 atinge quem descumpre ordem do Estado (como uma desobediência específica); O art. 47 atinge o leigo/aventureiro que não tem a habilitação. Erros das demais: não há tentativa em contravenção (C), as multas existem (D), exige-se decisão pública/administrativa (E) e as penas são diferentes (A).", status:0, historico:0 },
{ id:579, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Conforme a Lei nº 6.530/1978, os Conselhos Federal e Regionais de Corretores de Imóveis (COFECI e CRECI) são órgãos de disciplina e fiscalização da profissão. Sobre a natureza jurídica desses órgãos, é correto afirmar que:", imagem:null, alternativas:["A) Possuem personalidade jurídica de direito privado, atuando como sindicatos de defesa da classe patronal.","B) São empresas públicas, com autonomia financeira estrita, subordinadas invariavelmente ao Ministério do Trabalho.","C) Possuem personalidade jurídica de direito público, sendo autarquias dotadas de autonomia administrativa, operacional e financeira.","D) São organizações não governamentais (ONGs) criadas por lei para defender exclusivamente os interesses financeiros dos corretores.","E) Constituem sociedades de economia mista, visto que arrecadam recursos próprios por meio das anuidades."], resposta_correta:2, explicacao: "O Art. 5º da Lei nº 6.530/78 estabelece que o COFECI e os CRECIs são autarquias com personalidade jurídica de direito PÚBLICO. A Quadrix adora usar as palavras 'sindicato' e 'direito privado' (A e D) para fisgar quem confunde conselho de classe com associação sindical.", status:0, historico:0 },
{ id:580, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A Quadrix costuma inverter as competências entre os órgãos federal e regionais. Segundo a Lei nº 6.530/1978, assinale a alternativa que apresenta uma competência EXCLUSIVA do Conselho Regional de Corretores de Imóveis (CRECI):", imagem:null, alternativas:["A) Aprovar os regimentos internos de todos os CRECIs do país.","B) Julgar, em última e definitiva instância, os recursos contra decisões disciplinares.","C) Expedir as carteiras profissionais e certificados de inscrição aos corretores e empresas.","D) Fixar, mediante resolução, o valor máximo das anuidades e multas a serem cobradas no território nacional.","E) Intervir temporariamente em outros Conselhos Regionais quando houver grave falha administrativa."], resposta_correta:2, explicacao: "Expedir carteiras, arrecadar anuidades e fiscalizar o exercício (além de julgar em 1ª instância) são funções do CRECI (Art. 10). Todas as demais alternativas (A, B, D e E) são competências do COFECI (Art. 9º). Pegadinha clássica de inversão de competências.", status:0, historico:0 },
{ id:581, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O exercício da profissão de Corretor de Imóveis é regulamentado e exige qualificação específica. Nos termos da Lei nº 6.530/1978, o registro no CRECI será permitido ao possuidor de título de:", imagem:null, alternativas:["A) Bacharel em Direito ou Administração, com pós-graduação em Direito Imobiliário.","B) Técnico em Transações Imobiliárias, devidamente diplomado.","C) Qualquer nível superior, desde que comprove 5 anos ininterruptos de atuação prática no mercado.","D) Ensino médio completo, condicionado à aprovação em exame de suficiência aplicado pelo próprio COFECI.","E) Gestor de Negócios Imobiliários, sendo expressamente vedado o registro a quem possui apenas nível técnico."], resposta_correta:1, explicacao: "O Art. 2º da Lei exige expressamente o título de 'Técnico em Transações Imobiliárias' (TTI). A Quadrix cria alternativas plausíveis citando bacharelados afins (como Direito ou Administração) para confundir o candidato que acha que o diploma de nível superior hierarquicamente superior dispensa o TTI.", status:0, historico:0 },
{ id:582, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Situação Hipotética: Um corretor foi denunciado ao CRECI por locupletar-se (enriquecer ilicitamente) à custa de seu cliente. Após processo disciplinar garantindo a ampla defesa, ele foi condenado. Segundo as sanções disciplinares previstas no Art. 21 da Lei nº 6.530/1978, a suspensão do registro poderá ser aplicada por um prazo de:", imagem:null, alternativas:["A) Até 30 dias.","B) Até 60 dias.","C) Até 90 dias.","D) Até 180 dias.","E) No mínimo 1 ano e no máximo 5 anos."], resposta_correta:2, explicacao: "O Art. 21, inciso IV, determina que a sanção de suspensão é de ATÉ 90 DIAS. A Quadrix ama alterar esse prazo para 180 dias nas alternativas para testar a memória decoreba dos prazos legais aplicados pelos conselhos.", status:0, historico:0 },
{ id:583, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Julgue as sentenças (V) ou (F) sobre a composição e mandatos dos conselhos: ( ) O COFECI e os CRECIs serão compostos por 27 membros efetivos e igual número de suplentes. ( ) O mandato dos conselheiros do COFECI e dos CRECIs é de 3 (três) anos. ( ) É terminantemente proibida a reeleição de conselheiros para os CRECIs, garantindo-se a rotatividade administrativa. A sequência correta é:", imagem:null, alternativas:["A) V, V, F.","B) V, F, V.","C) F, V, V.","D) V, V, V.","E) F, F, F."], resposta_correta:0, explicacao: "A 1ª está correta (Art. 12). A 2ª está correta (o mandato é de 3 anos, redação dada pela Lei 10.795/03). A 3ª é falsa, pois a lei NÃO proíbe a reeleição. A banca Quadrix utiliza palavras como 'terminantemente proibida' para criar regras restritivas inexistentes.", status:0, historico:0 },
{ id:584, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"De acordo com o Art. 20 da Lei nº 6.530/1978, constitui infração disciplinar grave, passível de punição, a conduta do corretor de imóveis que:", imagem:null, alternativas:["A) Associar-se a outro corretor credenciado para a execução de uma transação imobiliária de grande porte.","B) Reter em suas mãos negócio, quando não tiver probabilidade de realizá-lo.","C) Cobrar comissões que estejam rigorosamente dentro da tabela fixada pelo respectivo CRECI.","D) Informar ao cliente, de forma clara e objetiva, os riscos inerentes a uma transação imobiliária específica.","E) Anunciar publicamente um imóvel com a prévia autorização por escrito do proprietário."], resposta_correta:1, explicacao: "Reter negócio sem probabilidade de realizá-lo é uma infração expressa no Art. 20, inciso V. As demais alternativas (A, C, D e E) são ações perfeitamente legais e recomendáveis, mas a Quadrix tenta forçar interpretações de que 'associar-se' (A) seria formação de cartel, o que é falso.", status:0, historico:0 },
{ id:585, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Sobre a vinculação e a subordinação entre os órgãos, assinale a alternativa que descreve corretamente a relação hierárquico-administrativa estabelecida pela Lei nº 6.530/1978:", imagem:null, alternativas:["A) Os CRECIs são órgãos independentes, não prestando qualquer tipo de subordinação normativa ao COFECI.","B) O COFECI atua como tribunal superior de ética, mas não detém poder para intervir administrativamente nos CRECIs.","C) Das decisões disciplinares proferidas pelo CRECI não cabe nenhum tipo de recurso, configurando trânsito em julgado imediato.","D) Cabe recurso ao COFECI de todas as decisões definitivas proferidas pelos CRECIs, consolidando-o como instância superior.","E) Os CRECIs estão diretamente subordinados ao Ministério da Economia, que julga seus recursos administrativos."], resposta_correta:3, explicacao: "O COFECI é o órgão supremo, julgando em última instância os recursos das decisões dos CRECIs (Art. 9º, c). A Quadrix sempre tenta 'isolar' o CRECI (alternativas A e C) ou submetê-lo diretamente a Ministérios (E) para testar o conhecimento hierárquico autárquico.", status:0, historico:0 },
{ id:586, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise: I. O pagamento da anuidade ao CRECI constitui condição legal para o exercício da profissão. II. As pessoas jurídicas (imobiliárias) que atuam na intermediação imobiliária estão isentas de inscrição no CRECI, exigindo-se apenas o registro de seus sócios. III. O não pagamento das contribuições e anuidades acarretará a suspensão imediata do registro, sem necessidade de processo disciplinar prévio. Está(ão) correta(s):", imagem:null, alternativas:["A) Apenas a I.","B) Apenas a II.","C) Apenas I e III.","D) Apenas II e III.","E) I, II e III."], resposta_correta:0, explicacao: "A II é falsa, pois a lei exige inscrição tanto da pessoa física quanto da pessoa jurídica (Art. 6º). A III é falsa, pois a Constituição garante o devido processo legal e o STF/STJ já firmaram que o conselho não pode suspender o registro sumariamente APENAS pelo não pagamento de anuidade (exige processo ou execução fiscal).", status:0, historico:0 },
{ id:587, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Um corretor de imóveis baiano foi penalizado com uma multa disciplinar pelo CRECI-BA. Segundo a Lei nº 6.530/1978, essa penalidade de multa não poderá exceder o valor equivalente a:", imagem:null, alternativas:["A) 10 vezes o valor da maior anuidade vigente.","B) 3 vezes o valor da anuidade do ano em que foi cometida a infração.","C) 1 salário mínimo nacional vigente à época dos fatos.","D) 50% do valor da comissão recebida na transação fraudulenta.","E) O triplo do valor auferido ilicitamente pelo corretor na transação."], resposta_correta:1, explicacao: "A multa disciplinar, segundo o Art. 22 da Lei, não poderá exceder a 3 (três) vezes o valor da anuidade do ano em que se cometeu a infração. A banca mistura penas do Código de Defesa do Consumidor (lucro da transação) com as do conselho.", status:0, historico:0 },
{ id:588, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O Artigo 3º da Lei nº 6.530/78 delimita o escopo de atuação do profissional. Assinale a atividade que NÃO é de competência do Corretor de Imóveis, conforme a legislação específica:", imagem:null, alternativas:["A) Exercer a intermediação na compra e venda de imóveis.","B) Intermediar a permuta de propriedades imobiliárias.","C) Opinar quanto à comercialização imobiliária, emitindo laudos técnicos de avaliação.","D) Intermediar a locação de imóveis urbanos e rurais.","E) Lavrar e registrar, com fé pública, as escrituras de compra e venda nos cartórios competentes."], resposta_correta:4, explicacao: "A lavratura de escrituras com 'fé pública' é competência exclusiva de Tabeliães/Notários (Cartórios), e o registro, de Oficiais de Registro de Imóveis. O corretor apenas *intermedia* e *opina* sobre o negócio. A banca testa o limite exato da atribuição do cargo.", status:0, historico:0 },
{ id:589, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"João, Corretor de Imóveis no estado de Pernambuco, decide intermediar a venda de um grande loteamento localizado na Bahia de forma pontual. Segundo as normas aplicáveis e o funcionamento dos CRECIs, ele deve:", imagem:null, alternativas:["A) Atuar livremente, pois a carteira profissional tem validade nacional e irrestrita, sem necessidade de aviso.","B) Requerer inscrição secundária no CRECI-BA ou proceder com os trâmites de atuação eventual, conforme resoluções do COFECI.","C) Cancelar definitivamente seu registro em Pernambuco para atuar uma única vez na Bahia.","D) Pagar a anuidade integral do ano simultaneamente para ambos os Conselhos (PE e BA) sem possibilidade de isenção ou taxa reduzida.","E) Realizar a venda em nome do sindicato local de corretores, isentando-se das obrigações no CRECI-BA."], resposta_correta:1, explicacao: "A inscrição principal habilita para o Estado expedidor. Atuações em outros Estados exigem inscrição secundária ou registro de atuação eventual, regulamentado pelo COFECI. A Quadrix joga com o 'livre exercício' (A) para tentar convencer de que a jurisdição do CRECI não existe.", status:0, historico:0 },
{ id:590, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Julgue (V) ou (F): ( ) É vedado ao Corretor de Imóveis receber comissões ou honorários de ambas as partes na mesma transação, exceto se houver concordância de todos os interessados. ( ) A sanção de 'Censura' é aplicada de forma verbal, em reunião fechada de diretoria, não constando nos assentamentos do profissional. ( ) O cancelamento da inscrição com apreensão da carteira profissional é a penalidade máxima do sistema COFECI/CRECI. A sequência correta é:", imagem:null, alternativas:["A) V, F, V.","B) V, V, F.","C) F, F, V.","D) V, V, V.","E) F, V, F."], resposta_correta:0, explicacao: "A 1ª é (V) - Art 20, inciso III. A 2ª é (F) - A 'Advertência' é verbal, enquanto a 'Censura' tem anotação na carteira profissional do corretor (Art 21, § 2º). A 3ª é (V) - Cancelamento é a pena máxima. A banca frequentemente confunde os efeitos da Censura com os da Advertência Verbal.", status:0, historico:0 },
{ id:591, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A Lei nº 6.530/1978 previu regras claras para as imobiliárias e corretores associados. A respeito da associação entre corretores ('Corretor Associado'), é correto afirmar:", imagem:null, alternativas:["A) A associação de um corretor a uma imobiliária cria, automaticamente, vínculo empregatício pleno, com direito a FGTS e horas extras.","B) É vedado por lei o contrato de associação específica sem vínculo empregatício entre corretores, para evitar a precarização do trabalho.","C) O corretor pode se associar a uma ou mais imobiliárias, mantendo sua autonomia profissional, sem que isso configure vínculo empregatício e previdenciário, desde que registrado no sindicato da categoria.","D) A imobiliária e o corretor associado deverão ter contrato escrito e registrado no respectivo sindicato, e não no CRECI.","E) As Pessoas Jurídicas inscritas no CRECI deverão ter sempre um Corretor de Imóveis responsável técnico por suas atividades."], resposta_correta:4, explicacao: "Toda imobiliária (PJ) precisa de um Responsável Técnico (Corretor Pessoa Física inscrito) respondendo por ela (Art. 6º). As alternativas A, B, C e D usam informações distorcidas sobre a Lei 13.097/15 (que regulou o corretor associado), mas a banca mistura exigências de registro no sindicato ao invés do CRECI.", status:0, historico:0 },
{ id:592, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Uma denúncia anônima informa que uma construtora local está comercializando seus próprios apartamentos diretamente no plantão de vendas, utilizando seus próprios funcionários que não são inscritos no CRECI. Perante a legislação vigente (Lei 6.530/78), esses funcionários da construtora:", imagem:null, alternativas:["A) Estão isentos de inscrição no CRECI, pois comercializam imóveis da própria empresa (proprietária), não ocorrendo a intermediação.","B) Cometem infração disciplinar gravíssima e devem ser julgados imediatamente pelo COFECI.","C) Praticam a contravenção penal de exercício ilegal da profissão, pois a venda de imóveis exige inscrição no CRECI, mesmo sendo patrimônio próprio.","D) Devem ser multados pelo CRECI em 10 anuidades por infração à reserva de mercado.","E) Têm sua conduta legitimada apenas se a venda ocorrer com a supervisão de um síndico credenciado."], resposta_correta:0, explicacao: "Quem vende imóvel PRÓPRIO não está fazendo 'intermediação' (não existe o elemento terceiro-corretor). Portanto, a construtora vendendo seu próprio patrimônio não pratica intermediação ilegal e não exige registro no CRECI para seus vendedores diretos celetistas. Pegadinha de interpretação doutrinária comum.", status:0, historico:0 },
{ id:593, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Analise as competências listadas abaixo e relacione-as ao órgão correspondente: 1. Fixar normas e limites para anuidades. 2. Arrecadar anuidades, multas e emolumentos. 3. Julgar processos disciplinares em primeira instância. 4. Funcionar como última instância recursal. A ordem sequencial que identifica os responsáveis é:", imagem:null, alternativas:["A) 1-COFECI; 2-COFECI; 3-CRECI; 4-CRECI.","B) 1-COFECI; 2-CRECI; 3-CRECI; 4-COFECI.","C) 1-CRECI; 2-CRECI; 3-COFECI; 4-COFECI.","D) 1-CRECI; 2-COFECI; 3-CRECI; 4-COFECI.","E) 1-COFECI; 2-CRECI; 3-COFECI; 4-CRECI."], resposta_correta:1, explicacao: "COFECI é o órgão máximo: fixa diretrizes (limites de taxas) e é última instância recursal. CRECI é o órgão executivo de base: arrecada o dinheiro e julga os processos na primeira instância em seu Estado.", status:0, historico:0 },
{ id:594, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Sobre os anúncios e a publicidade no ramo imobiliário, constitui infração grave, de acordo com o rol de proibições da Lei nº 6.530/1978:", imagem:null, alternativas:["A) Divulgar o preço real do imóvel sem acréscimo de taxas ocultas de corretagem.","B) Anunciar imóvel com a autorização expressa do cônjuge do proprietário por procuração.","C) Anunciar a realização de loteamento sem o prévio registro do projeto no Cartório de Imóveis competente.","D) Utilizar placas de 'Vende-se' com tamanho padronizado pela prefeitura municipal.","E) Publicar anúncios na internet contendo o número do registro no CRECI."], resposta_correta:2, explicacao: "O Art. 20 proíbe anunciar loteamento ou condomínio sem o respectivo registro no cartório de registro de imóveis competente (vedação para evitar fraudes em loteamentos irregulares). As opções A, B, D e E são atitudes lícitas e elogiáveis.", status:0, historico:0 },
{ id:595, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Situação Hipotética: Mário, Corretor de Imóveis, foi penalizado no dia 01/03/2026 com o cancelamento de sua inscrição por infração ética gravíssima. Desesperado, ele deseja recorrer. Nos termos dos ritos dos Conselhos, esse recurso:", imagem:null, alternativas:["A) Deve ser dirigido ao Ministério da Economia, por se tratar de decisão terminativa de emprego autárquico.","B) Não possui efeito suspensivo, o que significa que Mário deve entregar sua carteira imediatamente até o fim do processo.","C) Será julgado exclusivamente pelo Plenário do mesmo CRECI, pois decisões de cancelamento não sobem ao âmbito federal.","D) Será dirigido ao COFECI, que atua como instância recursal para revisar a decisão do CRECI regional.","E) Só será admitido se Mário depositar o valor de 5 anuidades como garantia recursal (caução) nos cofres da autarquia."], resposta_correta:3, explicacao: "Cabe recurso ao COFECI de todas as decisões definitivas proferidas pelo CRECI (Art. 9º, alínea c). A Quadrix cria amarras financeiras (E) ou bloqueios de instâncias (C) para invalidar recursos garantidos pelo contraditório administrativo.", status:0, historico:0 },
{ id:596, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"A Lei nº 6.530/1978 foi alterada para atualizar as regras da composição do COFECI. Assinale a afirmativa CORRETA acerca das eleições e mandatos nos conselhos:", imagem:null, alternativas:["A) O voto nas eleições do CRECI é meramente facultativo, não gerando penalidade a quem não comparecer.","B) A eleição para o COFECI é feita diretamente por todos os corretores inscritos no Brasil, em votação eletrônica obrigatória.","C) O mandato dos membros do Conselho Federal e dos Conselhos Regionais será de três anos, permitida a reeleição.","D) Apenas bacharéis em direito inscritos como corretores podem concorrer à presidência dos CRECIs.","E) Os conselheiros regionais recebem subsídio equivalente a 10 salários mínimos pelas funções desempenhadas."], resposta_correta:2, explicacao: "O mandato de três anos (Art. 12, § 1º) é a principal mudança moderna e alvo de provas. O voto no CRECI é obrigatório (pena de multa para abstenção sem justa causa), e a eleição do COFECI é indireta (delegados-eleitores do CRECI votam no COFECI, não a base de corretores - tornando a B falsa). O cargo de conselheiro é honorífico (não remunerado - derrubando a E).", status:0, historico:0 },
{ id:597, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"O Artigo 20 da Lei 6.530/78 estabelece as vedações ao Corretor. Identifique a alternativa que NÃO configura uma infração disciplinar legalmente prevista:", imagem:null, alternativas:["A) Prejudicar, por dolo ou culpa, os interesses que lhe forem confiados.","B) Associar-se a pessoa que não possui registro no CRECI para o exercício da corretagem.","C) Negar aos clientes recibos de quantias recebidas por transações efetuadas.","D) Promover a divulgação de venda de imóvel mediante autorização verbal do proprietário.","E) Recusar-se a atender clientes inadimplentes com suas antigas dívidas imobiliárias em outras corretoras."], resposta_correta:4, explicacao: "O Corretor não é obrigado a aceitar e atender qualquer cliente (liberdade contratual/profissional não fere o Art 20). No entanto, o anúncio sem autorização por ESCRITO é infração gravíssima (letra D é infração: não pode anunciar apenas de forma verbal). A banca inverte a lógica do livre exercício.", status:0, historico:0 },
{ id:598, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Julgue as sentenças (V) ou (F) referentes às penalidades: ( ) A pena de multa pode ser acumulada com qualquer outra penalidade disciplinar (advertência, censura, suspensão ou cancelamento). ( ) A pena de 'Censura' sujeita o infrator ao cancelamento definitivo do registro se houver uma segunda aplicação. ( ) A imposição de penalidades independe de o processo administrativo transitar em julgado administrativamente. A sequência correta é:", imagem:null, alternativas:["A) V, V, F.","B) F, F, V.","C) V, F, F.","D) F, V, V.","E) V, V, V."], resposta_correta:2, explicacao: "A 1ª está correta (Art. 21, § 1º: a multa pode acumular). A 2ª é falsa (a lei não diz que 2 censuras geram cancelamento sumário, exige-se graduação/reincidência e novo processo). A 3ª é falsa, pois penalidade exige o término do processo (ampla defesa). A Quadrix testa as exceções cumulativas da multa.", status:0, historico:0 },
{ id:599, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Uma empresa (Pessoa Jurídica) do ramo imobiliário, regularmente inscrita no CRECI, sofreu mudança de seu Responsável Técnico. Segundo a legislação profissional, a PJ:", imagem:null, alternativas:["A) Deverá comunicar ao CRECI a alteração no prazo máximo de 15 dias para que os atos da imobiliária mantenham validade.","B) Estará automaticamente com o registro cancelado se ficar mais de 48 horas sem um substituto formalizado perante o conselho.","C) Deverá possuir sempre um sócio majoritário que seja Corretor de Imóveis inscrito no CRECI, não bastando um mero responsável técnico contratado.","D) Pode continuar operando normalmente sem responsável técnico, desde que pague as anuidades em dia.","E) Deve indicar um novo Corretor de Imóveis responsável por suas operações, sob pena de infração, mas o registro da PJ não se confunde com o do PF."], resposta_correta:4, explicacao: "A PJ exige um Corretor PF como responsável. O erro da C (muito comum em provas) é afirmar que o SÓCIO tem que ser corretor; a lei exige que haja um Responsável Técnico, que pode ser um contratado. A E aborda a exigência sem os exageros punitivos de '48 horas' (B).", status:0, historico:0 },
{ id:600, categoria: "Conhecimentos Específicos", materia:"Legislação Específica", assunto:"Legislação Profissional CRECI", cargo:"Assistente Administrativo", ano:"2026", banca:"Quadrix (Inédita)", enunciado:"Considerando o funcionamento administrativo dos Conselhos, caso o Plenário do CRECI não atinja o quórum para reuniões ou o órgão entre em colapso financeiro/administrativo, cabe ao COFECI:", imagem:null, alternativas:["A) Extinguir permanentemente o CRECI daquele Estado, assumindo todas as suas funções localmente.","B) Intervir temporariamente no CRECI regional, mediante justificativa fundamentada, para restabelecer a normalidade administrativa.","C) Solicitar a intervenção militar direta no Estado para retomada dos arquivos físicos.","D) Perdoar todas as dívidas e multas acumuladas pela base de corretores locais para injetar ânimo no conselho.","E) Decretar falência judicial do CRECI-BA perante a Vara Empresarial do Tribunal de Justiça."], resposta_correta:1, explicacao: "O Art. 9º, inciso 'd', dá ao COFECI o poder de intervir nos CRECIs (poder hierárquico autárquico excepcional). A Quadrix cria opções como 'extinção permanente' (A) ou 'decretar falência' (E) que ferem o princípio de que autarquias não quebram (não pedem falência) e são criadas/extintas só por LEI.", status:0, historico:0 },

    
]